//! cuda_matmul -- GPU (cuBLAS) backend for the FLUX/LTX Q8_0 matmul hot path.
//!
//! WHY this exists: the dominant cost of a native FLUX render is the Q8_0
//! matmuls in the T5 encoder + the MMDiT velocity forward. On CPU those stream
//! ~12.6 GB of distinct Q8 weight per denoise pass through an mmap at ~4.5 GB/s
//! (flux-matmul-bench cold sweep) — a 256² render takes ~hours. An NVIDIA L4
//! (24 GB GDDR6, ~300 GB/s) holds the dequantized weights resident in VRAM, so
//! after a one-time upload every per-step matmul reads weights from VRAM at
//! ~60x the cold-mmap bandwidth and runs the GEMM on the tensor/CUDA cores.
//!
//! SOVEREIGNTY: cuBLAS is a BLAS math library (gemm), NOT a third-party AI model
//! or a paid hosted-inference API. It is the same class of dependency as the
//! CPU `matrixmultiply` crate, just on the GPU. No Workers AI / env.AI / hosted
//! model is involved. The numerically-identical CPU path remains the default;
//! this backend is gated behind the `cuda` cargo feature and, even when built
//! in, only activates if a CUDA device + driver are actually present at runtime
//! (Cloud Run L4). Anywhere else it transparently falls back to the CPU kernel.
//!
//! WEIGHT CACHING: FLUX weights are loaded once as stable `OwnedBytes` (mmap or
//! resident) for the whole render, so the host pointer of each weight slice is a
//! stable identity. We dequantize Q8_0 -> f32 on the host ONCE per weight,
//! upload to a device buffer, and cache that device buffer keyed by the weight's
//! host base pointer + length. Subsequent denoise steps reuse the resident
//! device weights — only the (small) activation `xs` is re-uploaded per call.
//!
//! WHY THE FIRST GPU RENDER HUNG / WAS PATHOLOGICALLY SLOW (the v1-v3 bug):
//! the T5-XXL encoder ran as ~74k *single-vector* GEMV calls (24 blocks ×
//! 512 tokens × ~6 projections, `tokens = 1`). The original code did a fresh
//! `cudaMalloc` (`alloc_zeros` for `out`) + a fresh `htod` allocation for `xs`
//! on EVERY call, plus two synchronous PCIe round-trips. cudaMalloc/cudaFree
//! serialize the whole stream and cost ~100µs-ms each; on a 1×4096 GEMV the GPU
//! arithmetic is trivial, so the call was 100% launch+alloc+sync overhead —
//! SLOWER than the SIMD CPU kernel, and across 74k calls it looked like a hang
//! (no T5 "done in" within 20-30 min). FIX: (1) persistent pooled device buffers
//! reused across calls (zero per-call cudaMalloc), and (2) route the tiny
//! single-vector T5 GEMV to the CPU (sync-overhead-bound — the GPU is a net loss
//! there) while keeping the GPU for the batched DiT `rows_shared` path where the
//! 12.6 GB weight stream is the real cost and the GPU is a 10-60x win.

#![cfg(all(feature = "cuda", not(target_arch = "wasm32")))]

use std::collections::HashMap;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::{Arc, Mutex, OnceLock};
use std::time::Instant;

use cudarc::cublas::{CudaBlas, Gemm, GemmConfig, StridedBatchedConfig};
use cudarc::driver::{CudaDevice, CudaSlice, DeviceSlice};
use half::{bf16, f16};

use crate::math::{dequantize_q4k_row, dequantize_q6k_row, dequantize_q8_0_row};

/// Weight residency dtype for the quantized-LLM paths. Default `f32` is the
/// FLUX-proven path (bit-comparable to the CPU kernels under PEDANTIC math).
/// `FLUX_GPU_WEIGHT_DTYPE=f16` halves resident bytes so 7-8B models fit the
/// 24 GB L4 (mistral-7b q4km: ~29 GB f32 -> ~14.5 GB f16); the GEMM is
/// cublasGemmEx with 16F storage and **CUBLAS_COMPUTE_32F accumulation**
/// (cudarc's Gemm<half::f16> impl), so only storage precision drops — the
/// standard LLM-serving profile.
fn weight_dtype_is_f16() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPU_WEIGHT_DTYPE")
            .map(|v| v.eq_ignore_ascii_case("f16") || v.eq_ignore_ascii_case("half"))
            .unwrap_or(false)
    })
}

/// `FLUX_GPU_WEIGHT_DTYPE=bf16` selects bfloat16 GPU storage instead of f16.
/// bf16 keeps f16's 2-bytes/elem VRAM footprint but has f32's 8-bit exponent
/// (max ~3.4e38) instead of f16's 5-bit (max 65504). gemma4-12b's residual
/// stream + large per-layer norm weights drive GEMM intermediates past 65504,
/// which OVERFLOW to inf in f16 (→ garbage logits) but are in-range for bf16.
/// HF serves gemma4 in bf16 for exactly this reason. The GEMM still accumulates
/// in f32 (CUBLAS_COMPUTE_32F), so only storage range/precision changes.
fn weight_dtype_is_bf16() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPU_WEIGHT_DTYPE")
            .map(|v| v.eq_ignore_ascii_case("bf16") || v.eq_ignore_ascii_case("bfloat16"))
            .unwrap_or(false)
    })
}

/// `FLUX_GPU_F32_ACT=1` (additive, DEFAULT OFF) — the gemma4 PRECISION fix.
///
/// ROOT CAUSE: the f16-weight GEMM path (`gemm_with_weight_f16_ptr`) rounds the
/// ACTIVATIONS to f16 before the contraction (`xs.iter().map(f16::from_f32)`),
/// with the weight resident f16. The f16 INPUT rounding error (mantissa ~10 bits,
/// ~1e-3 rel) accumulates over each large contraction (d up to 15360, vocab
/// 262144) and tips gemma4's hypersensitive readout (tanh-softcap=30, near-flat
/// logit margins, residual magnitudes ~2.7e2) into "unused-token salad" (top
/// tokens ~236xxx). gemma3 on the SAME GEMM body is fine — it isn't precision-
/// hypersensitive. Forcing ONLY the FFN down-proj to exact CPU did NOT fix it, so
/// the loss is spread across multiple large GEMMs + the lm_head — i.e. the fix
/// must be a higher-precision GPU GEMM, NOT a per-GEMM CPU fallback.
///
/// THE FIX: keep the ACTIVATIONS in f32 (zero input rounding) by routing the GEMM
/// through the PROVEN all-f32 cuBLAS path (`gemm_with_weight`), with the weight
/// dequantized to an f32 resident slab (`resident_weight_dequant`, cached under
/// the q8 f32 budget). cublasGemmEx REQUIRES Atype == Btype (you CANNOT mix a
/// CUDA_R_32F activation operand with a CUDA_R_16F weight operand — that combo is
/// rejected at runtime), so the ONLY way to feed f32 activations is to ALSO have
/// the weight as f32: Atype=Btype=CUDA_R_32F, Ctype=CUDA_R_32F,
/// computeType=CUBLAS_COMPUTE_32F (this is exactly the existing FLUX f32 SGEMM-
/// via-GemmEx path, bit-comparable to the CPU kernel under PEDANTIC math). No
/// activation rounding ANYWHERE on the contraction; the accumulate was already
/// f32. VRAM COST: the weight is resident at 4 B/elem (f32) instead of 2 B/elem
/// (f16) — 2× for the GEMMs it touches. The `FLUX_GPU_F32_ACT_MIN_D` threshold
/// bounds that: only weights with inner dim d >= min-d take this path (e.g. set
/// it to scope the f32 slab to just the large FFN / lm_head GEMMs and leave the
/// small attention projections on the cheaper f16 path). DEFAULT OFF and OUTSIDE
/// the f16/bf16 branches, so mistral/gemma3 are byte-unchanged.
fn gpu_f32_act_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPU_F32_ACT")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false)
    })
}

/// `FLUX_GPU_F32_ACT_MIN_D` (default 0 = all GEMMs). Only GEMMs whose inner
/// (contraction) dim `d` is >= this threshold take the f32-activation path; below
/// it they stay on the resident-dtype f16/bf16 GEMM. Lets the 2×-VRAM f32 slab be
/// scoped to the large GEMMs (FFN down-proj d=15360, lm_head over the 262k vocab)
/// where the f16-input rounding actually accumulates, leaving the small attention
/// projections cheap.
fn gpu_f32_act_min_d() -> usize {
    static V: OnceLock<usize> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPU_F32_ACT_MIN_D")
            .ok()
            .and_then(|v| v.trim().parse::<usize>().ok())
            .unwrap_or(0)
    })
}

/// True when the f32-activation precision path applies to a GEMM of inner dim `d`:
/// the flag is on AND `d >= FLUX_GPU_F32_ACT_MIN_D`.
fn gpu_f32_act_applies(d: usize) -> bool {
    gpu_f32_act_enabled() && d >= gpu_f32_act_min_d()
}

/// VRAM-saturation policy (fork/race/fold over the GPU↔CPU split). When the
/// resident weight cache is full and the next weight is NOT already resident:
///   - `evict` (default): FIFO-evict to make room, re-upload (the FLUX render
///     profile — one weight reused across many denoise steps, eviction amortizes).
///   - `cpu`: leave the GPU cache untouched and signal the caller to run THIS op
///     on the CPU SIMD kernel (weights are already host-mmap'd). The hot layers
///     stay GPU-resident; overflow runs on CPU → both engines busy, no per-token
///     re-upload thrash. This is the "liquid memory" regime for models whose f16
///     working set exceeds VRAM but whose quantized knot fits host RAM (e.g. a
///     12B on a 24 GB L4). Set FLUX_GPU_SATURATION_POLICY=cpu on those deploys.
/// Returns true when the policy is `cpu` (saturation should fall back, not evict).
fn saturation_falls_back_to_cpu() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPU_SATURATION_POLICY")
            .map(|v| v.eq_ignore_ascii_case("cpu") || v.eq_ignore_ascii_case("fallback"))
            .unwrap_or(false)
    })
}

/// Sentinel error string returned by resident_* when VRAM is saturated under
/// the `cpu` policy. try_* maps any Err to `false` (→ CPU kernel), so this need
/// only be distinct enough to log; it is never matched on.
const VRAM_SATURATED: &str = "[cuda] vram saturated — op routed to CPU (liquid-memory fallback)";

/// Activations with `tokens <= GPU_MIN_TOKENS` are run on the CPU instead of the
/// GPU. A single-vector GEMV (the T5 per-token path, tokens=1) does negligible
/// GPU arithmetic but pays the full host<->device sync overhead, so the SIMD CPU
/// kernel wins. The batched DiT `rows_shared` path (hundreds of tokens, 12.6 GB
/// weight stream) is where the GPU is a large win. Overridable via
/// `FLUX_GPU_MIN_TOKENS` for A/B.
fn gpu_min_tokens() -> usize {
    static V: OnceLock<usize> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPU_MIN_TOKENS")
            .ok()
            .and_then(|v| v.parse().ok())
            .unwrap_or(2)
    })
}

/// `MESH_GPU_SLAB=1` (additive, DEFAULT OFF) — route the f16 quantized GEMM
/// through a single contiguous f16 residency slab instead of per-weight
/// `cudaMalloc`s. One big allocation holds ALL ~14.5 GB of f16 weights so VRAM
/// never fragments and no layer falls back to CPU ("partial residency = worst of
/// both"). Only takes effect together with the f16 weight dtype path
/// (`FLUX_GPU_WEIGHT_DTYPE=f16`); the slab stores f16. OnceLock-cached.
fn gpu_slab_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("MESH_GPU_SLAB").map(|v| v == "1").unwrap_or(false))
}

/// Slab capacity in f16 elements, from `MESH_GPU_SLAB_GB` (default 22 GB).
/// elems = gb * 1e9 / 2 (f16 = 2 bytes). A 7B f16 working set is ~14.5 GB, so
/// 22 GB leaves headroom under the 24 GB L4 for the activation pools.
fn gpu_slab_capacity_elems() -> usize {
    static V: OnceLock<usize> = OnceLock::new();
    *V.get_or_init(|| {
        let gb = std::env::var("MESH_GPU_SLAB_GB")
            .ok()
            .and_then(|v| v.parse::<f64>().ok())
            .unwrap_or(22.0);
        ((gb * 1e9) / 2.0) as usize
    })
}

/// `MESH_GPU_FUSE=1` (additive, DEFAULT OFF) — fuse adjacent projections
/// (FFN gate+up) into ONE cublas GEMM + ONE readback to cut per-token dtoh
/// syncs. Real path: see `try_mat_vec_q8_0_fused` + `resident_weight_slab_f16_group`.
/// Only engages together with `MESH_GPU_SLAB=1` + `FLUX_GPU_WEIGHT_DTYPE=f16`
/// (it reuses the slab's raw-pointer GEMM body) — see `gpu_fuse_active`.
/// OnceLock-cached.
fn gpu_fuse_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("MESH_GPU_FUSE").map(|v| v == "1").unwrap_or(false))
}

/// `MESH_GPU_Q8K=1` (additive, DEFAULT OFF) — route the single-token (decode)
/// Q8_0 matmul through a CUSTOM in-kernel dequant-GEMV instead of cuBLAS.
///
/// WHY: GPU decode with cuBLAS is VRAM-BANDWIDTH-bound — it reads the f16
/// weights (~14.5 GB/token) at ~300 GB/s → a ~48 ms floor. Keeping the weights
/// resident as RAW Q8_0 bytes (~7.7 GB) and dequantizing IN-KERNEL reads ~half
/// the bytes (cuBLAS cannot consume block-scaled Q8): 7.7 GB / 300 GB/s ≈ 26 ms
/// → ~20 tps, NO quality loss (Q8 is the current knot). The kernel PTX is
/// compiled at build time (build.rs `nvcc --ptx`) and loaded via the driver at
/// runtime; if nvcc was absent at build time (`q8_kernel_ptx` cfg not set) the
/// flag silently no-ops to the existing cuBLAS/CPU path. OnceLock-cached.
fn gpu_q8k_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("MESH_GPU_Q8K").map(|v| v == "1").unwrap_or(false))
}

/// Embedded PTX for the custom Q8_0 dequant-GEMV kernel. build.rs writes
/// `$OUT_DIR/q8_gemv.ptx` (the compiled PTX when nvcc succeeded, an EMPTY file
/// otherwise), so this `include_str!` always resolves. When the string is empty
/// the kernel is treated as unavailable (`q8_kernel_ptx` cfg is also unset in
/// that case) and `MESH_GPU_Q8K` no-ops to the existing path.
const Q8_GEMV_CUBIN: &[u8] = include_bytes!(concat!(env!("OUT_DIR"), "/q8_gemv.cubin"));

/// Threads per CUDA block for the q8_gemv launch. The kernel maps ONE WARP
/// (32 lanes) to `Q8K_ROWS_PER_WARP` output rows and packs `Q8K_WARPS_PER_BLOCK`
/// warps per block, so `Q8K_BLOCK_DIM` MUST equal `32 * Q8K_WARPS_PER_BLOCK`.
/// grid.x = ceil(N / (Q8K_WARPS_PER_BLOCK * Q8K_ROWS_PER_WARP)); the kernel
/// reduces via warp-shuffle. `Q8K_WARPS_PER_BLOCK` / `Q8K_ROWS_PER_WARP` MUST
/// match `WARPS_PER_BLOCK` / `ROWS_PER_WARP` in `src/cuda/q8_gemv.cu`.
const Q8K_WARPS_PER_BLOCK: u32 = 8;
const Q8K_BLOCK_DIM: u32 = 32 * Q8K_WARPS_PER_BLOCK;
/// Output rows each warp computes in one pass over x (reuses staged x; raises
/// arithmetic intensity). MUST match `ROWS_PER_WARP` in `src/cuda/q8_gemv.cu`.
const Q8K_ROWS_PER_WARP: u32 = 2;
/// Max K (elements) for which the kernel stages x in shared memory (one load
/// per block instead of per-warp). MUST match `SHARED_X_MAX_K` in the .cu. When
/// K <= this, the launch passes shared_mem_bytes = K*4; else 0 (global x path).
const Q8K_SHARED_X_MAX_K: usize = 8192;

/// True when the custom Q8 kernel was compiled into this binary: build.rs set
/// the `q8_kernel_ptx` cfg (nvcc succeeded) AND the embedded PTX is non-empty.
/// When false, `MESH_GPU_Q8K=1` silently no-ops to the existing cuBLAS/CPU path.
fn q8_kernel_available() -> bool {
    cfg!(q8_kernel_cubin) && !Q8_GEMV_CUBIN.is_empty()
}

// ── MESH_GPU_Q4K=1 (additive, DEFAULT OFF): custom in-kernel K-quant GEMVs ──
//
// `MESH_GPU_Q4K=1` routes the single-token (decode) Q4_K **and** Q6_K matmuls
// through CUSTOM in-kernel dequant-GEMVs (q4k_gemv.cu / q6k_gemv.cu), modeled
// exactly on the proven Q8 kernel. WHY: mistral-7b as Q4_K_M reads ~4.0 GB/token
// (vs Q8's 7.55 GB) → ~26 tps at the proven kernel bandwidth, NO quality loss
// (Q4_K_M is the shipped knot). Q4_K_M is MIXED — most tensors Q4_K but ffn_down
// + attn_v are Q6_K — so to keep the WHOLE decode in-kernel (partial residency is
// a measured catastrophe) BOTH kernels are needed; ONE flag enables both.
//
// The cubins are compiled at build time (build.rs `nvcc --cubin -arch=sm_89`) and
// loaded via the driver at runtime; if nvcc was absent at build time (the
// `q4k_kernel_cubin` / `q6k_kernel_cubin` cfg not set, or the embedded cubin
// empty) the flag silently no-ops to the existing cuBLAS/CPU path. OnceLock-cached.
fn gpu_q4k_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("MESH_GPU_Q4K").map(|v| v == "1").unwrap_or(false))
}

/// Embedded sm_89 CUBIN for the custom Q4_K / Q6_K dequant-GEMV kernels. build.rs
/// writes the compiled cubin (nvcc succeeded) or an EMPTY file otherwise, so
/// these `include_bytes!` always resolve. When empty the kernel is treated as
/// unavailable (the matching `*_kernel_cubin` cfg is also unset) and the flag
/// no-ops to the existing path.
const Q4K_GEMV_CUBIN: &[u8] = include_bytes!(concat!(env!("OUT_DIR"), "/q4k_gemv.cubin"));
const Q6K_GEMV_CUBIN: &[u8] = include_bytes!(concat!(env!("OUT_DIR"), "/q6k_gemv.cubin"));

/// Launch constants for the K-quant kernels. IDENTICAL warp-per-rows mapping to
/// the Q8 kernel: ONE WARP computes `Q4K_ROWS_PER_WARP` output rows,
/// `Q4K_WARPS_PER_BLOCK` warps per block, warp-shuffle reduce. These MUST match
/// `WARPS_PER_BLOCK` / `ROWS_PER_WARP` / `SHARED_X_MAX_K` in BOTH q4k_gemv.cu
/// AND q6k_gemv.cu. The kernels share these constants (same launch geometry);
/// only the per-superblock dequant math differs.
const Q4K_WARPS_PER_BLOCK: u32 = 8;
const Q4K_BLOCK_DIM: u32 = 32 * Q4K_WARPS_PER_BLOCK;
const Q4K_ROWS_PER_WARP: u32 = 2;
/// Max K for which x is staged in shared memory; else the global-x path. MUST
/// match `SHARED_X_MAX_K` in q4k_gemv.cu / q6k_gemv.cu.
///
/// SPEED: raised 8192 -> 16384 so the gemma4-12b FFN down-projection (K=15360)
/// stages x in shared INSTEAD of re-reading it from global per (row, superblock).
/// Without staging, a [3840 x 15360] GEMV re-reads x for all 3840 rows = ~236 MB
/// of redundant global x traffic per token (≈7× the 33 MB weight read) — the
/// dominant term in the ~158 ms down-matvec. Staged, x is read ONCE (60 KB).
/// 16384 floats = 64 KB > the 48 KB classic shared cap, so the kernels opt into
/// the sm_89 large-dynamic-shared limit via `set_attribute(
/// MAX_DYNAMIC_SHARED_SIZE_BYTES)` at module load (see `ensure_q4k_module`);
/// the L4 (Ada) allows up to 99 KB/block. The host still passes the exact
/// `K*4` bytes per launch, so a K below this cap reserves only what it needs.
const Q4K_SHARED_X_MAX_K: usize = 16384;

/// Dynamic-shared opt-in (bytes) requested for the K-quant GEMV kernels so K up
/// to `Q4K_SHARED_X_MAX_K` (64 KB of staged f32 x) can exceed the 48 KB classic
/// cap. 64 KB is well under the L4/sm_89 99 KB max; the driver caps the actual
/// per-launch reservation to `shared_mem_bytes` regardless. Set once per loaded
/// function via `CU_FUNC_ATTRIBUTE_MAX_DYNAMIC_SHARED_SIZE_BYTES`.
const Q4K_MAX_DYNAMIC_SHARED_BYTES: i32 = (Q4K_SHARED_X_MAX_K * 4) as i32;

/// True when the custom Q4_K kernel was compiled into this binary (build.rs set
/// `q4k_kernel_cubin` AND the embedded cubin is non-empty). When false,
/// `MESH_GPU_Q4K=1` silently no-ops the Q4_K kernel path.
fn q4k_kernel_available() -> bool {
    cfg!(q4k_kernel_cubin) && !Q4K_GEMV_CUBIN.is_empty()
}

/// True when the custom Q6_K kernel was compiled into this binary (build.rs set
/// `q6k_kernel_cubin` AND the embedded cubin is non-empty). When false,
/// `MESH_GPU_Q4K=1` silently no-ops the Q6_K kernel path.
fn q6k_kernel_available() -> bool {
    cfg!(q6k_kernel_cubin) && !Q6K_GEMV_CUBIN.is_empty()
}

// ── MESH_GPU_PREFILL_ATTN=1 (additive, DEFAULT OFF): GPU batched prefill attn ──
//
// Long-prompt prefill on the mesh is bottlenecked by the per-token/per-head
// causal-attention loop (O(context²), CPU-bound even after the rayon
// parallelization — see PREFILL_ATTENTION_GPU_HANDOFF.md). This flag routes the
// chunk's attention (Phase B) through a batched GPU path: two cuBLAS
// `sgemmStridedBatched` GEMMs (QKᵀ, then AV) around one custom softmax+causal
// kernel (`prefill_attn.cu`). The CPU rayon path stays the source of truth and
// the gate falls back to it on ANY miss (flag off / GPU absent / kernel cubin
// empty / unsupported shape / memo or bowl-filter active / GPU error). Decode
// (T==1) NEVER takes this path — it stays on the existing decode kernels.
//
// DEFAULT ON. The path shipped gated (default OFF) and was validated end-to-end on
// the L4: the `prefill_chunk_matches_forward_one_multichunk` parity test (1e-4) +
// the in-op FLUX_GPUCHECK probe (max|gpu-cpu| ≈ 6e-10), then a live Mistral-7B
// benchmark on a 0%-traffic tagged revision — identical output vs the CPU path and
// ~33% faster end-to-end on a 1289-token prefill (18.9s vs 28.4s; attention ~3.2s
// vs ~13s). Having earned it, the default is now ON; set `MESH_GPU_PREFILL_ATTN=0`
// to force the CPU rayon path. (Still overhead-bound at ~9ms/call for T=128 — the
// compute is ~44µs — so pooling the per-tile device buffers is the next lever.)
fn gpu_prefill_attn_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("MESH_GPU_PREFILL_ATTN")
            .map(|v| v != "0")
            .unwrap_or(true)
    })
}

/// Embedded CUBIN for the prefill softmax+causal-mask kernel (`prefill_attn.cu`,
/// arch from MESH_CUDA_ARCH; default sm_89). build.rs writes the compiled cubin
/// or an EMPTY file (nvcc absent/failed), so this `include_bytes!` always
/// resolves; empty ⇒ kernel unavailable ⇒ the flag no-ops to the CPU path.
const PREFILL_ATTN_CUBIN: &[u8] =
    include_bytes!(concat!(env!("OUT_DIR"), "/prefill_attn.cubin"));

/// Threads per block for the softmax kernel. MUST be a power of two (the kernel's
/// shared-memory tree reduction halves blockDim each step). 256 covers the
/// per-row reduction over up to a few-thousand-key context with good occupancy;
/// shared_mem_bytes = PREFILL_ATTN_BLOCK_DIM * 4.
const PREFILL_ATTN_BLOCK_DIM: u32 = 256;

/// Query-tile height: the GPU processes the chunk's `seq_len` query rows in tiles
/// of this many tokens so the transient scores buffer [num_heads × Tq × L] stays
/// bounded (the full T×L×heads scores for a long prompt is multi-GB). 256 keeps
/// the worst-case tile scores ≈ 32·256·L·4 ≈ 44 MB at L≈1358.
const PREFILL_ATTN_TILE_Q: usize = 256;

/// True when the prefill softmax kernel was compiled into this binary (build.rs
/// set `prefill_attn_kernel_cubin` AND the embedded cubin is non-empty). When
/// false, `MESH_GPU_PREFILL_ATTN=1` silently no-ops to the CPU path.
fn prefill_attn_kernel_available() -> bool {
    cfg!(prefill_attn_kernel_cubin) && !PREFILL_ATTN_CUBIN.is_empty()
}

// ── MESH_GPU_SCAN=1 (additive, DEFAULT OFF): GPU Mamba-1 S6 selective-scan ──
//
// `MESH_GPU_SCAN=1` moves the per-token Mamba-1 (S6) recurrence off the CPU and
// onto a custom kernel (`mamba_scan.cu`). WHY: falcon-mamba-7b's Q8 matmuls are
// already GPU-fast (q8_gemv.cu ~0.3-0.5 ms) but the S6 scan runs on the CPU at
// ~2.2 s/token (8192×16×64 fused MACs, each with two fp32 exp) → 0.45 tok/s. The
// kernel keeps the recurrent state `h` [d_inner × d_state] RESIDENT in VRAM
// across tokens (seeded once from the host state on first use, updated in-place,
// reset via `mamba_scan_reset_all`) so no per-token H2D/D2H of the state; only
// the small dt/B/C/x_conv/y vectors (~64 KB) cross the bus. Numerics are
// byte-faithful to the CPU `mamba1_s6_step` (fp32, precise expf, A=-exp(a_log),
// same op/state order). The cubin is compiled at build time (build.rs nvcc) and
// loaded via the driver at runtime; if nvcc was absent (`mamba_scan_kernel_cubin`
// cfg unset / cubin empty) the flag silently no-ops to the CPU scan. OnceLock.
fn gpu_scan_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("MESH_GPU_SCAN").map(|v| v == "1").unwrap_or(false))
}

/// Embedded CUBIN for the Mamba-1 S6 selective-scan kernel (`mamba_scan.cu`,
/// arch from MESH_CUDA_ARCH; default sm_89). build.rs writes the compiled cubin
/// or an EMPTY file (nvcc absent/failed), so this `include_bytes!` always
/// resolves; empty ⇒ kernel unavailable ⇒ the flag no-ops to the CPU scan.
const MAMBA_SCAN_CUBIN: &[u8] = include_bytes!(concat!(env!("OUT_DIR"), "/mamba_scan.cubin"));

/// Threads per CUDA block for the mamba scan launch. ONE THREAD PER CHANNEL, so
/// grid.x = ceil(d_inner / MAMBA_SCAN_BLOCK_DIM). 256 gives good occupancy for
/// the typical d_inner (8192 for falcon-mamba-7b, 5120 for mamba-2.8b).
const MAMBA_SCAN_BLOCK_DIM: u32 = 256;

/// True when the Mamba scan kernel was compiled into this binary (build.rs set
/// `mamba_scan_kernel_cubin` AND the embedded cubin is non-empty). When false,
/// `MESH_GPU_SCAN=1` silently no-ops to the CPU scan.
fn mamba_scan_kernel_available() -> bool {
    cfg!(mamba_scan_kernel_cubin) && !MAMBA_SCAN_CUBIN.is_empty()
}

/// Embedded CUBIN for the Mamba-2 (SSD) selective-scan kernel (`mamba2_ssd_scan.cu`,
/// arch from MESH_CUDA_ARCH; default sm_89). The grouped multi-head cousin of
/// `mamba_scan.cu`. build.rs writes the compiled cubin or an EMPTY file (nvcc
/// absent/failed), so this `include_bytes!` always resolves; empty ⇒ kernel
/// unavailable ⇒ the flag no-ops to the CPU SSD scan. Shares MESH_GPU_SCAN with S6.
const MAMBA2_SSD_SCAN_CUBIN: &[u8] =
    include_bytes!(concat!(env!("OUT_DIR"), "/mamba2_ssd_scan.cubin"));

/// True when the Mamba-2 SSD scan kernel was compiled into this binary (build.rs
/// set `mamba2_ssd_scan_kernel_cubin` AND the embedded cubin is non-empty). When
/// false, `MESH_GPU_SCAN=1` silently no-ops to the CPU SSD scan. Mirrors
/// `mamba_scan_kernel_available`.
fn mamba2_ssd_scan_kernel_available() -> bool {
    cfg!(mamba2_ssd_scan_kernel_cubin) && !MAMBA2_SSD_SCAN_CUBIN.is_empty()
}

// ── MESH_GPU_SSM_FUSED=1 (additive, DEFAULT OFF): fused SSD scan → device gated
// RMSNorm → resident out_proj. When set (and the cuda feature + kernels are
// present), the Mamba-2 layer keeps the scan output `y` RESIDENT: the gated norm
// runs on-device (mamba2_gated_norm.cu) into a distinct resident buffer, and
// out_proj's GEMV reads x straight from that buffer — killing the per-layer
// dtoh(y)/host-norm/htod(x) round-trip the profiler measured as the SSD_STEP cost.
// Default OFF → the existing scan + host-norm + host out_proj path (parity ref).
fn gpu_ssm_fused_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| std::env::var("MESH_GPU_SSM_FUSED").map(|v| v == "1").unwrap_or(false))
}

/// Embedded CUBIN for the Mamba-2 gated-RMSNorm kernel (`mamba2_gated_norm.cu`,
/// arch from MESH_CUDA_ARCH; default sm_89). build.rs writes the compiled cubin or
/// an EMPTY file (nvcc absent/failed), so this `include_bytes!` always resolves;
/// empty ⇒ kernel unavailable ⇒ MESH_GPU_SSM_FUSED no-ops to the host-norm path.
const MAMBA2_GATED_NORM_CUBIN: &[u8] =
    include_bytes!(concat!(env!("OUT_DIR"), "/mamba2_gated_norm.cubin"));

/// Threads per block for the gated-norm launch. ONE BLOCK (d_inner ≤ this-thread
/// strided sweep); MUST be a power of two (the kernel's tree reduction assumes it).
const MAMBA2_GATED_NORM_BLOCK_DIM: u32 = 256;

/// True when the gated-norm kernel was compiled into this binary (build.rs set
/// `mamba2_gated_norm_kernel_cubin` AND the embedded cubin is non-empty). When
/// false, MESH_GPU_SSM_FUSED=1 silently no-ops to the host gated-norm path.
fn mamba2_gated_norm_kernel_available() -> bool {
    cfg!(mamba2_gated_norm_kernel_cubin) && !MAMBA2_GATED_NORM_CUBIN.is_empty()
}

/// Opt a loaded K-quant GEMV function into the sm_89 large-dynamic-shared limit
/// (`CU_FUNC_ATTRIBUTE_MAX_DYNAMIC_SHARED_SIZE_BYTES`) so a launch can reserve up
/// to `Q4K_MAX_DYNAMIC_SHARED_BYTES` (64 KB) of dynamic shared — above the 48 KB
/// classic cap — to stage x for the big-K (down-proj) GEMV. Best-effort: if a
/// driver rejects the attribute, the subsequent big-K launch (which requests
/// `K*4` > 48 KB shared) fails to launch and `q*_gemv_kernel` returns Err → the
/// caller falls through to the f16/CPU path UNCHANGED. So correctness is never
/// at risk; the worst case is the pre-existing (slower) fallback for big-K only.
/// On the L4 (Ada/sm_89, 99 KB/block) the attribute set succeeds and staging is
/// live. Small-K GEMVs (gate/up/qkv, K=3840 ≤ 48 KB) are unaffected regardless.
fn set_kquant_max_dynamic_shared(device: &Arc<CudaDevice>, module: &str, func: &str) {
    use cudarc::driver::sys::CUfunction_attribute_enum;
    let Some(f) = device.get_func(module, func) else {
        return;
    };
    match f.set_attribute(
        CUfunction_attribute_enum::CU_FUNC_ATTRIBUTE_MAX_DYNAMIC_SHARED_SIZE_BYTES,
        Q4K_MAX_DYNAMIC_SHARED_BYTES,
    ) {
        Ok(()) => eprintln!(
            "[cuda] {func}: max dynamic shared opted into {} KB (sm_89 large-shared; \
             enables shared-x staging up to K={})",
            Q4K_MAX_DYNAMIC_SHARED_BYTES / 1024,
            Q4K_SHARED_X_MAX_K,
        ),
        Err(e) => eprintln!(
            "[cuda] {func}: MAX_DYNAMIC_SHARED_SIZE_BYTES set failed ({e}) — big-K GEMVs \
             stay on the global-x path (correctness unaffected, just slower)"
        ),
    }
}

/// Global GPU context: one device + one cuBLAS handle for the process, plus a
/// resident-weight cache and a reusable activation-buffer pool. `None` if no
/// CUDA device is available (then callers fall back to the CPU kernel). Wrapped
/// in a Mutex because cuBLAS calls + the cache/pool mutation are serialized
/// through the single device stream; the heavy arithmetic happens on the GPU
/// regardless, so this lock is not the bottleneck.
struct GpuContext {
    device: Arc<CudaDevice>,
    blas: CudaBlas,
    /// Cache of resident dequantized Q8 weights (the DiT path), keyed by
    /// (host_ptr, byte_len). These are backed by a STABLE mmap for the whole
    /// render. The FULL DiT dequantized to f32 is ~47 GB (12.6 GB Q8 × ~4×) —
    /// far past the 24 GB L4 — so this cache is ALSO budgeted with FIFO eviction
    /// (`q8_budget_bytes`). A budget large enough to hold a handful of blocks
    /// keeps every in-flight GEMM of a block resident with zero re-upload while
    /// bounding VRAM; evicted blocks re-upload next pass at PCIe speed (cheap vs
    /// the CPU mmap stream). Without a budget this cache grew unbounded and the
    /// DiT silently OOMed the VRAM mid-block (the v4 "DiT hang").
    weights: HashMap<(usize, usize), Arc<CudaSlice<f32>>>,
    /// Insertion order for FIFO eviction of `weights` (the Q8 DiT cache).
    q8_order: std::collections::VecDeque<(usize, usize)>,
    /// Current resident Q8-derived-f32 bytes + the eviction budget.
    q8_bytes: u64,
    q8_budget_bytes: u64,
    /// Cache of resident ALREADY-f32 weights (the T5 path). T5 streams one block
    /// at a time and frees it (`Cow::Owned`), and the full f32 T5-XXL is ~18.5 GB
    /// — caching ALL of it would blow the 24 GB VRAM (and then leave no room for
    /// the 12.6 GB DiT). So this cache is BUDGETED: we evict the oldest entries
    /// (FIFO) once it exceeds `f32_budget_bytes`. Each T5 block (~770 MB) is used
    /// for all `seq` tokens across its 7 GEMMs before the next block, so a small
    /// budget (a few blocks) keeps every in-flight GEMM resident with zero
    /// re-upload while bounding VRAM.
    f32_weights: HashMap<(usize, usize), Arc<CudaSlice<f32>>>,
    /// Insertion order for FIFO eviction of `f32_weights`.
    f32_order: std::collections::VecDeque<(usize, usize)>,
    /// Current resident f32-weight bytes + the eviction budget.
    f32_bytes: u64,
    f32_budget_bytes: u64,
    /// Reusable activation-input buffer (`xs`), grown to the largest size seen.
    /// Reused across calls so we never cudaMalloc per matmul.
    xs_pool: Option<CudaSlice<f32>>,
    /// Reusable output buffer (`out`), grown to the largest size seen.
    out_pool: Option<CudaSlice<f32>>,
    /// f64-resident weight cache for the HIGH-PRECISION f32 GEMM path
    /// (MESH_GPU_F32_FP64=1). The f32 host weight is widened to f64 ONCE, uploaded
    /// once, and the GEMM runs cublasDgemm (f64 accumulate). Needed for
    /// hypersensitive decoders (mamba-2.8b's S6 scan) where cuBLAS sgemm's f32
    /// summation order tips the argmax off the exact-arithmetic token. Same
    /// (fingerprint, byte_len) keying + FIFO budget as `f32_weights`; bytes counted
    /// at 8/elem. Distinct key space from `f32_weights` (its own map), so the two
    /// never collide.
    f64_weights: HashMap<(usize, usize), Arc<CudaSlice<f64>>>,
    f64_order: std::collections::VecDeque<(usize, usize)>,
    f64_bytes: u64,
    f64_budget_bytes: u64,
    /// f64 activation/output pools for the Dgemm path (grown like the f32 pools).
    xs_pool_d: Option<CudaSlice<f64>>,
    out_pool_d: Option<CudaSlice<f64>>,
    /// f16-resident weight cache (FLUX_GPU_WEIGHT_DTYPE=f16 — the 7-8B LLM
    /// path). Same (host_ptr, byte_len) keying + FIFO budget as the f32
    /// caches; bytes counted at 2/elem.
    weights_h: HashMap<(usize, usize), Arc<CudaSlice<f16>>>,
    /// bf16-resident weight cache (FLUX_GPU_WEIGHT_DTYPE=bf16). Shares the
    /// h_bytes/h_order/h_budget accounting with the f16 cache — only one half
    /// dtype is active per process, so at most one of weights_h/weights_b is
    /// ever populated.
    weights_b: HashMap<(usize, usize), Arc<CudaSlice<bf16>>>,
    h_order: std::collections::VecDeque<(usize, usize)>,
    h_bytes: u64,
    h_budget_bytes: u64,
    /// f16 activation/output pools for the GemmEx 16F path.
    xs_pool_h: Option<CudaSlice<f16>>,
    out_pool_h: Option<CudaSlice<f16>>,
    /// bf16 activation/output pools for the GemmEx 16BF path.
    xs_pool_b: Option<CudaSlice<bf16>>,
    out_pool_b: Option<CudaSlice<bf16>>,
    // --- MESH_GPU_SLAB=1 (additive, default OFF): contiguous f16 residency slab.
    // One big alloc holds ALL f16 weights so there is no per-weight cudaMalloc
    // fragmentation and zero CPU fallback (fixes the ~12 GB residency ceiling the
    // per-weight `resident_weight_dequant_f16` mallocs hit on the 24 GB L4). The
    // weight device pointer is the slab base device pointer + byte offset; the
    // cublas GEMM takes a raw `*const c_void` so no typed CudaView is needed.
    /// The single contiguous f16 weight slab. `None` until the first slab-path
    /// call lazily allocs it (`MESH_GPU_SLAB_GB`, default 22 GB worth of f16).
    slab: Option<CudaSlice<f16>>,
    /// Map weight fingerprint-key -> (offset_elems, len_elems) within the slab.
    /// A hit returns the cached sub-range pointer; a miss bump-allocates.
    slab_map: HashMap<(usize, usize), (usize, usize)>,
    /// MESH_GPU_FUSE=1: map a GROUP key (combined member fingerprints, cols) ->
    /// (group_offset_elems, total_rows) of a CONTIGUOUSLY-packed projection group
    /// (gate+up, q+k+v). Lets a fused GEMM read the whole group as one weight.
    slab_group_map: HashMap<(usize, usize), (usize, usize)>,
    /// Bump cursor (elems used) and capacity (elems) of the slab.
    slab_used_elems: usize,
    slab_capacity_elems: usize,
    // --- MESH_GPU_Q8K=1 (additive, default OFF): custom in-kernel Q8 GEMV.
    /// Resident RAW Q8_0 weight bytes (the WHOLE point — read ~7.7 GB instead of
    /// the ~14.5 GB f16 working set). Keyed by (weight_fingerprint, byte_len),
    /// the SAME content-fingerprint key as the slab/f16 caches. Bytes are
    /// uploaded ONCE via htod_sync_copy (NO host dequant) and reused per token.
    /// FIFO-evicted under `q8raw_budget_bytes`.
    q8raw_weights: HashMap<(usize, usize), Arc<CudaSlice<u8>>>,
    q8raw_order: std::collections::VecDeque<(usize, usize)>,
    q8raw_bytes: u64,
    q8raw_budget_bytes: u64,
    /// True once the q8_gemv PTX module has been loaded into this device
    /// (`load_ptx` is idempotent-once per (device, module_name)). `false` if the
    /// PTX is empty / load failed → the kernel path is unavailable.
    q8k_ptx_loaded: bool,
    // --- MESH_GPU_Q4K=1 (additive, default OFF): custom in-kernel K-quant GEMVs.
    /// Resident RAW Q4_K / Q6_K weight bytes (the WHOLE point — read ~4.0 GB
    /// instead of the ~14.5 GB f16 working set). SAME (fingerprint, byte_len)
    /// keying + FIFO budget as `q8raw_weights`; the two K-quant formats share one
    /// raw-byte cache and budget (only one weight content lives per key). Bytes
    /// uploaded ONCE via htod_sync_copy (NO host dequant) and reused per token.
    q4kraw_weights: HashMap<(usize, usize), Arc<CudaSlice<u8>>>,
    q4kraw_order: std::collections::VecDeque<(usize, usize)>,
    q4kraw_bytes: u64,
    q4kraw_budget_bytes: u64,
    /// True once the q4k_gemv / q6k_gemv cubin modules have been loaded into this
    /// device (idempotent-once). `false` if the cubin is empty / load failed →
    /// that kernel path is unavailable.
    q4k_cubin_loaded: bool,
    q6k_cubin_loaded: bool,
    /// True once the prefill_attn softmax cubin module has been loaded into this
    /// device (idempotent-once). `false` if the cubin is empty / load failed →
    /// the GPU prefill-attention path is unavailable (caller runs CPU Phase B).
    prefill_attn_cubin_loaded: bool,
    // --- MESH_GPU_SCAN=1 (additive, default OFF): GPU Mamba-1 S6 selective-scan.
    /// True once the mamba_scan cubin module has been loaded into this device
    /// (idempotent-once). `false` if the cubin is empty / load failed → the
    /// GPU-scan path is unavailable and the caller runs the CPU S6 scan.
    mamba_scan_cubin_loaded: bool,
    /// RESIDENT recurrent state `h` [d_inner × d_state] per Mamba layer, keyed by
    /// `(layer_idx, d_inner*d_state)` — the layer's POSITION in the stack, NOT a
    /// content hash of its weights. Keying state by layer index guarantees each
    /// layer owns a distinct VRAM buffer even if two layers' `a_log` tensors hash
    /// alike (or an init-shared / barely-trained A_log), which would otherwise let
    /// layers clobber each other's recurrence — a state-carry corruption that
    /// worsens with sequence length. The WHOLE point: `h` lives in VRAM across
    /// tokens (seeded from the host CPU state on first use, updated in-place every
    /// step) so there is NO per-token H2D/D2H of the state. `mamba_scan_reset_all`
    /// clears this map at a sequence boundary so the next step re-seeds from the
    /// freshly-zeroed host state.
    mamba_h: HashMap<(usize, usize), CudaSlice<f32>>,
    /// Resident `a_log` [d_inner × d_state] per layer (uploaded ONCE, keyed by its
    /// own fingerprint = the layer id). Read-only across tokens.
    mamba_alog: HashMap<(usize, usize), Arc<CudaSlice<f32>>>,
    /// Resident `d_skip` [d_inner] per layer (uploaded ONCE, keyed by fingerprint).
    mamba_dskip: HashMap<(usize, usize), Arc<CudaSlice<f32>>>,
    /// Reusable per-token upload scratch, packed [dt(d_inner) | x_conv(d_inner) |
    /// B(d_state) | C(d_state)]. Grown to the largest shape seen; no per-call
    /// cudaMalloc. Read-only during the launch.
    mamba_scratch: Option<CudaSlice<f32>>,
    /// Reusable HOST staging buffer for the Mamba-2 scan's per-token scratch pack
    /// `[dt | x_conv | B | C]`. Filled by `extend_from_slice` and uploaded in ONE
    /// `htod_sync_copy_into` (vs four separate ones) so the layer costs 1 blocking
    /// host→device sync instead of 4 (256→64 per token across 64 layers). Grown to
    /// the largest pack seen; `clear()`ed and re-filled each call (capacity reused).
    mamba_scratch_host: Vec<f32>,
    /// Reusable per-token output pool [d_inner] (written by the launch, then dtoh).
    /// Kept separate from `mamba_scratch` so the launch can borrow the read-only
    /// scratch inputs and the mutable output simultaneously (disjoint fields).
    mamba_y: Option<CudaSlice<f32>>,
    // --- MESH_GPU_SCAN=1 (additive, default OFF): GPU Mamba-2 (SSD) selective-scan.
    // Parallel to the Mamba-1 S6 state above; a given model is either Mamba-1 OR
    // Mamba-2, never both, but the fields are kept distinct so the two paths never
    // alias state buffers. Read-only weights (a_log/d_skip) are per-head SCALARS
    // here (not the S6 per-channel [d_inner·d_state] matrix), so these maps are tiny.
    /// True once the mamba2_ssd_scan cubin module has been loaded into this device.
    mamba2_scan_cubin_loaded: bool,
    /// RESIDENT recurrent state `h` [num_heads·head_dim·d_state = d_inner·d_state]
    /// per Mamba-2 layer, keyed by `(layer_idx, d_inner*d_state)` — the layer's
    /// POSITION in the stack, NOT a content hash of its weights (same rationale as
    /// `mamba_h`). Lives in VRAM across tokens (seeded from the host state on first
    /// use, updated in-place). `mamba_scan_reset_all` clears it at a sequence boundary.
    mamba2_h: HashMap<(usize, usize), CudaSlice<f32>>,
    /// Resident `a_log` [num_heads] per layer (uploaded ONCE, keyed by its own
    /// fingerprint = the layer id). Read-only across tokens.
    mamba2_alog: HashMap<(usize, usize), Arc<CudaSlice<f32>>>,
    /// Resident `d_skip` [num_heads] per layer (uploaded ONCE, keyed by fingerprint).
    mamba2_dskip: HashMap<(usize, usize), Arc<CudaSlice<f32>>>,
    // --- MESH_GPU_SSM_FUSED=1 (additive, default OFF): device gated-RMSNorm +
    // resident out_proj so the scan output never dtoh's. Distinct from `mamba_y`
    // (the scan's raw output) so the norm reads mamba_y and writes here WITHOUT
    // clobbering its own input, and so out_proj can read a stable normed buffer.
    /// True once the mamba2_gated_norm cubin module has been loaded into this device.
    mamba2_gated_norm_cubin_loaded: bool,
    /// RESIDENT normed-y [d_inner]: the gated-RMSNorm output, written by the
    /// gated-norm kernel and read directly by the resident out_proj GEMV. Grown to
    /// fit; kept DISTINCT from `mamba_y` so the norm's y_in (mamba_y) is untouched.
    mamba2_y_normed: Option<CudaSlice<f32>>,
    /// Reusable per-token upload buffer for the gate `z` [d_inner] (a fresh
    /// activation each token → one small htod per layer, unavoidable). Pooled so
    /// there is no per-call cudaMalloc.
    mamba2_z: Option<CudaSlice<f32>>,
    /// Resident gated-RMSNorm gamma `norm_w` [d_inner] per layer (uploaded ONCE,
    /// keyed by its fingerprint like a_log/d_skip — read-only across tokens).
    mamba2_normw: HashMap<(usize, usize), Arc<CudaSlice<f32>>>,
}

// SAFETY: all access is funneled through the process-wide Mutex below; the
// CudaDevice/CudaBlas handles are used only while that lock is held.
unsafe impl Send for GpuContext {}

static GPU: OnceLock<Option<Mutex<GpuContext>>> = OnceLock::new();

/// Op counters for instrumentation (lock-free; read on a periodic basis).
static GPU_OPS: AtomicU64 = AtomicU64::new(0);
/// Count of ops routed to CPU by the liquid-memory saturation policy.
static SATURATION_OPS: AtomicU64 = AtomicU64::new(0);
static WEIGHT_UPLOADS: AtomicU64 = AtomicU64::new(0);
static WEIGHT_BYTES_UP: AtomicU64 = AtomicU64::new(0);
/// Per-PHASE (e.g. T5 vs DiT) counters, reset by `begin_dit_phase`, so the
/// "first 8" log heuristic fires again at the DiT boundary instead of being
/// silenced by the global T5 counts (the "DiT does ZERO gemms" log artifact).
static PHASE_UPLOADS: AtomicU64 = AtomicU64::new(0);
static PHASE_OPS: AtomicU64 = AtomicU64::new(0);
static CUDA_UPLOAD_LOG_EVERY: OnceLock<u64> = OnceLock::new();
static CUDA_OP_LOG_EVERY: OnceLock<u64> = OnceLock::new();

fn env_u64(name: &str) -> Option<u64> {
    std::env::var(name)
        .ok()
        .and_then(|raw| raw.trim().parse::<u64>().ok())
}

// --- Mamba-2 SSD scan micro-profiler (MESH_PROFILE_MAMBA=1) ------------------
// Splits the per-layer scan wall-time into three buckets so we can tell whether
// the measured ~1.7 ms/layer ssd_step is the htod(scratch) sync or the kernel
// itself (see MAMBA2_VGPU_FUSED_LAYER.md — S1 falsified the dtoh/host-norm read):
//   htod   — the per-token scratch pack upload(s) + any first-use resident seed
//            (a_log / d_skip / h) in `mamba2_scan_into_mamba_y`.
//   launch — the `mamba2_ssd_scan` kernel launch itself.
//   tail   — the non-fused y dtoh (`mamba2_ssd_scan`) OR the fused device
//            gated-norm (`mamba2_ssd_scan_fused`), whichever ran.
// Accumulated process-wide and printed once every MESH_MAMBA_SCAN_PROF_EVERY
// scan calls (default 64 ≈ one codestral token), then reset — so each line is a
// per-token breakdown, mirroring the model_mamba `[mamba-prof]` cadence.
struct MambaScanProf {
    htod: u128,
    launch: u128,
    tail: u128,
    calls: u64,
}
static MAMBA_SCAN_PROF: OnceLock<Mutex<MambaScanProf>> = OnceLock::new();

fn mamba_scan_prof_enabled() -> bool {
    static E: OnceLock<bool> = OnceLock::new();
    *E.get_or_init(|| std::env::var("MESH_PROFILE_MAMBA").is_ok())
}

fn mamba_scan_prof_every() -> u64 {
    static N: OnceLock<u64> = OnceLock::new();
    *N.get_or_init(|| env_u64("MESH_MAMBA_SCAN_PROF_EVERY").filter(|n| *n > 0).unwrap_or(64))
}

/// Accumulate one slice of scan wall-time (nanoseconds). `bump_call` is set once
/// per scan (by the helper) to mark a completed layer-step; when the running
/// count crosses the print window the accumulated per-window totals are logged
/// (in ms) and reset. No-op unless MESH_PROFILE_MAMBA is set.
fn mamba_scan_prof_add(htod: u128, launch: u128, tail: u128, bump_call: bool) {
    if !mamba_scan_prof_enabled() {
        return;
    }
    let m = MAMBA_SCAN_PROF
        .get_or_init(|| Mutex::new(MambaScanProf { htod: 0, launch: 0, tail: 0, calls: 0 }));
    let mut p = m.lock().unwrap();
    p.htod += htod;
    p.launch += launch;
    p.tail += tail;
    if bump_call {
        p.calls += 1;
        let every = mamba_scan_prof_every();
        if p.calls % every == 0 {
            let (h, l, t) =
                (p.htod as f64 / 1e6, p.launch as f64 / 1e6, p.tail as f64 / 1e6);
            eprintln!(
                "[mamba-scan-prof] htod={h:.1}ms launch={l:.1}ms tail={t:.1}ms \
                 (over {every} scan calls ≈ 1 token)"
            );
            p.htod = 0;
            p.launch = 0;
            p.tail = 0;
        }
    }
}

fn cuda_upload_log_every() -> u64 {
    *CUDA_UPLOAD_LOG_EVERY.get_or_init(|| {
        env_u64("FLUX_GPU_UPLOAD_LOG_EVERY")
            .or_else(|| env_u64("FLUX_GPU_LOG_EVERY"))
            .unwrap_or(64)
    })
}

fn cuda_op_log_every() -> u64 {
    *CUDA_OP_LOG_EVERY.get_or_init(|| {
        env_u64("FLUX_GPU_OP_LOG_EVERY")
            .or_else(|| env_u64("FLUX_GPU_LOG_EVERY"))
            .unwrap_or(256)
    })
}

fn should_log_phase(phase: u64, every: u64) -> bool {
    phase <= 8 || (every > 0 && phase % every == 0)
}

/// Mark the start of the DiT denoise phase: free the T5 encoder's resident f32
/// weights (so the ~24 GB L4 is almost entirely free for the DiT working set)
/// and reset the per-phase instrumentation counters. Safe no-op when the GPU is
/// not engaged. Call once, right before the first `dit.velocity(...)`.
pub fn begin_dit_phase() {
    PHASE_UPLOADS.store(0, Ordering::Relaxed);
    PHASE_OPS.store(0, Ordering::Relaxed);
    let Some(ctx) = gpu() else {
        return;
    };
    let Ok(mut guard) = ctx.lock() else {
        return;
    };
    let freed_gb = guard.f32_bytes as f64 / 1e9;
    let n = guard.f32_weights.len();
    guard.f32_weights.clear();
    guard.f32_order.clear();
    guard.f32_bytes = 0;
    eprintln!(
        "[cuda] DiT phase begin — freed {n} resident T5 f32 weights ({freed_gb:.2} GB VRAM \
         reclaimed); DiT Q8->f32 cache budget {:.1} GB",
        guard.q8_budget_bytes as f64 / 1e9,
    );
}

/// Report (free, total) VRAM bytes on the active device, or `None` if the GPU
/// is not engaged / the query fails. Used to instrument the DiT-setup gap so a
/// VRAM-OOM (silent cudaMalloc failure / hang) is visible in the logs.
pub fn vram_free_total() -> Option<(usize, usize)> {
    let ctx = gpu()?;
    let guard = ctx.lock().ok()?;
    // mem_get_info() is a free CUDA call requiring this device's context to be
    // current on the calling thread; bind it first (all GPU work funnels through
    // this mutex, so binding here is safe and cheap).
    guard.device.bind_to_thread().ok()?;
    cudarc::driver::result::mem_get_info().ok()
}

/// Log a one-line VRAM snapshot with a caller-supplied marker. No-op without a
/// GPU. Flushes stderr so the line lands even if the next op hangs/OOM-kills.
pub fn log_vram(marker: &str) {
    if let Some((free, total)) = vram_free_total() {
        eprintln!(
            "[vram] {marker}: free={:.2} GB / total={:.2} GB (used={:.2} GB)",
            free as f64 / 1e9,
            total as f64 / 1e9,
            (total - free) as f64 / 1e9,
        );
        use std::io::Write;
        let _ = std::io::stderr().flush();
    }
}

/// Initialize (once) the GPU context. Returns `false` if no device is present
/// or initialization failed — callers then use the CPU path. Honors
/// `FLUX_GPU=0` to force the CPU path even on a GPU host (debugging / A-B).
fn gpu() -> Option<&'static Mutex<GpuContext>> {
    GPU.get_or_init(|| {
        if std::env::var("FLUX_GPU").map(|v| v == "0").unwrap_or(false) {
            eprintln!("[cuda] FLUX_GPU=0 — GPU backend disabled, using CPU kernels");
            return None;
        }
        match CudaDevice::new(0) {
            Ok(device) => match CudaBlas::new(device.clone()) {
                Ok(blas) => {
                    let name = device
                        .name()
                        .unwrap_or_else(|_| "<unknown CUDA device>".to_string());
                    // Force STRICT FP32 (no TF32 tensor-core rounding). On Ada/L4
                    // cuBLAS can transparently down-route FP32 GEMM to TF32
                    // (10-bit mantissa) for some call paths; over a 4-step FLUX
                    // denoise that rounding can corrupt the velocity field into
                    // structured noise. PEDANTIC math makes the GPU GEMM
                    // bit-comparable to the CPU f32 kernel (the source of truth).
                    // Honors FLUX_GPU_TF32=1 to opt back into TF32 for A/B.
                    let allow_tf32 = std::env::var("FLUX_GPU_TF32")
                        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
                        .unwrap_or(false);
                    let mode = if allow_tf32 {
                        cudarc::cublas::sys::cublasMath_t::CUBLAS_TF32_TENSOR_OP_MATH
                    } else {
                        cudarc::cublas::sys::cublasMath_t::CUBLAS_PEDANTIC_MATH
                    };
                    // SAFETY: `blas.handle()` is a live cuBLAS handle on this
                    // thread's bound device context; `lib()` is the same loaded
                    // cuBLAS the gemm calls use.
                    let math_status = unsafe {
                        cudarc::cublas::sys::lib().cublasSetMathMode(*blas.handle(), mode)
                    };
                    eprintln!(
                        "[cuda] cublasSetMathMode({}) -> {:?}",
                        if allow_tf32 { "TF32_TENSOR_OP" } else { "PEDANTIC (strict fp32)" },
                        math_status
                    );
                    eprintln!("[cuda] GPU matmul backend ACTIVE on device 0: {name}");
                    eprintln!(
                        "[cuda] gpu_min_tokens={} (single-vector GEMV runs on CPU below this)",
                        gpu_min_tokens()
                    );
                    // f32 T5-weight VRAM budget (bytes). Default 6 GB ≈ ~8 T5
                    // blocks resident, well clear of the 24 GB L4 and the DiT's
                    // ~12.6 GB. Overridable via FLUX_GPU_F32_BUDGET_GB.
                    let f32_budget_bytes = std::env::var("FLUX_GPU_F32_BUDGET_GB")
                        .ok()
                        .and_then(|v| v.parse::<f64>().ok())
                        .map(|gb| (gb * 1e9) as u64)
                        .unwrap_or(6_000_000_000);
                    // DiT Q8->f32 VRAM budget (bytes). The full DiT f32 working
                    // set is ~47 GB; the L4 has 24 GB. After T5's resident f32
                    // weights are freed at the DiT boundary (`begin_dit_phase`)
                    // almost the whole 24 GB is free, so a default 16 GB budget
                    // keeps many DiT blocks resident, never OOMs, and the rest
                    // re-upload per pass at PCIe speed. Overridable via
                    // FLUX_GPU_Q8_BUDGET_GB.
                    let q8_budget_bytes = std::env::var("FLUX_GPU_Q8_BUDGET_GB")
                        .ok()
                        .and_then(|v| v.parse::<f64>().ok())
                        .map(|gb| (gb * 1e9) as u64)
                        .unwrap_or(19_000_000_000);
                    // f16-resident weight budget (FLUX_GPU_WEIGHT_DTYPE=f16).
                    // Default 16 GB keeps a full 7B model resident (~14.5 GB)
                    // with headroom for activations on the 24 GB L4.
                    let h_budget_bytes = std::env::var("FLUX_GPU_F16_BUDGET_GB")
                        .ok()
                        .and_then(|v| v.parse::<f64>().ok())
                        .map(|gb| (gb * 1e9) as u64)
                        .unwrap_or(16_000_000_000);
                    // RAW Q8_0 residency budget (MESH_GPU_Q8K). A 7-8B q8 knot is
                    // ~7.7 GB of raw bytes; default 16 GB holds it whole with
                    // activation headroom on the 24 GB L4. Override via
                    // MESH_GPU_Q8K_BUDGET_GB.
                    let q8raw_budget_bytes = std::env::var("MESH_GPU_Q8K_BUDGET_GB")
                        .ok()
                        .and_then(|v| v.parse::<f64>().ok())
                        .map(|gb| (gb * 1e9) as u64)
                        .unwrap_or(16_000_000_000);
                    // RAW K-quant (Q4_K + Q6_K) residency budget (MESH_GPU_Q4K). A
                    // 7B Q4_K_M knot is ~4.0 GB of raw bytes; default 8 GB holds
                    // it whole with generous activation headroom on the 24 GB L4.
                    // Override via MESH_GPU_Q4K_BUDGET_GB.
                    let q4kraw_budget_bytes = std::env::var("MESH_GPU_Q4K_BUDGET_GB")
                        .ok()
                        .and_then(|v| v.parse::<f64>().ok())
                        .map(|gb| (gb * 1e9) as u64)
                        .unwrap_or(8_000_000_000);
                    eprintln!(
                        "[cuda] VRAM budgets: T5-f32={:.1} GB, DiT-Q8->f32={:.1} GB \
                         (full DiT f32 ~47 GB > 24 GB L4, so FIFO-evicted)",
                        f32_budget_bytes as f64 / 1e9,
                        q8_budget_bytes as f64 / 1e9,
                    );
                    eprintln!(
                        "[cuda] log cadence: uploads first 8 + every {}, ops first 8 + every {} \
                         (override FLUX_GPU_UPLOAD_LOG_EVERY / FLUX_GPU_OP_LOG_EVERY / FLUX_GPU_LOG_EVERY)",
                        cuda_upload_log_every(),
                        cuda_op_log_every(),
                    );
                    if weight_dtype_is_bf16() {
                        eprintln!(
                            "[cuda] weight dtype = bf16 (GemmEx 16BF storage, 32F accumulate; \
                             8-bit exponent — no f16 overflow); budget {:.1} GB",
                            h_budget_bytes as f64 / 1e9,
                        );
                    } else if weight_dtype_is_f16() {
                        eprintln!(
                            "[cuda] weight dtype = f16 (GemmEx 16F storage, 32F accumulate); \
                             f16 budget {:.1} GB",
                            h_budget_bytes as f64 / 1e9,
                        );
                    }
                    if gpu_slab_enabled() {
                        eprintln!(
                            "[cuda] MESH_GPU_SLAB=1 — contiguous f16 residency slab \
                             ({:.1} GB cap, no per-weight malloc / no CPU fallback; \
                             requires FLUX_GPU_WEIGHT_DTYPE=f16). override MESH_GPU_SLAB_GB",
                            gpu_slab_capacity_elems() as f64 * 2.0 / 1e9,
                        );
                        if !weight_dtype_is_f16() {
                            eprintln!(
                                "[cuda] WARNING: MESH_GPU_SLAB=1 but FLUX_GPU_WEIGHT_DTYPE != f16 \
                                 — slab path is INACTIVE (only the f16 branch uses it)"
                            );
                        }
                    }
                    if gpu_fuse_enabled() {
                        if gpu_slab_enabled() && weight_dtype_is_f16() {
                            eprintln!(
                                "[cuda] MESH_GPU_FUSE=1 — fused-projection lever ACTIVE (FFN gate+up \
                                 fused into ONE slab GEMM + ONE dtoh; q+k+v left per-projection). \
                                 Requires MESH_GPU_SLAB=1 + FLUX_GPU_WEIGHT_DTYPE=f16."
                            );
                        } else {
                            eprintln!(
                                "[cuda] WARNING: MESH_GPU_FUSE=1 but MESH_GPU_SLAB=1 + \
                                 FLUX_GPU_WEIGHT_DTYPE=f16 not BOTH set — fused path is INACTIVE \
                                 (routes to the per-projection path)"
                            );
                        }
                    }
                    if gpu_q8k_enabled() {
                        if q8_kernel_available() {
                            eprintln!(
                                "[cuda] MESH_GPU_Q8K=1 — custom in-kernel Q8_0 dequant-GEMV ACTIVE \
                                 for single-token decode (reads RAW Q8 ~7.7 GB vs f16 ~14.5 GB; \
                                 raw-Q8 budget {:.1} GB). override MESH_GPU_Q8K_BUDGET_GB",
                                q8raw_budget_bytes as f64 / 1e9,
                            );
                        } else {
                            eprintln!(
                                "[cuda] WARNING: MESH_GPU_Q8K=1 but the q8_gemv PTX is unavailable \
                                 (nvcc absent at build time) — kernel path INACTIVE, decode uses \
                                 the existing cuBLAS/CPU path"
                            );
                        }
                    }
                    if gpu_q4k_enabled() {
                        if q4k_kernel_available() && q6k_kernel_available() {
                            eprintln!(
                                "[cuda] MESH_GPU_Q4K=1 — custom in-kernel Q4_K + Q6_K dequant-GEMV \
                                 ACTIVE for single-token decode (reads RAW K-quant ~4.0 GB vs f16 \
                                 ~14.5 GB; raw budget {:.1} GB). override MESH_GPU_Q4K_BUDGET_GB",
                                q4kraw_budget_bytes as f64 / 1e9,
                            );
                        } else {
                            eprintln!(
                                "[cuda] WARNING: MESH_GPU_Q4K=1 but the q4k_gemv/q6k_gemv cubin is \
                                 unavailable (q4k={}, q6k={}; nvcc absent at build time) — K-quant \
                                 kernel path INACTIVE, decode uses the existing cuBLAS/CPU path",
                                q4k_kernel_available(),
                                q6k_kernel_available(),
                            );
                        }
                    }
                    if gpu_scan_enabled() {
                        if mamba_scan_kernel_available() {
                            eprintln!(
                                "[cuda] MESH_GPU_SCAN=1 — GPU Mamba-1 S6 selective-scan ACTIVE \
                                 (recurrent state resident in VRAM across tokens; moves the \
                                 ~2.2 s/token CPU scan onto the GPU, byte-faithful numerics)"
                            );
                        } else {
                            eprintln!(
                                "[cuda] WARNING: MESH_GPU_SCAN=1 but the mamba_scan cubin is \
                                 unavailable (nvcc absent at build time) — GPU-scan path INACTIVE, \
                                 decode uses the existing CPU S6 scan"
                            );
                        }
                        if mamba2_ssd_scan_kernel_available() {
                            eprintln!(
                                "[cuda] MESH_GPU_SCAN=1 — GPU Mamba-2 SSD selective-scan ACTIVE \
                                 (grouped multi-head; recurrent state resident in VRAM across \
                                 tokens, host does softplus(dt) + the gated RMSNorm)"
                            );
                        } else {
                            eprintln!(
                                "[cuda] WARNING: MESH_GPU_SCAN=1 but the mamba2_ssd_scan cubin is \
                                 unavailable (nvcc absent at build time) — GPU SSD-scan path \
                                 INACTIVE, decode uses the existing CPU SSD scan"
                            );
                        }
                    }
                    Some(Mutex::new(GpuContext {
                        device,
                        blas,
                        weights: HashMap::new(),
                        q8_order: std::collections::VecDeque::new(),
                        q8_bytes: 0,
                        q8_budget_bytes,
                        f32_weights: HashMap::new(),
                        f32_order: std::collections::VecDeque::new(),
                        f32_bytes: 0,
                        f32_budget_bytes,
                        xs_pool: None,
                        out_pool: None,
                        f64_weights: HashMap::new(),
                        f64_order: std::collections::VecDeque::new(),
                        f64_bytes: 0,
                        // Reuse the f32 budget knob (FLUX_GPU_F32_BUDGET_GB) — the
                        // f64 residency is opt-in (MESH_GPU_F32_FP64=1) and only the
                        // pure-f32 tensors (mamba x_proj/dt_proj/lm_head) use it, so
                        // sharing the ceiling keeps VRAM bounded without a new knob.
                        f64_budget_bytes: f32_budget_bytes,
                        xs_pool_d: None,
                        out_pool_d: None,
                        weights_h: HashMap::new(),
                        weights_b: HashMap::new(),
                        h_order: std::collections::VecDeque::new(),
                        h_bytes: 0,
                        h_budget_bytes,
                        xs_pool_h: None,
                        out_pool_h: None,
                        xs_pool_b: None,
                        out_pool_b: None,
                        slab: None,
                        slab_map: HashMap::new(),
                        slab_group_map: HashMap::new(),
                        slab_used_elems: 0,
                        slab_capacity_elems: gpu_slab_capacity_elems(),
                        q8raw_weights: HashMap::new(),
                        q8raw_order: std::collections::VecDeque::new(),
                        q8raw_bytes: 0,
                        q8raw_budget_bytes,
                        q8k_ptx_loaded: false,
                        q4kraw_weights: HashMap::new(),
                        q4kraw_order: std::collections::VecDeque::new(),
                        q4kraw_bytes: 0,
                        q4kraw_budget_bytes,
                        q4k_cubin_loaded: false,
                        q6k_cubin_loaded: false,
                        prefill_attn_cubin_loaded: false,
                        mamba_scan_cubin_loaded: false,
                        mamba_h: HashMap::new(),
                        mamba_alog: HashMap::new(),
                        mamba_dskip: HashMap::new(),
                        mamba_scratch: None,
                        mamba_scratch_host: Vec::new(),
                        mamba_y: None,
                        mamba2_scan_cubin_loaded: false,
                        mamba2_h: HashMap::new(),
                        mamba2_alog: HashMap::new(),
                        mamba2_dskip: HashMap::new(),
                        mamba2_gated_norm_cubin_loaded: false,
                        mamba2_y_normed: None,
                        mamba2_z: None,
                        mamba2_normw: HashMap::new(),
                    }))
                }
                Err(e) => {
                    eprintln!("[cuda] cuBLAS init failed ({e}) — falling back to CPU");
                    None
                }
            },
            Err(e) => {
                eprintln!("[cuda] no CUDA device 0 ({e}) — falling back to CPU");
                None
            }
        }
    })
    .as_ref()
}

/// True when the GPU backend is built in AND a device initialized successfully.
pub fn gpu_available() -> bool {
    gpu().is_some()
}

/// GEMMA4_DBG helper: true when the f16-resident weight dtype is selected
/// (`FLUX_GPU_WEIGHT_DTYPE=f16`). Lets the gemma4 forward log whether a layer's
/// projection GEMMs would route through the f16 CUDA path (the suspect path for
/// the gemma4-arch garbage-logits bug). Pairs with `gpu_wants(tokens)` at the
/// call site: a matmul takes the GPU f16 path iff `gpu_wants(tokens) &&
/// weight_dtype_f16()`.
pub fn weight_dtype_f16() -> bool {
    weight_dtype_is_f16()
}

/// Eagerly initialize + report the GPU backend at process startup so engagement
/// is NEVER ambiguous. Without this the `[cuda]` line only fires lazily on the
/// first matmul, which is buried ~27 min into the T5 stage — if the process is
/// killed before then (client disconnect) you never learn whether the L4 was
/// used. Call this once, right after arg-parse, before the heavy stages.
///
/// Prints exactly one definitive line to stderr:
///   "[cuda] GPU matmul backend ACTIVE on device 0: NVIDIA L4"   (engaged), or
///   "[cuda] no CUDA device 0 (...) — falling back to CPU"       (CPU fallback).
/// Returns true when the GPU is engaged.
pub fn report_gpu_engagement() -> bool {
    let engaged = gpu_available();
    if !engaged {
        // gpu() already logged the specific failure reason; add a loud summary.
        eprintln!(
            "[cuda] GPU NOT engaged — running the SLOW CPU matmul path \
             (a 256² FLUX render will take ~hours). Check nvidia-smi/libcuda \
             on this host."
        );
    }
    engaged
}

impl GpuContext {
    /// Get (or build + cache) the resident f32 weight buffer for a Q8_0 weight
    /// slice. Dequant happens on the host ONCE; the f32 buffer lives in VRAM for
    /// the rest of the render. Key is (ptr, len) of the Q8 source bytes.
    fn resident_weight(
        &mut self,
        w: &[u8],
        rows: usize,
        cols: usize,
    ) -> Result<Arc<CudaSlice<f32>>, String> {
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.weights.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = (rows * cols * 4) as u64;
        // Liquid-memory fallback (LLM Q8 path, env-gated off by default so FLUX
        // keeps evicting): saturation → CPU instead of re-upload thrash.
        if saturation_falls_back_to_cpu() && self.q8_bytes + bytes > self.q8_budget_bytes {
            return Err(VRAM_SATURATED.to_string());
        }
        // Evict oldest (FIFO) until this upload fits the DiT budget. The full DiT
        // f32 working set (~47 GB) cannot all stay resident on the 24 GB L4, so a
        // budgeted cache is mandatory: without it the cache grew unbounded and the
        // first DiT pass silently OOMed VRAM mid-block (no further gemms => the
        // "DiT hang"). Evicted blocks re-upload next pass at PCIe speed.
        while self.q8_bytes + bytes > self.q8_budget_bytes {
            let Some(old_key) = self.q8_order.pop_front() else {
                break;
            };
            if let Some(old) = self.weights.remove(&old_key) {
                self.q8_bytes = self.q8_bytes.saturating_sub((old.len() * 4) as u64);
                drop(old); // frees the device buffer (last Arc) -> VRAM reclaimed
            }
        }
        let t_deq = Instant::now();
        // Dequantize Q8_0 -> f32 on the host (parallel over rows), row-major
        // [rows*cols], exactly matching `dequantize_q8_0_row` so the GPU GEMM is
        // numerically equivalent to the CPU kernel (last-bit reduction noise
        // only).
        use gnosis_frf::prelude::*;
        let mut host = vec![0.0f32; rows * cols];
        host.par_chunks_mut(cols).enumerate().for_each(|(r, dst)| {
            dequantize_q8_0_row(dst, w, r, cols);
        });
        let deq_ms = t_deq.elapsed().as_secs_f64() * 1e3;
        let t_up = Instant::now();
        let dev = self
            .device
            .htod_sync_copy(&host)
            .map_err(|e| format!("[cuda] weight htod_sync_copy failed (Q8 {rows}x{cols}, {:.0} MB, q8 resident {:.2} GB / budget {:.1} GB): {e}",
                bytes as f64 / 1e6,
                self.q8_bytes as f64 / 1e9,
                self.q8_budget_bytes as f64 / 1e9))?;
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        // Log the first few uploads OF THIS PHASE + every 64th so we can SEE the
        // DiT cache working even though the global counter is past 8 from T5.
        if should_log_phase(phase_up, cuda_upload_log_every()) {
            eprintln!(
                "[cuda] Q8 weight upload #{n_up} (phase #{phase_up}) MISS [{rows}x{cols}] {:.1} MB \
                 dequant={deq_ms:.1}ms htod={up_ms:.1}ms (q8 resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                (self.q8_bytes + bytes) as f64 / 1e9,
                self.q8_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.weights.insert(key, arc.clone());
        self.q8_order.push_back(key);
        self.q8_bytes += bytes;
        Ok(arc)
    }

    /// Get (or build + cache) the resident device buffer for an ALREADY-f32
    /// weight slice (the T5-XXL path pre-dequantizes its Q8 blocks to f32 host
    /// buffers). Keyed by (host_ptr, elem_len). Uploaded once, reused per call.
    fn resident_weight_f32(
        &mut self,
        w: &[f32],
        rows: usize,
        cols: usize,
    ) -> Result<Arc<CudaSlice<f32>>, String> {
        debug_assert_eq!(w.len(), rows * cols);
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.f32_weights.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = (rows * cols * 4) as u64;
        // Evict oldest (FIFO) until this upload fits the budget. Entries whose
        // Arc is held by an in-flight GEMM survive logically (the device buffer
        // is freed only when its last Arc drops), but in this single-threaded
        // mutex region nothing else holds them, so eviction reclaims VRAM.
        while self.f32_bytes + bytes > self.f32_budget_bytes {
            let Some(old_key) = self.f32_order.pop_front() else {
                break;
            };
            if let Some(old) = self.f32_weights.remove(&old_key) {
                self.f32_bytes = self.f32_bytes.saturating_sub((old.len() * 4) as u64);
                drop(old); // frees the device buffer (last Arc) -> VRAM reclaimed
            }
        }
        let t_up = Instant::now();
        let dev = self
            .device
            .htod_sync_copy(w)
            .map_err(|e| format!("[cuda] f32 weight htod_sync_copy failed: {e}"))?;
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        if n_up <= 8 || n_up % 64 == 0 {
            eprintln!(
                "[cuda] f32 weight upload #{n_up} MISS [{rows}x{cols}] {:.1} MB \
                 htod={up_ms:.1}ms (f32 resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                self.f32_bytes as f64 / 1e9,
                self.f32_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.f32_weights.insert(key, arc.clone());
        self.f32_order.push_back(key);
        self.f32_bytes += bytes;
        Ok(arc)
    }

    /// Borrow a reusable device input buffer holding `xs` (copied up). Grows the
    /// pool if needed; never allocates when the existing buffer already fits.
    fn upload_xs(&mut self, xs: &[f32]) -> Result<(), String> {
        let need = xs.len();
        let grow = match &self.xs_pool {
            Some(buf) => buf.len() < need,
            None => true,
        };
        if grow {
            // Round up so the pool stabilizes after the first few sizes.
            let cap = need.next_power_of_two().max(4096);
            self.xs_pool = Some(
                self.device
                    .alloc_zeros::<f32>(cap)
                    .map_err(|e| format!("[cuda] xs pool alloc failed: {e}"))?,
            );
        }
        let pool = self.xs_pool.as_mut().unwrap();
        // Copy host xs into the front of the resident pool buffer (no malloc).
        self.device
            .htod_sync_copy_into(xs, &mut pool.slice_mut(0..need))
            .map_err(|e| format!("[cuda] xs htod_sync_copy_into failed: {e}"))?;
        Ok(())
    }

    /// Ensure the output pool holds at least `need` f32; grows if needed.
    fn ensure_out(&mut self, need: usize) -> Result<(), String> {
        let grow = match &self.out_pool {
            Some(buf) => buf.len() < need,
            None => true,
        };
        if grow {
            let cap = need.next_power_of_two().max(4096);
            self.out_pool = Some(
                self.device
                    .alloc_zeros::<f32>(cap)
                    .map_err(|e| format!("[cuda] out pool alloc failed: {e}"))?,
            );
        }
        Ok(())
    }

    /// out[t*n + r] = sum_c W[r,c] * xs[t*d + c]  (row-major everywhere).
    /// W is [n x d] (Q8 weight, dequantized + resident), xs is [tokens x d],
    /// out is [tokens x n]. Computed as out = xs · Wᵀ on the GPU via cuBLAS.
    /// Uses POOLED device buffers for xs/out so there is NO per-call cudaMalloc.
    fn gemm_rows_shared(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w: &[u8],
        n: usize,
        d: usize,
        tokens: usize,
    ) -> Result<(), String> {
        // FLUX_GPU_F32_ACT=1 (the gemma4 PRECISION fix): keep ACTIVATIONS in f32
        // (no f16-input rounding on the contraction) by running the all-f32 cuBLAS
        // path with the weight dequantized to an f32 resident slab. cublasGemmEx
        // requires Atype==Btype, so f32 activations ⇒ f32 weight
        // (Atype=Btype=Ctype=CUDA_R_32F, CUBLAS_COMPUTE_32F). Overrides the
        // f16/bf16 branches below; default OFF + d-gated (FLUX_GPU_F32_ACT_MIN_D).
        if gpu_f32_act_applies(d) {
            let w_dev = self.resident_weight_dequant(w, n, d, dequantize_q8_0_row, "Q8")?;
            self.gemm_with_weight(out, xs, w_dev.as_ref(), n, d, tokens)?;
            gpucheck_q8(out, xs, w, n, d, tokens);
            return Ok(());
        }
        // f16 residency opt-in (FLUX_GPU_WEIGHT_DTYPE=f16) — used by 7-8B LLM
        // services whose f32 dequant exceeds the L4. FLUX renders stay on the
        // default f32 path (bit-comparable to CPU under PEDANTIC math).
        if weight_dtype_is_bf16() {
            let w_dev = self.resident_weight_dequant_bf16(w, n, d, dequantize_q8_0_row, "Q8")?;
            return self.gemm_with_weight_bf16(out, xs, w_dev.as_ref(), n, d, tokens);
        }
        if weight_dtype_is_f16() {
            if gpu_slab_enabled() {
                let w_ptr =
                    self.resident_weight_slab_f16(w, n, d, dequantize_q8_0_row, "Q8")?;
                return self.gemm_with_weight_f16_ptr(out, xs, w_ptr, n, d, tokens);
            }
            let w_dev = self.resident_weight_dequant_f16(w, n, d, dequantize_q8_0_row, "Q8")?;
            return self.gemm_with_weight_f16(out, xs, w_dev.as_ref(), n, d, tokens);
        }
        let w_dev = self.resident_weight(w, n, d)?;
        self.gemm_with_weight(out, xs, w_dev.as_ref(), n, d, tokens)?;
        // REAL-DATA correctness probe (FLUX_GPUCHECK=1): recompute this Q8 GEMM on
        // the CPU with the EXACT same inputs and report cos-sim + max-abs-err vs
        // the GPU result. This is the definitive "GPU == CPU on real render
        // activations" diff (the synthetic gpu_selftest only samples a few
        // outputs). Logged for the first few ops of each phase to bound cost.
        gpucheck_q8(out, xs, w, n, d, tokens);
        Ok(())
    }

    /// f32-weight variant: identical GEMM, but the weight is already an f32 host
    /// slice (the T5 path). out[t*n + r] = Σ_c W[r,c]·xs[t*d + c].
    fn gemm_rows_shared_f32(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w: &[f32],
        n: usize,
        d: usize,
        tokens: usize,
    ) -> Result<(), String> {
        // High-precision (f64) opt-in for hypersensitive decoders (mamba-2.8b):
        // widen weight+xs to f64 and run cublasDgemm so the accumulation ORDER no
        // longer perturbs the argmax. Default OFF → the fast f32 sgemm path below.
        if gpu_f32_fp64() {
            let w_dev = self.resident_weight_f64(w, n, d)?;
            self.gemm_with_weight_f64(out, xs, w_dev.as_ref(), n, d, tokens)?;
            gpucheck_f32(out, xs, w, n, d, tokens);
            if gpufix_applies(d) || gpufix_f32_only() {
                force_cpu_gemm_f32(out, xs, w, n, d, tokens);
            }
            return Ok(());
        }
        let w_dev = self.resident_weight_f32(w, n, d)?;
        self.gemm_with_weight(out, xs, w_dev.as_ref(), n, d, tokens)?;
        gpucheck_f32(out, xs, w, n, d, tokens);
        // Exact-CPU override (default OFF). `FLUX_GPUFIX=1` (all paths, d-gated) or
        // `FLUX_GPUFIX_F32=1` (this path only) overwrites the GPU result with the
        // f64-accumulate CPU GEMM — the known-correct oracle. Previously this path
        // had NO override (only the observer above), so FLUX_GPUFIX silently
        // skipped it; that left the pure-f32 GEMM un-bisectable on the L4.
        if gpufix_applies(d) || gpufix_f32_only() {
            force_cpu_gemm_f32(out, xs, w, n, d, tokens);
        }
        Ok(())
    }

    /// Get (or build + cache) the resident f32 device buffer for a QUANTIZED
    /// weight in any row-dequantizable format (Q4K/Q6K — the formats the LLM
    /// .knot files actually ship). Identical lifecycle to `resident_weight`
    /// (the Q8 path): host-dequant once (rayon over rows), upload once, FIFO
    /// eviction under the shared `q8_budget_bytes`. Cache keys are
    /// (host_ptr, byte_len), so distinct weights never collide across formats.
    fn resident_weight_dequant(
        &mut self,
        w: &[u8],
        rows: usize,
        cols: usize,
        dequant_row: fn(&mut [f32], &[u8], usize, usize),
        label: &str,
    ) -> Result<Arc<CudaSlice<f32>>, String> {
        if no_weight_cache() {
            // Transient: dequant + upload fresh from the CURRENT bytes, never cache.
            use gnosis_frf::prelude::*;
            let mut host = vec![0.0f32; rows * cols];
            host.par_chunks_mut(cols)
                .enumerate()
                .for_each(|(r, dst)| dequant_row(dst, w, r, cols));
            let dev = self
                .device
                .htod_sync_copy(&host)
                .map_err(|e| format!("[cuda] transient f32 weight htod failed ({label} {rows}x{cols}): {e}"))?;
            return Ok(Arc::new(dev));
        }
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.weights.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = (rows * cols * 4) as u64;
        // Liquid-memory fallback (see resident_weight_dequant_f16): saturation →
        // CPU instead of evict-thrash. f32-resident LLM path (Q4K/Q6K → f32).
        if saturation_falls_back_to_cpu() && self.q8_bytes + bytes > self.q8_budget_bytes {
            return Err(VRAM_SATURATED.to_string());
        }
        while self.q8_bytes + bytes > self.q8_budget_bytes {
            let Some(old_key) = self.q8_order.pop_front() else {
                break;
            };
            if let Some(old) = self.weights.remove(&old_key) {
                self.q8_bytes = self.q8_bytes.saturating_sub((old.len() * 4) as u64);
                drop(old); // frees the device buffer (last Arc) -> VRAM reclaimed
            }
        }
        let t_deq = Instant::now();
        use gnosis_frf::prelude::*;
        let mut host = vec![0.0f32; rows * cols];
        host.par_chunks_mut(cols).enumerate().for_each(|(r, dst)| {
            dequant_row(dst, w, r, cols);
        });
        let deq_ms = t_deq.elapsed().as_secs_f64() * 1e3;
        let t_up = Instant::now();
        let dev = self
            .device
            .htod_sync_copy(&host)
            .map_err(|e| format!("[cuda] weight htod_sync_copy failed ({label} {rows}x{cols}, {:.0} MB, resident {:.2} GB / budget {:.1} GB): {e}",
                bytes as f64 / 1e6,
                self.q8_bytes as f64 / 1e9,
                self.q8_budget_bytes as f64 / 1e9))?;
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        if should_log_phase(phase_up, cuda_upload_log_every()) {
            eprintln!(
                "[cuda] {label} weight upload #{n_up} (phase #{phase_up}) MISS [{rows}x{cols}] {:.1} MB \
                 dequant={deq_ms:.1}ms htod={up_ms:.1}ms (resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                (self.q8_bytes + bytes) as f64 / 1e9,
                self.q8_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.weights.insert(key, arc.clone());
        self.q8_order.push_back(key);
        self.q8_bytes += bytes;
        Ok(arc)
    }

    /// Quantized-LLM variant of `gemm_rows_shared`: dequant+resident via
    /// `dequant_row`, then the same pooled cuBLAS GEMM. The CPU kernel stays
    /// the correctness source of truth; callers fall back to it on any error.
    /// Under FLUX_GPU_WEIGHT_DTYPE=f16 the weight lives in VRAM as f16 and the
    /// GEMM is GemmEx 16F-storage/32F-accumulate (the 7-8B-fits-the-L4 path).
    #[allow(clippy::too_many_arguments)]
    fn gemm_rows_shared_quant(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w: &[u8],
        n: usize,
        d: usize,
        tokens: usize,
        dequant_row: fn(&mut [f32], &[u8], usize, usize),
        label: &str,
    ) -> Result<(), String> {
        // MESH_GPU_Q4K=1 (additive, DEFAULT OFF): RAW-RESIDENCY in-kernel K-quant
        // dequant-GEMV for single-token DECODE — tried FIRST, BEFORE every f16/f32
        // dequant+resident path below. WHY: a Q4_K_M knot (e.g. gemma4-12b) that
        // dequantizes to an f16 working set is ~4× its on-disk size (7 GB → ~19 GB)
        // and OOMs/thrashes the 24 GB L4 (the lm_head spills / weights re-upload per
        // op → mesh "socket hang up"). The kernels here keep the weights RAW resident
        // (Q4_K body ~4–5 GB + Q6_K lm_head/embed ~1.5 GB ≈ 6 GB total, sized by
        // MESH_GPU_Q4K_BUDGET_GB) in `self.q4kraw_*`, NOT the f16 cache, and
        // dequantize in-flight with f32 accumulate. Decode-only: `tokens == 1` (the
        // GEMV shape [n×d]·[1×d]); batched prefill (tokens > 1) stays on the existing
        // path unchanged. Dispatch by the tensor's actual quant via `label` ("Q4K" /
        // "Q6K") — Q4_K_M is MIXED (most tensors Q4_K, lm_head/embed are Q6_K) so each
        // tensor must hit its matching kernel. Mirrors `mat_vec_q8_0`'s
        // try-kernel-FIRST discipline. We call the kernel METHODS directly on `self`
        // (we already hold the GPU guard — the standalone `try_*_kernel` entries would
        // re-lock and deadlock). On ANY miss (flag off, cubin absent, wrong shape,
        // launch/dtoh error) fall THROUGH unchanged to the f16/f32 path → CPU; CPU
        // stays the source of truth (the kernel's own `gpucheck_quant` guards it).
        if tokens == 1 && gpu_q4k_enabled() && d != 0 && d % 256 == 0 {
            // `out` may be batch-capacity-sized (> n); the kernel dtoh needs an
            // exact-n dst, and the f16/f32 fallback below already writes out[..n].
            let n_rows = n;
            match label {
                "Q4K" if q4k_kernel_available() && w.len() >= n_rows * (d / 256) * 144 => {
                    if self.q4k_gemv_kernel(&mut out[..n_rows], xs, w, n_rows, d).is_ok() {
                        let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                        let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                        if should_log_phase(phase, cuda_op_log_every()) {
                            eprintln!(
                                "[cuda] Q4K-KERNEL(decode) gemm #{nops} (phase #{phase}) [{n_rows}x{d}]·[1x{d}] -> [1x{n_rows}] (raw-resident, no f16 expansion)"
                            );
                        }
                        return Ok(());
                    }
                    // miss → fall through to the existing f16/f32 path unchanged.
                }
                "Q6K" if q6k_kernel_available() && w.len() >= n_rows * (d / 256) * 210 => {
                    if self.q6k_gemv_kernel(&mut out[..n_rows], xs, w, n_rows, d).is_ok() {
                        let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                        let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                        if should_log_phase(phase, cuda_op_log_every()) {
                            eprintln!(
                                "[cuda] Q6K-KERNEL(decode) gemm #{nops} (phase #{phase}) [{n_rows}x{d}]·[1x{d}] -> [1x{n_rows}] (raw-resident, no f16 expansion)"
                            );
                        }
                        return Ok(());
                    }
                    // miss → fall through to the existing f16/f32 path unchanged.
                }
                _ => {}
            }
        }
        // FLUX_GPU_F32_ACT=1 (the gemma4 PRECISION fix): route this GEMM through
        // the all-f32 cuBLAS path so the ACTIVATIONS are NEVER rounded to f16
        // before the contraction (cublasGemmEx requires Atype==Btype, so f32
        // activations ⇒ f32 weight: Atype=Btype=Ctype=CUDA_R_32F,
        // CUBLAS_COMPUTE_32F). Weight resident at 4 B/elem (2× the f16 slab);
        // `gpu_f32_act_applies` (FLUX_GPU_F32_ACT_MIN_D) bounds the cost to large
        // GEMMs. Sits BEFORE the f16/bf16 branches so it wins for those models;
        // default OFF leaves mistral/gemma3 on the byte-unchanged f16 path.
        if gpu_f32_act_applies(d) {
            let w_dev = self.resident_weight_dequant(w, n, d, dequant_row, label)?;
            let r = self.gemm_with_weight(out, xs, w_dev.as_ref(), n, d, tokens);
            gpucheck_quant("f32-act", out, xs, w, n, d, tokens, dequant_row);
            if gpufix_applies(d) {
                force_cpu_gemm(out, xs, w, n, d, tokens, dequant_row);
            }
            return r;
        }
        if weight_dtype_is_bf16() {
            let w_dev = self.resident_weight_dequant_bf16(w, n, d, dequant_row, label)?;
            let r = self.gemm_with_weight_bf16(out, xs, w_dev.as_ref(), n, d, tokens);
            gpucheck_quant("bf16", out, xs, w, n, d, tokens, dequant_row);
            if gpufix_applies(d) {
                force_cpu_gemm(out, xs, w, n, d, tokens, dequant_row);
            }
            return r;
        }
        if weight_dtype_is_f16() {
            // MESH_GPU_SLAB=1: one contiguous f16 slab (no per-weight malloc
            // fragmentation, no CPU fallback). Shares the EXACT cublas body via
            // gemm_with_weight_f16_ptr; numerics identical to the per-weight f16
            // path. Same FLUX_GPUCHECK + FLUX_GPUFIX instrumentation.
            if gpu_slab_enabled() {
                let w_ptr = self.resident_weight_slab_f16(w, n, d, dequant_row, label)?;
                let r = self.gemm_with_weight_f16_ptr(out, xs, w_ptr, n, d, tokens);
                gpucheck_quant("f16-slab", out, xs, w, n, d, tokens, dequant_row);
                if gpufix_applies(d) {
                    force_cpu_gemm(out, xs, w, n, d, tokens, dequant_row);
                }
                return r;
            }
            let w_dev = self.resident_weight_dequant_f16(w, n, d, dequant_row, label)?;
            let r = self.gemm_with_weight_f16(out, xs, w_dev.as_ref(), n, d, tokens);
            gpucheck_quant("f16", out, xs, w, n, d, tokens, dequant_row);
            if gpufix_applies(d) {
                force_cpu_gemm(out, xs, w, n, d, tokens, dequant_row);
            }
            return r;
        }
        let w_dev = self.resident_weight_dequant(w, n, d, dequant_row, label)?;
        let r = self.gemm_with_weight(out, xs, w_dev.as_ref(), n, d, tokens);
        // Same instrumentation the f16 branch gets: FLUX_GPUCHECK diffs the GPU
        // f32 Sgemm against an f64-accumulate CPU recompute (this path was
        // previously UNVERIFIED in the live forward); FLUX_GPUFIX overwrites the
        // GPU output with the exact CPU GEMM so we can isolate a real GEMM bug
        // from an integration/precision-consistency one.
        gpucheck_quant("f32", out, xs, w, n, d, tokens, dequant_row);
        if gpufix_applies(d) {
            force_cpu_gemm(out, xs, w, n, d, tokens, dequant_row);
        }
        r
    }

    /// MESH_GPU_FUSE=1: ONE GEMM over a CONTIGUOUS group of projections that
    /// share the input `xs` and inner dim `d`. `out_concat` is [tokens *
    /// total_rows], laid out row-block by row-block in member order (member0's
    /// rows first, then member1's, …), EXACTLY as if each projection had been
    /// run separately and their outputs concatenated. The caller splits.
    ///
    /// Reuses the slab group-resident packer + the SAME raw-pointer cublas body
    /// (`gemm_with_weight_f16_ptr`) as the per-projection slab path, so numerics
    /// are identical — only the row count differs. Slab-only / f16-only (the
    /// caller must check the flags first). `gpucheck_quant`-validates each member
    /// sub-block so FLUX_GPUCHECK can diff the fused output against per-proj CPU.
    fn gemm_rows_shared_fused(
        &mut self,
        out_concat: &mut [f32],
        xs: &[f32],
        members: &[(&[u8], usize, usize)],
        d: usize,
        tokens: usize,
        dequant_row: fn(&mut [f32], &[u8], usize, usize),
        label: &str,
    ) -> Result<(), String> {
        let (base_ptr, total_rows) =
            self.resident_weight_slab_f16_group(members, dequant_row, label)?;
        self.gemm_with_weight_f16_ptr(out_concat, xs, base_ptr, total_rows, d, tokens)?;
        // Per-member GPU-vs-CPU diff (FLUX_GPUCHECK=1): the fused output is the
        // concatenation of the per-projection results. The GEMM lays out out as
        // out[t*total_rows + r], so a member's rows are CONTIGUOUS only when
        // tokens==1 (the decode hot path this fusion targets) — out[row_off ..
        // row_off+rows]. For tokens>1 the rows interleave across tokens, so we
        // skip the per-member slice diff there (the fused path is decode-only).
        if tokens == 1 {
            let mut row_off = 0usize;
            for &(w, rows, _c) in members.iter() {
                let sub = &out_concat[row_off..row_off + rows];
                gpucheck_quant(label, sub, xs, w, rows, d, tokens, dequant_row);
                row_off += rows;
            }
        }
        Ok(())
    }

    /// Get (or build + cache) the **f16** resident device buffer for a
    /// quantized weight. Dequant happens per-row into a thread-local f32
    /// scratch, converted straight to f16 — the full-tensor f32 never
    /// materializes on the host (a 7B lm-head row block stays ~MBs).
    fn resident_weight_dequant_f16(
        &mut self,
        w: &[u8],
        rows: usize,
        cols: usize,
        dequant_row: fn(&mut [f32], &[u8], usize, usize),
        label: &str,
    ) -> Result<Arc<CudaSlice<f16>>, String> {
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.weights_h.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = (rows * cols * 2) as u64;
        // Liquid-memory fallback: if this (not-yet-resident) weight won't fit the
        // f16 budget, don't evict+re-upload — signal the caller to run it on CPU.
        // Keeps the hot layers GPU-resident and streams overflow on CPU.
        if saturation_falls_back_to_cpu() && self.h_bytes + bytes > self.h_budget_bytes {
            return Err(VRAM_SATURATED.to_string());
        }
        while self.h_bytes + bytes > self.h_budget_bytes {
            let Some(old_key) = self.h_order.pop_front() else {
                break;
            };
            if let Some(old) = self.weights_h.remove(&old_key) {
                self.h_bytes = self.h_bytes.saturating_sub((old.len() * 2) as u64);
                drop(old); // frees the device buffer (last Arc) -> VRAM reclaimed
            }
        }
        let t_deq = Instant::now();
        use gnosis_frf::prelude::*;
        let mut host = vec![f16::ZERO; rows * cols];
        host.par_chunks_mut(cols).enumerate().for_each(|(r, dst)| {
            let mut rowf = vec![0.0f32; cols];
            dequant_row(&mut rowf, w, r, cols);
            for (o, &v) in dst.iter_mut().zip(rowf.iter()) {
                *o = f16::from_f32(v);
            }
        });
        let deq_ms = t_deq.elapsed().as_secs_f64() * 1e3;
        let t_up = Instant::now();
        let dev = self
            .device
            .htod_sync_copy(&host)
            .map_err(|e| format!("[cuda] f16 weight htod_sync_copy failed ({label} {rows}x{cols}, {:.0} MB, f16 resident {:.2} GB / budget {:.1} GB): {e}",
                bytes as f64 / 1e6,
                self.h_bytes as f64 / 1e9,
                self.h_budget_bytes as f64 / 1e9))?;
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        if should_log_phase(phase_up, cuda_upload_log_every()) {
            eprintln!(
                "[cuda] {label}->f16 weight upload #{n_up} (phase #{phase_up}) MISS [{rows}x{cols}] {:.1} MB \
                 dequant={deq_ms:.1}ms htod={up_ms:.1}ms (f16 resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                (self.h_bytes + bytes) as f64 / 1e9,
                self.h_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.weights_h.insert(key, arc.clone());
        self.h_order.push_back(key);
        self.h_bytes += bytes;
        Ok(arc)
    }

    /// MESH_GPU_SLAB=1: get (or dequant+place) the f16 weight inside the ONE
    /// contiguous slab, returning its weight device pointer (CUdeviceptr/u64) =
    /// `slab_base + offset_elems * 2` (f16 = 2 bytes). Holding the whole working
    /// set in a single allocation avoids the per-weight cudaMalloc fragmentation
    /// that capped `resident_weight_dequant_f16` at ~12 GB on the 24 GB L4.
    ///
    /// First call lazily allocs `slab_capacity_elems` f16 (`MESH_GPU_SLAB_GB`).
    /// On a miss: dequant per-row to host f16 (EXACT same pattern as
    /// `resident_weight_dequant_f16`, rayon par_chunks_mut), htod into the slab
    /// sub-range, record (off, len), bump the cursor. The slab is NEVER evicted
    /// (it holds everything); if it can't fit the next weight, return Err so the
    /// caller falls back to the per-weight cache / CPU. dtoh is unchanged.
    fn resident_weight_slab_f16(
        &mut self,
        w: &[u8],
        rows: usize,
        cols: usize,
        dequant_row: fn(&mut [f32], &[u8], usize, usize),
        label: &str,
    ) -> Result<u64, String> {
        use cudarc::driver::DevicePtr;
        let key = (weight_fingerprint(w) as usize, w.len());
        // Cache hit: pointer = slab base + recorded byte offset.
        if let Some(&(off, _len)) = self.slab_map.get(&key) {
            let base: u64 = *self.slab.as_ref().unwrap().device_ptr();
            return Ok(base + (off as u64) * 2);
        }
        let len = rows * cols;
        // Lazily allocate the single slab on first use; log its size.
        if self.slab.is_none() {
            let cap = self.slab_capacity_elems;
            let t_alloc = Instant::now();
            let s = self
                .device
                .alloc_zeros::<f16>(cap)
                .map_err(|e| format!("[cuda] slab alloc_zeros::<f16>({cap} elems / {:.1} GB) failed: {e}", (cap as f64 * 2.0) / 1e9))?;
            eprintln!(
                "[cuda] MESH_GPU_SLAB allocated {:.1} GB contiguous f16 slab ({cap} elems) in {:.0}ms",
                (cap as f64 * 2.0) / 1e9,
                t_alloc.elapsed().as_secs_f64() * 1e3,
            );
            self.slab = Some(s);
        }
        // Slab full? Bail so the caller falls back (do NOT evict the slab).
        if self.slab_used_elems + len > self.slab_capacity_elems {
            return Err(format!(
                "[cuda] slab full: need {len} elems but {} / {} used ({label} {rows}x{cols}) — increase MESH_GPU_SLAB_GB; op falls back",
                self.slab_used_elems, self.slab_capacity_elems
            ));
        }
        // Dequant per-row into host f16 — EXACT copy of resident_weight_dequant_f16.
        let t_deq = Instant::now();
        use gnosis_frf::prelude::*;
        let mut host = vec![f16::ZERO; len];
        host.par_chunks_mut(cols).enumerate().for_each(|(r, dst)| {
            let mut rowf = vec![0.0f32; cols];
            dequant_row(&mut rowf, w, r, cols);
            for (o, &v) in dst.iter_mut().zip(rowf.iter()) {
                *o = f16::from_f32(v);
            }
        });
        let deq_ms = t_deq.elapsed().as_secs_f64() * 1e3;
        let off = self.slab_used_elems;
        let t_up = Instant::now();
        {
            let slab = self.slab.as_mut().unwrap();
            self.device
                .htod_sync_copy_into(&host, &mut slab.slice_mut(off..off + len))
                .map_err(|e| format!("[cuda] slab htod_sync_copy_into failed ({label} {rows}x{cols}, off={off}, len={len}): {e}"))?;
        }
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add((len * 2) as u64, Ordering::Relaxed);
        if should_log_phase(phase_up, cuda_upload_log_every()) {
            eprintln!(
                "[cuda] {label}->slab upload #{n_up} (phase #{phase_up}) MISS [{rows}x{cols}] {:.1} MB \
                 dequant={deq_ms:.1}ms htod={up_ms:.1}ms (slab {:.2} GB / {:.1} GB)",
                (len * 2) as f64 / 1e6,
                ((off + len) as f64 * 2.0) / 1e9,
                self.slab_capacity_elems as f64 * 2.0 / 1e9,
            );
        }
        self.slab_map.insert(key, (off, len));
        self.slab_used_elems += len;
        let base: u64 = *self.slab.as_ref().unwrap().device_ptr();
        Ok(base + (off as u64) * 2)
    }

    /// MESH_GPU_FUSE=1: place a GROUP of projections (e.g. FFN gate+up, or
    /// q+k+v) CONTIGUOUSLY in the f16 slab so a single GEMM over the concatenated
    /// rows reads them as one weight. Returns (base_ptr_of_first_member,
    /// total_rows). All members MUST share the same `cols` (the inner/contraction
    /// dim `d`) — asserted.
    ///
    /// Correctness over incidental adjacency: we do NOT rely on the bump
    /// allocator happening to place gate then up back-to-back from the call site.
    /// Instead this fn keys the WHOLE group by its members' combined fingerprints
    /// and, on a miss, packs every member back-to-back in ONE pass (same per-row
    /// dequant + htod as `resident_weight_slab_f16`) into consecutive slab
    /// offsets, recording each member in `slab_map` AND the group in
    /// `slab_group_map`. A subsequent call returns the cached group base + total.
    ///
    /// Members already individually resident in the slab (from a prior
    /// non-fused call) are NOT reused in place (their offsets may be
    /// non-contiguous); the group is packed fresh once. This costs at most one
    /// extra residency of each grouped weight (a few MB), bounded because the
    /// group is itself cached after the first pack.
    fn resident_weight_slab_f16_group(
        &mut self,
        members: &[(&[u8], usize, usize)],
        dequant_row: fn(&mut [f32], &[u8], usize, usize),
        label: &str,
    ) -> Result<(u64, usize), String> {
        use cudarc::driver::DevicePtr;
        if members.is_empty() {
            return Err("[cuda] slab group: empty members".to_string());
        }
        let cols = members[0].2;
        for (i, &(_, _rows, c)) in members.iter().enumerate() {
            if c != cols {
                return Err(format!(
                    "[cuda] slab group ({label}): member {i} cols={c} != cols={cols} (all members must share inner dim d)"
                ));
            }
        }
        // Group key: fold each member's (fingerprint,len) into one stable key so a
        // repeated identical group (same weights, same order) hits the cache.
        let mut gh: u64 = 0xcbf2_9ce4_8422_2325 ^ (members.len() as u64);
        for &(w, _rows, _c) in members.iter() {
            gh = gh.wrapping_mul(0x0000_0100_0000_01b3) ^ (weight_fingerprint(w));
            gh = gh.wrapping_mul(0x0000_0100_0000_01b3) ^ (w.len() as u64);
        }
        let gkey = (gh as usize, cols);
        if let Some(&(off, total_rows)) = self.slab_group_map.get(&gkey) {
            let base: u64 = *self.slab.as_ref().unwrap().device_ptr();
            return Ok((base + (off as u64) * 2, total_rows));
        }
        let total_rows: usize = members.iter().map(|&(_, r, _)| r).sum();
        let total_len = total_rows * cols;
        // Lazily allocate the slab on first use (same as resident_weight_slab_f16).
        if self.slab.is_none() {
            let cap = self.slab_capacity_elems;
            let t_alloc = Instant::now();
            let s = self
                .device
                .alloc_zeros::<f16>(cap)
                .map_err(|e| format!("[cuda] slab alloc_zeros::<f16>({cap} elems / {:.1} GB) failed: {e}", (cap as f64 * 2.0) / 1e9))?;
            eprintln!(
                "[cuda] MESH_GPU_SLAB allocated {:.1} GB contiguous f16 slab ({cap} elems) in {:.0}ms",
                (cap as f64 * 2.0) / 1e9,
                t_alloc.elapsed().as_secs_f64() * 1e3,
            );
            self.slab = Some(s);
        }
        if self.slab_used_elems + total_len > self.slab_capacity_elems {
            return Err(format!(
                "[cuda] slab full: fused group ({label}) needs {total_len} elems but {} / {} used — increase MESH_GPU_SLAB_GB; op falls back",
                self.slab_used_elems, self.slab_capacity_elems
            ));
        }
        let group_off = self.slab_used_elems;
        // Pack each member back-to-back. Per-member offset = group_off + Σ prior
        // member elems; this is exactly the concatenated-rows layout the fused
        // GEMM expects: rows [0, m0_rows) = member0, [m0_rows, m0+m1) = member1, …
        let mut member_off = group_off;
        for &(w, rows, c) in members.iter() {
            let len = rows * c;
            let key = (weight_fingerprint(w) as usize, w.len());
            let t_deq = Instant::now();
            use gnosis_frf::prelude::*;
            let mut host = vec![f16::ZERO; len];
            host.par_chunks_mut(c).enumerate().for_each(|(r, dst)| {
                let mut rowf = vec![0.0f32; c];
                dequant_row(&mut rowf, w, r, c);
                for (o, &v) in dst.iter_mut().zip(rowf.iter()) {
                    *o = f16::from_f32(v);
                }
            });
            let deq_ms = t_deq.elapsed().as_secs_f64() * 1e3;
            let t_up = Instant::now();
            {
                let slab = self.slab.as_mut().unwrap();
                self.device
                    .htod_sync_copy_into(&host, &mut slab.slice_mut(member_off..member_off + len))
                    .map_err(|e| format!("[cuda] slab group htod_sync_copy_into failed ({label} {rows}x{c}, off={member_off}, len={len}): {e}"))?;
            }
            let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
            let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
            WEIGHT_BYTES_UP.fetch_add((len * 2) as u64, Ordering::Relaxed);
            if should_log_phase(phase_up, cuda_upload_log_every()) {
                eprintln!(
                    "[cuda] {label}->slab-fused upload #{n_up} (phase #{phase_up}) MISS [{rows}x{c}] {:.1} MB \
                     dequant={deq_ms:.1}ms htod={up_ms:.1}ms (slab {:.2} GB / {:.1} GB)",
                    (len * 2) as f64 / 1e6,
                    ((member_off + len) as f64 * 2.0) / 1e9,
                    self.slab_capacity_elems as f64 * 2.0 / 1e9,
                );
            }
            // Record this member individually too (cheap; lets a later per-proj
            // slab call hit), but the group entry is the authoritative one.
            self.slab_map.entry(key).or_insert((member_off, len));
            member_off += len;
        }
        self.slab_used_elems += total_len;
        self.slab_group_map.insert(gkey, (group_off, total_rows));
        let base: u64 = *self.slab.as_ref().unwrap().device_ptr();
        Ok((base + (group_off as u64) * 2, total_rows))
    }

    /// GemmEx 16F-storage/32F-accumulate against an f16-resident weight.
    /// Activations are converted f32->f16 on upload; the (small) f16 output
    /// is converted back to f32 on readback. Mirrors `gemm_with_weight`'s
    /// col-major mapping: out[t*n + r] = Σ_c W[r,c]·xs[t*d + c].
    fn gemm_with_weight_f16(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w_dev: &CudaSlice<f16>,
        n: usize,
        d: usize,
        tokens: usize,
    ) -> Result<(), String> {
        // The weight device pointer is a raw CUdeviceptr (u64); the cublas call
        // takes it as `*const c_void` (see the slab path), so this fn and the
        // slab fn share ONE cublas body. Existing (non-slab) behavior unchanged.
        use cudarc::driver::DevicePtr;
        let w_ptr: u64 = *w_dev.device_ptr();
        self.gemm_with_weight_f16_ptr(out, xs, w_ptr, n, d, tokens)
    }

    /// Shared cublasGemmEx 16F-storage/32F-accumulate body taking a RAW weight
    /// device pointer (CUdeviceptr/u64) instead of a typed `CudaSlice<f16>`.
    /// Used by BOTH the per-weight f16 cache path (`gemm_with_weight_f16`) and
    /// the contiguous-slab path (`MESH_GPU_SLAB=1`), where the weight pointer is
    /// `slab_base + offset_elems*2`. Numerics are identical: same GemmEx 16F
    /// inputs, CUDA_R_32F output, CUBLAS_COMPUTE_32F accumulate.
    fn gemm_with_weight_f16_ptr(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w_ptr: u64,
        n: usize,
        d: usize,
        tokens: usize,
    ) -> Result<(), String> {
        // Upload xs as f16 into the pooled buffer.
        let xs_h: Vec<f16> = xs.iter().map(|&v| f16::from_f32(v)).collect();
        let need_xs = xs_h.len();
        let grow_xs = match &self.xs_pool_h {
            Some(buf) => buf.len() < need_xs,
            None => true,
        };
        if grow_xs {
            let cap = need_xs.next_power_of_two().max(4096);
            self.xs_pool_h = Some(
                self.device
                    .alloc_zeros::<f16>(cap)
                    .map_err(|e| format!("[cuda] f16 xs pool alloc failed: {e}"))?,
            );
        }
        {
            let pool = self.xs_pool_h.as_mut().unwrap();
            self.device
                .htod_sync_copy_into(&xs_h, &mut pool.slice_mut(0..need_xs))
                .map_err(|e| format!("[cuda] f16 xs htod failed: {e}"))?;
        }
        // Ensure the f16 out pool.
        let need_out = tokens * n;
        let grow_out = match &self.out_pool_h {
            Some(buf) => buf.len() < need_out,
            None => true,
        };
        if grow_out {
            let cap = need_out.next_power_of_two().max(4096);
            self.out_pool_h = Some(
                self.device
                    .alloc_zeros::<f16>(cap)
                    .map_err(|e| format!("[cuda] f16 out pool alloc failed: {e}"))?,
            );
        }
        // f32-OUTPUT mixed precision (the gemma4 fix): keep f16 weights+xs (VRAM
        // savings + 32F accumulate), but write the GEMM result as f32 via
        // cublasGemmEx Ctype=CUDA_R_32F — DO NOT round the output to f16. The
        // f16 output rounding (~0.27 abs-err on the FFN down-proj) accumulated
        // over gemma4's 48 layers into a directional error at the hypersensitive
        // readout. Reuses the f32 `out_pool`. Col-major mapping identical to
        // gemm_with_weight: Oc(n×tokens) = op(Wc)=T(n×d) · op(Xc)=N(d×tokens).
        use cudarc::driver::{DevicePtr, DevicePtrMut};
        self.ensure_out(tokens * n)?;
        let alpha = 1.0f32;
        let beta = 0.0f32;
        let w_ptr = w_ptr as *const std::ffi::c_void;
        let x_ptr =
            *self.xs_pool_h.as_ref().unwrap().device_ptr() as *const std::ffi::c_void;
        let c_ptr =
            *self.out_pool.as_mut().unwrap().device_ptr_mut() as *mut std::ffi::c_void;
        let handle = *self.blas.handle();
        // SAFETY: handle/stream are the device's; shapes/leading-dims match the
        // allocations above (W=[n*d] f16, xs=[tokens*d] f16, out=[tokens*n] f32).
        let status = unsafe {
            cudarc::cublas::sys::lib().cublasGemmEx(
                handle,
                cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_T,
                cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_N,
                n as i32,
                tokens as i32,
                d as i32,
                &alpha as *const f32 as *const std::ffi::c_void,
                w_ptr,
                cudarc::cublas::sys::cudaDataType_t::CUDA_R_16F,
                d as i32,
                x_ptr,
                cudarc::cublas::sys::cudaDataType_t::CUDA_R_16F,
                d as i32,
                &beta as *const f32 as *const std::ffi::c_void,
                c_ptr,
                cudarc::cublas::sys::cudaDataType_t::CUDA_R_32F,
                n as i32,
                cudarc::cublas::sys::cublasComputeType_t::CUBLAS_COMPUTE_32F,
                cudarc::cublas::sys::cublasGemmAlgo_t::CUBLAS_GEMM_DEFAULT,
            )
        };
        if status != cudarc::cublas::sys::cublasStatus_t::CUBLAS_STATUS_SUCCESS {
            return Err(format!("[cuda] f16->f32 cublasGemmEx failed: {status:?}"));
        }
        let out_view = self.out_pool.as_ref().unwrap().slice(0..tokens * n);
        self.device
            .dtoh_sync_copy_into(&out_view, out)
            .map_err(|e| format!("[cuda] f16->f32 out dtoh failed: {e}"))?;
        Ok(())
    }

    /// bf16 analogue of `resident_weight_dequant_f16`: dequant per row into f32
    /// scratch, convert straight to bf16, upload, cache in `weights_b`. Shares
    /// the f16 budget accounting (h_bytes/h_order/h_budget) — only one half
    /// dtype is active per process, so the eviction below only ever touches the
    /// populated map.
    fn resident_weight_dequant_bf16(
        &mut self,
        w: &[u8],
        rows: usize,
        cols: usize,
        dequant_row: fn(&mut [f32], &[u8], usize, usize),
        label: &str,
    ) -> Result<Arc<CudaSlice<bf16>>, String> {
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.weights_b.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = (rows * cols * 2) as u64;
        if saturation_falls_back_to_cpu() && self.h_bytes + bytes > self.h_budget_bytes {
            return Err(VRAM_SATURATED.to_string());
        }
        while self.h_bytes + bytes > self.h_budget_bytes {
            let Some(old_key) = self.h_order.pop_front() else {
                break;
            };
            if let Some(old) = self.weights_b.remove(&old_key) {
                self.h_bytes = self.h_bytes.saturating_sub((old.len() * 2) as u64);
                drop(old);
            }
        }
        let t_deq = Instant::now();
        use gnosis_frf::prelude::*;
        let mut host = vec![bf16::ZERO; rows * cols];
        host.par_chunks_mut(cols).enumerate().for_each(|(r, dst)| {
            let mut rowf = vec![0.0f32; cols];
            dequant_row(&mut rowf, w, r, cols);
            for (o, &v) in dst.iter_mut().zip(rowf.iter()) {
                *o = bf16::from_f32(v);
            }
        });
        let deq_ms = t_deq.elapsed().as_secs_f64() * 1e3;
        let t_up = Instant::now();
        let dev = self
            .device
            .htod_sync_copy(&host)
            .map_err(|e| format!("[cuda] bf16 weight htod_sync_copy failed ({label} {rows}x{cols}, {:.0} MB, bf16 resident {:.2} GB / budget {:.1} GB): {e}",
                bytes as f64 / 1e6,
                self.h_bytes as f64 / 1e9,
                self.h_budget_bytes as f64 / 1e9))?;
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        if should_log_phase(phase_up, cuda_upload_log_every()) {
            eprintln!(
                "[cuda] {label}->bf16 weight upload #{n_up} (phase #{phase_up}) MISS [{rows}x{cols}] {:.1} MB \
                 dequant={deq_ms:.1}ms htod={up_ms:.1}ms (bf16 resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                (self.h_bytes + bytes) as f64 / 1e9,
                self.h_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.weights_b.insert(key, arc.clone());
        self.h_order.push_back(key);
        self.h_bytes += bytes;
        Ok(arc)
    }

    /// bf16 analogue of `gemm_with_weight_f16`: GemmEx 16BF storage / 32F
    /// accumulate. Identical col-major mapping; only the storage dtype differs
    /// (bf16's 8-bit exponent avoids the f16 overflow that garbles gemma4).
    fn gemm_with_weight_bf16(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w_dev: &CudaSlice<bf16>,
        n: usize,
        d: usize,
        tokens: usize,
    ) -> Result<(), String> {
        let xs_h: Vec<bf16> = xs.iter().map(|&v| bf16::from_f32(v)).collect();
        let need_xs = xs_h.len();
        let grow_xs = match &self.xs_pool_b {
            Some(buf) => buf.len() < need_xs,
            None => true,
        };
        if grow_xs {
            let cap = need_xs.next_power_of_two().max(4096);
            self.xs_pool_b = Some(
                self.device
                    .alloc_zeros::<bf16>(cap)
                    .map_err(|e| format!("[cuda] bf16 xs pool alloc failed: {e}"))?,
            );
        }
        {
            let pool = self.xs_pool_b.as_mut().unwrap();
            self.device
                .htod_sync_copy_into(&xs_h, &mut pool.slice_mut(0..need_xs))
                .map_err(|e| format!("[cuda] bf16 xs htod failed: {e}"))?;
        }
        let need_out = tokens * n;
        let grow_out = match &self.out_pool_b {
            Some(buf) => buf.len() < need_out,
            None => true,
        };
        if grow_out {
            let cap = need_out.next_power_of_two().max(4096);
            self.out_pool_b = Some(
                self.device
                    .alloc_zeros::<bf16>(cap)
                    .map_err(|e| format!("[cuda] bf16 out pool alloc failed: {e}"))?,
            );
        }
        let cfg = GemmConfig {
            transa: cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_T,
            transb: cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_N,
            m: n as i32,
            n: tokens as i32,
            k: d as i32,
            alpha: bf16::from_f32(1.0),
            lda: d as i32,
            ldb: d as i32,
            beta: bf16::ZERO,
            ldc: n as i32,
        };
        let xs_pool = self.xs_pool_b.as_ref().unwrap();
        let xs_view = xs_pool.slice(0..tokens * d);
        let out_pool = self.out_pool_b.as_mut().unwrap();
        let mut out_view = out_pool.slice_mut(0..tokens * n);
        // SAFETY: shapes/leading-dims match the allocations above; the handle's
        // stream == the device stream, so the dtoh below sees the GEMM result.
        unsafe {
            self.blas
                .gemm(cfg, w_dev, &xs_view, &mut out_view)
                .map_err(|e| format!("[cuda] bf16 gemm_ex failed: {e}"))?;
        }
        let mut out_h = vec![bf16::ZERO; tokens * n];
        self.device
            .dtoh_sync_copy_into(&out_view, &mut out_h)
            .map_err(|e| format!("[cuda] bf16 out dtoh failed: {e}"))?;
        for (o, &v) in out.iter_mut().zip(out_h.iter()) {
            *o = v.to_f32();
        }
        Ok(())
    }

    /// Core GEMM against an already-resident device weight buffer (row-major
    /// [n x d]). Uploads `xs` into the pool, runs cuBLAS, copies `out` back.
    fn gemm_with_weight(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w_dev: &CudaSlice<f32>,
        n: usize,
        d: usize,
        tokens: usize,
    ) -> Result<(), String> {
        self.upload_xs(xs)?;
        self.ensure_out(tokens * n)?;

        // We want row-major C[tokens x n] = A[tokens x d] · Bᵀ where
        // A = xs (row-major [tokens x d]) and B = W (row-major [n x d], so Bᵀ is
        // [d x n]). cuBLAS is column-major. A row-major [p x q] matrix M is the
        // same bytes as a column-major [q x p] matrix Mᶜ = Mᵀ.
        //
        // Let, in column-major terms:
        //   Wc  = W  viewed col-major = [d x n]   (Wc = Wᵀ_rowmajor's transpose)
        //   Xc  = xs viewed col-major = [d x tokens]
        //   Oc  = out viewed col-major = [n x tokens]
        // We need row-major out = xs · Wᵀ, i.e. out[t,r] = Σ_c xs[t,c] W[r,c].
        // In col-major that is Oc[r,t] = Σ_c Wc[c,r] · Xc[c,t]
        //                              = Σ_c (Wcᵀ)[r,c] · Xc[c,t]
        // => Oc (n x tokens) = op(Wc)=T (n x d) · op(Xc)=N (d x tokens).
        // So: gemm(transa = T, transb = N, m = n, n = tokens, k = d,
        //          A = Wc [lda = d], B = Xc [ldb = d], C = Oc [ldc = n]).
        let cfg = GemmConfig {
            transa: cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_T,
            transb: cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_N,
            m: n as i32,
            n: tokens as i32,
            k: d as i32,
            alpha: 1.0f32,
            lda: d as i32,
            ldb: d as i32,
            beta: 0.0f32,
            ldc: n as i32,
        };
        let xs_pool = self.xs_pool.as_ref().unwrap();
        let xs_view = xs_pool.slice(0..tokens * d);
        let out_pool = self.out_pool.as_mut().unwrap();
        let mut out_view = out_pool.slice_mut(0..tokens * n);
        // SAFETY: shapes/leading-dims are consistent with the allocations above
        // (W = [n*d], xs_view = [tokens*d], out_view = [tokens*n]); cuBLAS
        // reads/writes within those bounds. The handle's stream == the device
        // stream, so the dtoh below sees the completed GEMM.
        unsafe {
            self.blas
                .gemm(cfg, w_dev, &xs_view, &mut out_view)
                .map_err(|e| format!("[cuda] sgemm failed: {e}"))?;
        }
        // CudaViewMut implements DevicePtr, so it is a valid dtoh source.
        self.device
            .dtoh_sync_copy_into(&out_view, out)
            .map_err(|e| format!("[cuda] out dtoh failed: {e}"))?;
        Ok(())
    }

    // ---- MESH_GPU_F32_FP64=1: double-precision GEMM for the pure-f32 path ----

    /// Get (or build + cache) the resident f64 device buffer for an f32 weight,
    /// widened host-side once. Mirrors `resident_weight_f32` exactly (fingerprint
    /// key, FIFO eviction) but stores f64 (8 B/elem) under `f64_budget_bytes`.
    fn resident_weight_f64(
        &mut self,
        w: &[f32],
        rows: usize,
        cols: usize,
    ) -> Result<Arc<CudaSlice<f64>>, String> {
        debug_assert_eq!(w.len(), rows * cols);
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.f64_weights.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = (rows * cols * 8) as u64;
        while self.f64_bytes + bytes > self.f64_budget_bytes {
            let Some(old_key) = self.f64_order.pop_front() else {
                break;
            };
            if let Some(old) = self.f64_weights.remove(&old_key) {
                self.f64_bytes = self.f64_bytes.saturating_sub((old.len() * 8) as u64);
                drop(old);
            }
        }
        let host: Vec<f64> = w.iter().map(|&v| v as f64).collect();
        let dev = self
            .device
            .htod_sync_copy(&host)
            .map_err(|e| format!("[cuda] f64 weight htod_sync_copy failed ({rows}x{cols}): {e}"))?;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        if n_up <= 8 || n_up % 64 == 0 {
            eprintln!(
                "[cuda] f64 weight upload #{n_up} MISS [{rows}x{cols}] {:.1} MB \
                 (f64 resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                self.f64_bytes as f64 / 1e9,
                self.f64_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.f64_weights.insert(key, arc.clone());
        self.f64_order.push_back(key);
        self.f64_bytes += bytes;
        Ok(arc)
    }

    /// Borrow the f64 xs pool holding `xs` (widened + copied up). Grows if needed.
    fn upload_xs_f64(&mut self, xs: &[f32]) -> Result<(), String> {
        let need = xs.len();
        let grow = match &self.xs_pool_d {
            Some(buf) => buf.len() < need,
            None => true,
        };
        if grow {
            let cap = need.next_power_of_two().max(4096);
            self.xs_pool_d = Some(
                self.device
                    .alloc_zeros::<f64>(cap)
                    .map_err(|e| format!("[cuda] xs f64 pool alloc failed: {e}"))?,
            );
        }
        let host: Vec<f64> = xs.iter().map(|&v| v as f64).collect();
        let pool = self.xs_pool_d.as_mut().unwrap();
        self.device
            .htod_sync_copy_into(&host, &mut pool.slice_mut(0..need))
            .map_err(|e| format!("[cuda] xs f64 htod_sync_copy_into failed: {e}"))?;
        Ok(())
    }

    /// Ensure the f64 output pool holds at least `need` f64; grows if needed.
    fn ensure_out_f64(&mut self, need: usize) -> Result<(), String> {
        let grow = match &self.out_pool_d {
            Some(buf) => buf.len() < need,
            None => true,
        };
        if grow {
            let cap = need.next_power_of_two().max(4096);
            self.out_pool_d = Some(
                self.device
                    .alloc_zeros::<f64>(cap)
                    .map_err(|e| format!("[cuda] out f64 pool alloc failed: {e}"))?,
            );
        }
        Ok(())
    }

    /// f64 (cublasDgemm) twin of `gemm_with_weight`. IDENTICAL col-major mapping
    /// (transa=T, transb=N, m=n, n=tokens, k=d, lda=ldb=d, ldc=n) — only the dtype
    /// and pools change. `w_dev` is the resident f64 weight; xs is widened here.
    fn gemm_with_weight_f64(
        &mut self,
        out: &mut [f32],
        xs: &[f32],
        w_dev: &CudaSlice<f64>,
        n: usize,
        d: usize,
        tokens: usize,
    ) -> Result<(), String> {
        self.upload_xs_f64(xs)?;
        self.ensure_out_f64(tokens * n)?;
        let cfg = GemmConfig {
            transa: cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_T,
            transb: cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_N,
            m: n as i32,
            n: tokens as i32,
            k: d as i32,
            alpha: 1.0f64,
            lda: d as i32,
            ldb: d as i32,
            beta: 0.0f64,
            ldc: n as i32,
        };
        let xs_pool = self.xs_pool_d.as_ref().unwrap();
        let xs_view = xs_pool.slice(0..tokens * d);
        let out_pool = self.out_pool_d.as_mut().unwrap();
        let mut out_view = out_pool.slice_mut(0..tokens * n);
        // SAFETY: shapes/leading-dims match the allocations (w=[n*d], xs=[tokens*d],
        // out=[tokens*n]); the handle's stream == the device stream.
        unsafe {
            self.blas
                .gemm(cfg, w_dev, &xs_view, &mut out_view)
                .map_err(|e| format!("[cuda] dgemm failed: {e}"))?;
        }
        // Read f64 device result back, narrowing to the f32 `out` buffer.
        let mut host = vec![0.0f64; tokens * n];
        self.device
            .dtoh_sync_copy_into(&out_view, &mut host)
            .map_err(|e| format!("[cuda] out f64 dtoh failed: {e}"))?;
        for (o, &h) in out.iter_mut().zip(host.iter()) {
            *o = h as f32;
        }
        Ok(())
    }

    // ---- MESH_GPU_Q8K=1: custom in-kernel Q8_0 dequant-GEMV (decode) ----

    /// Get (or upload + cache) the RAW Q8_0 weight bytes resident in VRAM. This
    /// is the whole point of the kernel path: NO host dequant, NO f16 conversion
    /// — the raw ~7.7 GB Q8 bytes go up ONCE via htod_sync_copy and the kernel
    /// dequantizes them in-flight. Keyed by content fingerprint (same key as the
    /// slab/f16 caches). FIFO-evicted under `q8raw_budget_bytes`.
    fn resident_weight_q8_raw(&mut self, w: &[u8]) -> Result<Arc<CudaSlice<u8>>, String> {
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.q8raw_weights.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = w.len() as u64;
        // Evict oldest (FIFO) until this upload fits the raw-Q8 budget. Evicted
        // blocks re-upload next pass at PCIe speed (cheap vs re-streaming).
        while self.q8raw_bytes + bytes > self.q8raw_budget_bytes {
            let Some(old_key) = self.q8raw_order.pop_front() else {
                break;
            };
            if let Some(old) = self.q8raw_weights.remove(&old_key) {
                self.q8raw_bytes = self.q8raw_bytes.saturating_sub(old.len() as u64);
                drop(old); // last Arc -> device buffer freed -> VRAM reclaimed
            }
        }
        let t_up = Instant::now();
        let dev = self
            .device
            .htod_sync_copy(w)
            .map_err(|e| format!("[cuda] raw-Q8 weight htod_sync_copy failed ({:.0} MB, raw resident {:.2} GB / budget {:.1} GB): {e}",
                bytes as f64 / 1e6,
                self.q8raw_bytes as f64 / 1e9,
                self.q8raw_budget_bytes as f64 / 1e9))?;
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        if should_log_phase(phase_up, cuda_upload_log_every()) {
            eprintln!(
                "[cuda] raw-Q8 weight upload #{n_up} (phase #{phase_up}) MISS {:.1} MB \
                 htod={up_ms:.1}ms (raw-Q8 resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                (self.q8raw_bytes + bytes) as f64 / 1e9,
                self.q8raw_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.q8raw_weights.insert(key, arc.clone());
        self.q8raw_order.push_back(key);
        self.q8raw_bytes += bytes;
        Ok(arc)
    }

    /// Load the q8_gemv PTX module into this device ONCE (idempotent guard via
    /// `q8k_ptx_loaded`). The PTX is ALREADY compiled (build.rs nvcc → embedded
    /// string); `Ptx::from_src` + `load_ptx` go through the DRIVER's
    /// cuModuleLoadData — NO runtime NVRTC (libnvrtc.so is absent on the runtime
    /// stage). Returns Err if the PTX is empty (kernel unavailable) or the load
    /// fails; callers map Err -> false (existing path).
    fn ensure_q8k_module(&mut self) -> Result<(), String> {
        if self.q8k_ptx_loaded {
            return Ok(());
        }
        if Q8_GEMV_CUBIN.is_empty() {
            return Err("[cuda] q8_gemv cubin empty — kernel unavailable (nvcc absent at build)".to_string());
        }
        // Materialize the embedded sm_89 CUBIN to a temp file and load via
        // `Ptx::from_file` (the public cudarc 0.12 constructor); load_ptx ->
        // cuModuleLoadData auto-detects cubin (native SASS, no PTX-version JIT).
        let cubin_path = std::env::temp_dir().join("q8_gemv.cubin");
        std::fs::write(&cubin_path, Q8_GEMV_CUBIN)
            .map_err(|e| format!("[cuda] q8_gemv cubin temp write failed ({}): {e}", cubin_path.display()))?;
        let cubin = cudarc::nvrtc::Ptx::from_file(&cubin_path);
        self.device
            .load_ptx(cubin, "q8_gemv_mod", &["q8_gemv", "q8_gemv_f32"])
            .map_err(|e| format!("[cuda] load_ptx(q8_gemv cubin) failed: {e}"))?;
        self.q8k_ptx_loaded = true;
        // Build-freshness marker: the embedded cubin's byte length + fnv1a hash.
        // A `.cu` edit that actually recompiled (build.rs nvcc) changes BOTH; if
        // this log shows the SAME len/hash across two builds, the cubin is STALE
        // (the edit did not reach nvcc — Docker/OUT_DIR cache) and any kernel-source
        // fix (e.g. the f64 accumulate) is NOT live. This is the decisive check for
        // "f64 changed nothing": compare this line before vs after the rebuild.
        let cubin_len = Q8_GEMV_CUBIN.len();
        let cubin_hash = {
            let mut h: u64 = 0xcbf2_9ce4_8422_2325;
            for &b in Q8_GEMV_CUBIN {
                h ^= b as u64;
                h = h.wrapping_mul(0x0000_0100_0000_01b3);
            }
            h
        };
        eprintln!(
            "[cuda] q8_gemv CUBIN module loaded (cuModuleLoadData, sm_89) — cubin {cubin_len} bytes, hash {cubin_hash:016x} (compare across builds to detect a stale/un-recompiled cubin)"
        );
        Ok(())
    }

    /// Single-token (decode) GEMV via the custom kernel: out[r] = Σ_k
    /// dequant(W[r,k]) · x[k]. `w` is the RAW Q8_0 bytes [n rows × d], `x` is the
    /// length-d activation, `out` is length n. One WARP per output row,
    /// Q8K_WARPS_PER_BLOCK warps per CUDA block, warp-shuffle reduction (no
    /// shared mem). Reuses
    /// the pooled `xs`/`out` device buffers (no per-call cudaMalloc).
    fn q8_gemv_kernel(
        &mut self,
        out: &mut [f32],
        x: &[f32],
        w: &[u8],
        n: usize,
        d: usize,
    ) -> Result<(), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_q8k_module()?;
        // Resident raw Q8 weight (uploaded once, reused per token).
        let w_dev = self.resident_weight_q8_raw(w)?;
        // Pooled activation + output device buffers (grown to fit; no malloc per
        // call). `upload_xs` copies x into xs_pool[0..d]; `ensure_out` grows
        // out_pool to >= n.
        self.upload_xs(x)?;
        self.ensure_out(n)?;
        // f32-accumulate variant (MESH_GPU_Q8K_F32=1): ~2-3× faster on the L4 (Ada
        // f64 ≈ 1/64 f32 + f32 halves register pressure → higher occupancy). Safe ONLY
        // for decoders not argmax-sensitive to summation order — parity-gated per model
        // (Codestral Mamba-2 SSD tolerates it; mamba-2.8b S6 does NOT, keep it unset there).
        static Q8K_F32: std::sync::OnceLock<bool> = std::sync::OnceLock::new();
        let fname = if *Q8K_F32.get_or_init(|| std::env::var("MESH_GPU_Q8K_F32").is_ok()) {
            "q8_gemv_f32"
        } else {
            "q8_gemv"
        };
        let func = self
            .device
            .get_func("q8_gemv_mod", fname)
            .ok_or_else(|| format!("[cuda] {fname} func missing after load_ptx"))?;
        // Warp-per-rows mapping: each warp computes Q8K_ROWS_PER_WARP rows, and a
        // CUDA block holds Q8K_WARPS_PER_BLOCK warps → rows_per_block rows.
        // grid.x = ceil(N / rows_per_block); the kernel bounds-checks each row.
        let rows_per_block = Q8K_WARPS_PER_BLOCK * Q8K_ROWS_PER_WARP;
        let grid_x = (n as u32).div_ceil(rows_per_block);
        // Stage x in shared memory (one cooperative load per block, reused by all
        // warps) when K fits the shared budget; otherwise the kernel reads x from
        // global (shared_mem_bytes=0 → empty extern shared array, untouched).
        let shared_mem_bytes = if d <= Q8K_SHARED_X_MAX_K {
            (d * std::mem::size_of::<f32>()) as u32
        } else {
            0
        };
        let cfg = LaunchConfig {
            grid_dim: (grid_x, 1, 1),
            block_dim: (Q8K_BLOCK_DIM, 1, 1),
            shared_mem_bytes,
        };
        // Borrow the pooled buffers as device views matching the kernel signature
        // (const u8* W, const f32* x, f32* out, i32 N, i32 K). DeviceRepr is impl'd
        // for &CudaSlice / &CudaView / &mut CudaViewMut and i32, so the tuple
        // launch form binds them directly (no raw c_void juggling).
        let x_view = self.xs_pool.as_ref().unwrap().slice(0..d);
        let mut out_view = self.out_pool.as_mut().unwrap().slice_mut(0..n);
        // SAFETY: grid/block/shared match the kernel's launch contract; W has
        // n*(d/32)*34 bytes, x has d elems, out has n elems — all within the
        // resident/pooled allocations. The launch is on the device's stream, so
        // the dtoh below sees the completed kernel.
        unsafe {
            func.launch(
                cfg,
                (w_dev.as_ref(), &x_view, &mut out_view, n as i32, d as i32),
            )
            .map_err(|e| format!("[cuda] q8_gemv launch failed: {e}"))?;
        }
        // CudaViewMut implements DevicePtr, so it is a valid dtoh source (same
        // pattern as gemm_with_weight) — avoids reborrowing out_pool.
        self.device
            .dtoh_sync_copy_into(&out_view, out)
            .map_err(|e| format!("[cuda] q8_gemv out dtoh failed: {e}"))?;
        // REAL-DATA correctness probe (FLUX_GPUCHECK=1): diff vs the exact CPU
        // recompute from the SAME Q8 weight (f64 accumulate). tokens=1 (decode).
        gpucheck_quant("q8-kernel", out, x, w, n, d, 1, dequantize_q8_0_row);
        // Exact-CPU override (default OFF): `FLUX_GPUFIX=1` (all paths, d-gated) or
        // `FLUX_GPUFIX_Q8K=1` (this path only) overwrites the in-kernel GEMV result
        // with the f64-accumulate CPU GEMM from the SAME Q8 bytes. Complements
        // FLUX_GPUFIX_F32 for the per-path mamba corruptor bisect (this path was
        // also override-less before).
        if gpufix_applies(d) || gpufix_q8k_only() {
            force_cpu_gemm(out, x, w, n, d, 1, dequantize_q8_0_row);
        }
        Ok(())
    }

    // ---- MESH_GPU_SCAN=1: GPU Mamba-1 S6 selective-scan (decode step) ----

    /// Load the mamba_scan cubin module into this device ONCE (idempotent guard
    /// via `mamba_scan_cubin_loaded`). EXACTLY mirrors `ensure_q8k_module`:
    /// materialize the embedded CUBIN to a temp file, load via `Ptx::from_file`
    /// -> cuModuleLoadData (native SASS, NO runtime NVRTC). Err if the cubin is
    /// empty / load fails; callers map Err -> false (CPU scan path).
    fn ensure_mamba_scan_module(&mut self) -> Result<(), String> {
        if self.mamba_scan_cubin_loaded {
            return Ok(());
        }
        if MAMBA_SCAN_CUBIN.is_empty() {
            return Err("[cuda] mamba_scan cubin empty — kernel unavailable (nvcc absent at build)"
                .to_string());
        }
        let cubin_path = std::env::temp_dir().join("mamba_scan.cubin");
        std::fs::write(&cubin_path, MAMBA_SCAN_CUBIN).map_err(|e| {
            format!("[cuda] mamba_scan cubin temp write failed ({}): {e}", cubin_path.display())
        })?;
        let cubin = cudarc::nvrtc::Ptx::from_file(&cubin_path);
        self.device
            .load_ptx(cubin, "mamba_scan_mod", &["mamba1_s6_scan"])
            .map_err(|e| format!("[cuda] load_ptx(mamba_scan cubin) failed: {e}"))?;
        self.mamba_scan_cubin_loaded = true;
        eprintln!("[cuda] mamba_scan CUBIN module loaded (cuModuleLoadData, sm_89)");
        Ok(())
    }

    /// Ensure the packed per-token upload scratch [dt | x_conv | B | C] holds at
    /// least `need` f32; grows (rounded to a power of two) if needed.
    fn ensure_mamba_scratch(&mut self, need: usize) -> Result<(), String> {
        let grow = self.mamba_scratch.as_ref().map(|b| b.len() < need).unwrap_or(true);
        if grow {
            let cap = need.next_power_of_two().max(1024);
            self.mamba_scratch = Some(
                self.device
                    .alloc_zeros::<f32>(cap)
                    .map_err(|e| format!("[cuda] mamba scratch alloc failed: {e}"))?,
            );
        }
        Ok(())
    }

    /// Ensure the per-token output pool holds at least `need` f32 (y = [d_inner]).
    fn ensure_mamba_y(&mut self, need: usize) -> Result<(), String> {
        let grow = self.mamba_y.as_ref().map(|b| b.len() < need).unwrap_or(true);
        if grow {
            let cap = need.next_power_of_two().max(1024);
            self.mamba_y = Some(
                self.device
                    .alloc_zeros::<f32>(cap)
                    .map_err(|e| format!("[cuda] mamba y pool alloc failed: {e}"))?,
            );
        }
        Ok(())
    }

    /// One decode step of the Mamba-1 S6 recurrence on the GPU. `h_host` is the
    /// CPU state for THIS layer; on the FIRST step for a layer it SEEDS the
    /// resident VRAM state (so reset/resume "just work": a zeroed or loaded host
    /// state becomes the initial resident state), and subsequent steps update the
    /// resident state in-place with NO further h transfer. `y` receives the output.
    /// dt/B/C are expected already-normed by the host for the FalconMamba branch.
    #[allow(clippy::too_many_arguments)]
    fn mamba1_s6_scan(
        &mut self,
        y: &mut [f32],
        x_conv: &[f32],
        dt: &[f32],
        b_vec: &[f32],
        c_vec: &[f32],
        a_log: &[f32],
        d_skip: &[f32],
        d_inner: usize,
        d_state: usize,
        layer_idx: usize,
        h_host: &mut [f32],
    ) -> Result<(), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_mamba_scan_module()?;

        let device = self.device.clone();
        // Weight caches (a_log / d_skip) stay CONTENT-addressed by fingerprint —
        // they are read-only and identical across sequences, so content keying is
        // correct and dedups shared weights. The RECURRENT STATE, however, is
        // per-layer-per-sequence and MUST be keyed by the layer's position, NOT by
        // a content hash of a_log: two layers whose a_log tensors happened to hash
        // alike (or a barely-trained / init-shared A_log) would otherwise SHARE one
        // VRAM `h` buffer and corrupt each other's recurrence — a state-carry bug
        // that worsens with sequence length. `state_key` keys `mamba_h` by layer.
        let layer_key = (weight_fingerprint(a_log) as usize, a_log.len());
        let hlen = d_inner * d_state;
        let state_key = (layer_idx, hlen);

        // Resident a_log (uploaded once, keyed by the layer's fingerprint).
        let a_dev = match self.mamba_alog.get(&layer_key) {
            Some(a) => a.clone(),
            None => {
                let d = Arc::new(
                    device
                        .htod_sync_copy(a_log)
                        .map_err(|e| format!("[cuda] mamba a_log htod failed: {e}"))?,
                );
                self.mamba_alog.insert(layer_key, d.clone());
                d
            }
        };
        // Resident d_skip (uploaded once, keyed by its own fingerprint).
        let dk_key = (weight_fingerprint(d_skip) as usize, d_skip.len());
        let dk_dev = match self.mamba_dskip.get(&dk_key) {
            Some(d) => d.clone(),
            None => {
                let d = Arc::new(
                    device
                        .htod_sync_copy(d_skip)
                        .map_err(|e| format!("[cuda] mamba d_skip htod failed: {e}"))?,
                );
                self.mamba_dskip.insert(dk_key, d.clone());
                d
            }
        };
        // Resident state h — seed from the host state on first use for this layer.
        if !self.mamba_h.contains_key(&state_key) {
            let hd = device
                .htod_sync_copy(&h_host[..hlen])
                .map_err(|e| format!("[cuda] mamba h seed htod failed: {e}"))?;
            self.mamba_h.insert(state_key, hd);
        }

        // Pack the per-token inputs into scratch: [dt | x_conv | B | C].
        let scratch_len = 2 * d_inner + 2 * d_state;
        self.ensure_mamba_scratch(scratch_len)?;
        self.ensure_mamba_y(d_inner)?;
        {
            let scratch = self.mamba_scratch.as_mut().unwrap();
            device
                .htod_sync_copy_into(dt, &mut scratch.slice_mut(0..d_inner))
                .map_err(|e| format!("[cuda] mamba dt htod failed: {e}"))?;
            device
                .htod_sync_copy_into(x_conv, &mut scratch.slice_mut(d_inner..2 * d_inner))
                .map_err(|e| format!("[cuda] mamba x_conv htod failed: {e}"))?;
            device
                .htod_sync_copy_into(
                    b_vec,
                    &mut scratch.slice_mut(2 * d_inner..2 * d_inner + d_state),
                )
                .map_err(|e| format!("[cuda] mamba B htod failed: {e}"))?;
            device
                .htod_sync_copy_into(
                    c_vec,
                    &mut scratch.slice_mut(2 * d_inner + d_state..2 * d_inner + 2 * d_state),
                )
                .map_err(|e| format!("[cuda] mamba C htod failed: {e}"))?;
        }

        let func = device
            .get_func("mamba_scan_mod", "mamba1_s6_scan")
            .ok_or_else(|| "[cuda] mamba1_s6_scan func missing after load_ptx".to_string())?;

        let cfg = LaunchConfig {
            grid_dim: ((d_inner as u32).div_ceil(MAMBA_SCAN_BLOCK_DIM), 1, 1),
            block_dim: (MAMBA_SCAN_BLOCK_DIM, 1, 1),
            // Shared: B and C staged once per block (2 * d_state floats).
            shared_mem_bytes: (2 * d_state * std::mem::size_of::<f32>()) as u32,
        };

        // Read-only input views (all from the immutable scratch buffer) + the
        // mutable state (mamba_h) and output (mamba_y). Disjoint fields, so the
        // read-only scratch slices and the two mutable buffers coexist.
        {
            let scratch = self.mamba_scratch.as_ref().unwrap();
            let dt_v = scratch.slice(0..d_inner);
            let x_v = scratch.slice(d_inner..2 * d_inner);
            let b_v = scratch.slice(2 * d_inner..2 * d_inner + d_state);
            let c_v = scratch.slice(2 * d_inner + d_state..2 * d_inner + 2 * d_state);
            let mut y_v = self.mamba_y.as_mut().unwrap().slice_mut(0..d_inner);
            let mut h_v = self.mamba_h.get_mut(&state_key).unwrap().slice_mut(0..hlen);
            // SAFETY: grid/block/shared match the kernel contract; all pointers are
            // within resident/pooled allocations sized above. The launch is on the
            // device stream, so the dtoh below observes the completed kernel.
            unsafe {
                func.launch(
                    cfg,
                    (
                        &x_v,
                        &dt_v,
                        &b_v,
                        &c_v,
                        a_dev.as_ref(),
                        dk_dev.as_ref(),
                        &mut h_v,
                        &mut y_v,
                        d_inner as i32,
                        d_state as i32,
                    ),
                )
                .map_err(|e| format!("[cuda] mamba1_s6_scan launch failed: {e}"))?;
            }
        }

        // Read the output back.
        let y_v = self.mamba_y.as_ref().unwrap().slice(0..d_inner);
        device
            .dtoh_sync_copy_into(&y_v, y)
            .map_err(|e| format!("[cuda] mamba y dtoh failed: {e}"))?;

        // Mirror the advanced resident state back into the HOST state so
        // `state.ssm_h` stays coherent with VRAM. The state still LIVES resident
        // (the next step's seed is skipped — see the `contains_key` guard above),
        // this is a cheap D2H (d_inner*d_state*4 ≈ 328 KB/layer, ~0.1 ms) that keeps
        // the host authoritative for the two paths that read it: (1) a mid-sequence
        // CPU-scan fallback (a transient GPU error) would otherwise resume from a
        // STALE host `h` and corrupt the output from that token on; (2) `/ssm-state/save`
        // serializes `state.ssm_h`, which was previously never updated under
        // MESH_GPU_SCAN → checkpoints saved zero state and resume produced garbage.
        let h_resident = self.mamba_h.get(&state_key).unwrap().slice(0..hlen);
        device
            .dtoh_sync_copy_into(&h_resident, &mut h_host[..hlen])
            .map_err(|e| format!("[cuda] mamba h dtoh (host mirror) failed: {e}"))?;
        Ok(())
    }

    // ---- MESH_GPU_SCAN=1: GPU Mamba-2 (SSD) selective-scan (decode step) ----

    /// Load the mamba2_ssd_scan cubin module into this device ONCE (idempotent guard
    /// via `mamba2_scan_cubin_loaded`). EXACTLY mirrors `ensure_mamba_scan_module`:
    /// materialize the embedded CUBIN to a temp file, load via `Ptx::from_file`
    /// -> cuModuleLoadData (native SASS, NO runtime NVRTC). Err if the cubin is
    /// empty / load fails; callers map Err -> false (CPU SSD-scan path).
    fn ensure_mamba2_ssd_scan_module(&mut self) -> Result<(), String> {
        if self.mamba2_scan_cubin_loaded {
            return Ok(());
        }
        if MAMBA2_SSD_SCAN_CUBIN.is_empty() {
            return Err(
                "[cuda] mamba2_ssd_scan cubin empty — kernel unavailable (nvcc absent at build)"
                    .to_string(),
            );
        }
        let cubin_path = std::env::temp_dir().join("mamba2_ssd_scan.cubin");
        std::fs::write(&cubin_path, MAMBA2_SSD_SCAN_CUBIN).map_err(|e| {
            format!("[cuda] mamba2_ssd_scan cubin temp write failed ({}): {e}", cubin_path.display())
        })?;
        let cubin = cudarc::nvrtc::Ptx::from_file(&cubin_path);
        self.device
            .load_ptx(cubin, "mamba2_ssd_scan_mod", &["mamba2_ssd_scan"])
            .map_err(|e| format!("[cuda] load_ptx(mamba2_ssd_scan cubin) failed: {e}"))?;
        self.mamba2_scan_cubin_loaded = true;
        eprintln!("[cuda] mamba2_ssd_scan CUBIN module loaded (cuModuleLoadData, sm_89)");
        Ok(())
    }

    /// One decode step of the Mamba-2 (SSD) grouped multi-head recurrence on the
    /// GPU. Mirrors `mamba1_s6_scan`: `h_host` is THIS layer's CPU state; on the
    /// FIRST step for the layer it SEEDS the resident VRAM state, subsequent steps
    /// update it in-place with NO further h transfer, and after every step the
    /// advanced resident state is MIRRORED back into `h_host` (so a mid-sequence
    /// CPU fallback / `/ssm-state/save` stays coherent). The kernel replaces ONLY
    /// the scan → raw `y`; the host precomputes `dt = softplus(dt_in + dt_bias)`
    /// BEFORE calling and applies the gated RMSNorm AFTER (needs z + norm_w).
    /// `a_log` / `d_skip` are per-head SCALARS ([num_heads]).
    #[allow(clippy::too_many_arguments)]
    /// Run the SSD scan, leaving the raw output RESIDENT in `mamba_y[0..d_inner]`
    /// (NO dtoh). Shared by both `mamba2_ssd_scan` (dtoh + host norm) and
    /// `mamba2_ssd_scan_fused` (device norm). Handles module load, resident
    /// a_log/d_skip, resident-state seed, per-token scratch pack, and the launch.
    /// Returns the layer's `state_key` so the caller can mirror `h` back to host.
    /// `head_dim` is intentionally absent (the kernel derives d_inner/num_heads).
    #[allow(clippy::too_many_arguments)]
    fn mamba2_scan_into_mamba_y(
        &mut self,
        x_conv: &[f32],
        dt: &[f32],
        b_vec: &[f32],
        c_vec: &[f32],
        a_log: &[f32],
        d_skip: &[f32],
        d_inner: usize,
        d_state: usize,
        num_heads: usize,
        n_groups: usize,
        layer_idx: usize,
        h_host: &mut [f32],
    ) -> Result<(usize, usize), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_mamba2_ssd_scan_module()?;

        let device = self.device.clone();
        // Read-only per-head weights (a_log / d_skip) stay CONTENT-addressed by
        // fingerprint (identical across sequences); the RECURRENT STATE is keyed by
        // the layer's POSITION so two layers can never share one `h` buffer even if
        // their a_log tensors hash alike (same rationale as `mamba1_s6_scan`).
        let layer_key = (weight_fingerprint(a_log) as usize, a_log.len());
        let hlen = d_inner * d_state;
        let state_key = (layer_idx, hlen);
        let bc_len = n_groups * d_state;

        // htod bucket: resident first-use seeds (a_log / d_skip / h) + the
        // per-token scratch pack upload (see `mamba_scan_prof_add`).
        let _t_htod = std::time::Instant::now();

        // Resident a_log (uploaded once, keyed by the layer's fingerprint).
        let a_dev = match self.mamba2_alog.get(&layer_key) {
            Some(a) => a.clone(),
            None => {
                let d = Arc::new(
                    device
                        .htod_sync_copy(a_log)
                        .map_err(|e| format!("[cuda] mamba2 a_log htod failed: {e}"))?,
                );
                self.mamba2_alog.insert(layer_key, d.clone());
                d
            }
        };
        // Resident d_skip (uploaded once, keyed by its own fingerprint).
        let dk_key = (weight_fingerprint(d_skip) as usize, d_skip.len());
        let dk_dev = match self.mamba2_dskip.get(&dk_key) {
            Some(d) => d.clone(),
            None => {
                let d = Arc::new(
                    device
                        .htod_sync_copy(d_skip)
                        .map_err(|e| format!("[cuda] mamba2 d_skip htod failed: {e}"))?,
                );
                self.mamba2_dskip.insert(dk_key, d.clone());
                d
            }
        };
        // Resident state h — seed from the host state on first use for this layer.
        // The GPU keeps h STATE-MAJOR (coalesced): h_gpu[n*d_inner + c]. The host
        // reference is CHANNEL-MAJOR (h_host[c*d_state + n]), so TRANSPOSE on seed.
        // This is a GPU-INTERNAL layout change (kernel + seed + mirror only); the CPU
        // path never sees it. First-use only (once per layer) → negligible vs decode.
        if !self.mamba2_h.contains_key(&state_key) {
            let mut h_seed = vec![0.0f32; hlen];
            for ch in 0..d_inner {
                let src = ch * d_state;
                for n in 0..d_state {
                    h_seed[n * d_inner + ch] = h_host[src + n];
                }
            }
            let hd = device
                .htod_sync_copy(&h_seed)
                .map_err(|e| format!("[cuda] mamba2 h seed htod failed: {e}"))?;
            self.mamba2_h.insert(state_key, hd);
        }

        // Pack the per-token inputs into scratch: [dt | x_conv | B | C]. Reuses the
        // shared generic f32 scratch/output pools (model-exclusive with the S6 path).
        let dt_off = 0;
        let x_off = num_heads;
        let b_off = num_heads + d_inner;
        let c_off = num_heads + d_inner + bc_len;
        let scratch_len = num_heads + d_inner + 2 * bc_len;
        self.ensure_mamba_scratch(scratch_len)?;
        self.ensure_mamba_y(d_inner)?;
        // Build ONE contiguous host buffer [dt | x_conv | B | C] whose layout
        // matches the scratch offsets EXACTLY (dt @ dt_off=0, x_conv @ x_off,
        // B @ b_off, C @ c_off — verified equal to the `scratch.slice(..)` views
        // the launch reads below), then ONE htod. This replaces four separate
        // `htod_sync_copy_into` calls (4 blocking syncs/layer → 1). The push order
        // MUST stay dt→x_conv→B→C to match the kernel's arg views.
        debug_assert_eq!(dt_off, 0);
        debug_assert_eq!(x_off, dt.len());
        debug_assert_eq!(b_off, x_off + x_conv.len());
        debug_assert_eq!(c_off, b_off + b_vec.len());
        debug_assert_eq!(scratch_len, c_off + c_vec.len());
        self.mamba_scratch_host.clear();
        self.mamba_scratch_host.reserve(scratch_len);
        self.mamba_scratch_host.extend_from_slice(dt); // [dt_off .. num_heads)
        self.mamba_scratch_host.extend_from_slice(x_conv); // [x_off .. +d_inner)
        self.mamba_scratch_host.extend_from_slice(b_vec); // [b_off .. +bc_len)
        self.mamba_scratch_host.extend_from_slice(c_vec); // [c_off .. +bc_len)
        {
            let scratch = self.mamba_scratch.as_mut().unwrap();
            device
                .htod_sync_copy_into(
                    &self.mamba_scratch_host,
                    &mut scratch.slice_mut(0..scratch_len),
                )
                .map_err(|e| format!("[cuda] mamba2 scratch pack htod failed: {e}"))?;
        }
        let htod_ns = _t_htod.elapsed().as_nanos();

        // launch bucket: the scan kernel launch itself.
        let _t_launch = std::time::Instant::now();
        let func = device
            .get_func("mamba2_ssd_scan_mod", "mamba2_ssd_scan")
            .ok_or_else(|| "[cuda] mamba2_ssd_scan func missing after load_ptx".to_string())?;

        let cfg = LaunchConfig {
            grid_dim: ((d_inner as u32).div_ceil(MAMBA_SCAN_BLOCK_DIM), 1, 1),
            block_dim: (MAMBA_SCAN_BLOCK_DIM, 1, 1),
            // Shared: grouped B and C staged once per block (2 * n_groups * d_state floats).
            shared_mem_bytes: (2 * bc_len * std::mem::size_of::<f32>()) as u32,
        };

        // Read-only input views (immutable scratch) + mutable state (mamba2_h) and
        // output (mamba_y). Disjoint fields, so the read-only scratch slices and the
        // two mutable buffers coexist.
        {
            let scratch = self.mamba_scratch.as_ref().unwrap();
            let dt_v = scratch.slice(dt_off..dt_off + num_heads);
            let x_v = scratch.slice(x_off..x_off + d_inner);
            let b_v = scratch.slice(b_off..b_off + bc_len);
            let c_v = scratch.slice(c_off..c_off + bc_len);
            let mut y_v = self.mamba_y.as_mut().unwrap().slice_mut(0..d_inner);
            let mut h_v = self.mamba2_h.get_mut(&state_key).unwrap().slice_mut(0..hlen);
            // SAFETY: grid/block/shared match the kernel contract; all pointers are
            // within resident/pooled allocations sized above. The launch is on the
            // device stream, so the dtoh below observes the completed kernel.
            unsafe {
                func.launch(
                    cfg,
                    (
                        &x_v,
                        &dt_v,
                        &b_v,
                        &c_v,
                        a_dev.as_ref(),
                        dk_dev.as_ref(),
                        &mut h_v,
                        &mut y_v,
                        d_inner as i32,
                        d_state as i32,
                        num_heads as i32,
                        // head_dim omitted (kernel derives d_inner/num_heads): cudarc's
                        // LaunchAsync tuple arity maxes at 12, so 8 ptrs + 4 ints is the cap.
                        n_groups as i32,
                    ),
                )
                .map_err(|e| format!("[cuda] mamba2_ssd_scan launch failed: {e}"))?;
            }
        }
        // `func.launch` is ASYNCHRONOUS: without a sync here `launch_ns` reads only the
        // launch overhead (~µs) and the real kernel-execution time smears into the NEXT
        // layer's htod sync (or the tail dtoh) — which is exactly why the S2 htod/launch/
        // tail split was uninformative. Under the profiler ONLY, synchronize the stream
        // so `launch` is the TRUE kernel wall-time — the direct reading that confirms
        // whether the 108ms is the kernel. Costs one extra sync/layer, so it is strictly
        // profiler-gated (never runs in production decode).
        if mamba_scan_prof_enabled() {
            let _ = device.synchronize();
        }
        let launch_ns = _t_launch.elapsed().as_nanos();
        // One scan completed → bump the per-token call counter. The tail (dtoh /
        // gated-norm) is added separately by the caller with bump_call=false.
        mamba_scan_prof_add(htod_ns, launch_ns, 0, true);
        Ok(state_key)
    }

    /// Mirror the advanced resident state back into the HOST state so `state.ssm_h`
    /// stays coherent with VRAM. Unlike S6 (328 KB/layer), the Mamba-2 SSD state is
    /// num_heads*head_dim*d_state = 4 MB/LAYER (256 MB/token across 64 layers), so this
    /// blocking D2H is a real decode cost. It only matters for two off-hot-path cases:
    /// a mid-sequence CPU-scan fallback and `/ssm-state/save` checkpointing. Skip it on
    /// the decode hot path by default (the resident VRAM state is authoritative and
    /// persists across tokens); set MESH_GPU_SCAN_MIRROR_HOST=1 to re-enable for
    /// checkpoint/resume. Measured ~256 MB/token of blocking PCIe traffic removed.
    fn mamba2_mirror_h_if_enabled(
        &self,
        state_key: (usize, usize),
        hlen: usize,
        d_inner: usize,
        d_state: usize,
        h_host: &mut [f32],
    ) -> Result<(), String> {
        static MIRROR: std::sync::OnceLock<bool> = std::sync::OnceLock::new();
        if *MIRROR.get_or_init(|| std::env::var("MESH_GPU_SCAN_MIRROR_HOST").is_ok()) {
            // The resident state is STATE-MAJOR (h_gpu[n*d_inner + c]); the host state
            // is CHANNEL-MAJOR (h_host[c*d_state + n]). DtoH into a staging buffer, then
            // TRANSPOSE back so the host reference stays coherent for the two off-hot-
            // path readers (mid-sequence CPU fallback, /ssm-state/save). GPU-internal
            // layout ⇒ this transpose is the exact inverse of the seed transpose.
            let h_resident = self.mamba2_h.get(&state_key).unwrap().slice(0..hlen);
            let mut h_gpu = vec![0.0f32; hlen];
            self.device
                .dtoh_sync_copy_into(&h_resident, &mut h_gpu)
                .map_err(|e| format!("[cuda] mamba2 h dtoh (host mirror) failed: {e}"))?;
            for ch in 0..d_inner {
                let dst = ch * d_state;
                for n in 0..d_state {
                    h_host[dst + n] = h_gpu[n * d_inner + ch];
                }
            }
        }
        Ok(())
    }

    /// One decode step of the Mamba-2 (SSD) grouped multi-head recurrence on the
    /// GPU. Mirrors `mamba1_s6_scan`: `h_host` is THIS layer's CPU state; on the
    /// FIRST step for the layer it SEEDS the resident VRAM state, subsequent steps
    /// update it in-place with NO further h transfer, and after every step the
    /// advanced resident state is MIRRORED back into `h_host` (so a mid-sequence
    /// CPU fallback / `/ssm-state/save` stays coherent). The kernel replaces ONLY
    /// the scan → raw `y`; the host precomputes `dt = softplus(dt_in + dt_bias)`
    /// BEFORE calling and applies the gated RMSNorm AFTER (needs z + norm_w).
    /// `a_log` / `d_skip` are per-head SCALARS ([num_heads]).
    #[allow(clippy::too_many_arguments)]
    fn mamba2_ssd_scan(
        &mut self,
        y: &mut [f32],
        x_conv: &[f32],
        dt: &[f32],    // [num_heads] = softplus(dt_in + dt_bias), host-precomputed
        b_vec: &[f32], // [n_groups * d_state]
        c_vec: &[f32], // [n_groups * d_state]
        a_log: &[f32], // [num_heads]
        d_skip: &[f32], // [num_heads]
        d_inner: usize,
        d_state: usize,
        num_heads: usize,
        _head_dim: usize,
        n_groups: usize,
        layer_idx: usize,
        h_host: &mut [f32],
    ) -> Result<(), String> {
        let device = self.device.clone();
        let state_key = self.mamba2_scan_into_mamba_y(
            x_conv, dt, b_vec, c_vec, a_log, d_skip, d_inner, d_state, num_heads, n_groups,
            layer_idx, h_host,
        )?;
        let hlen = state_key.1;

        // Read the raw scan output back to host (the non-fused path: the host then
        // applies the gated RMSNorm — the parity reference).
        // tail bucket: the y dtoh (non-fused path).
        let _t_tail = std::time::Instant::now();
        let y_v = self.mamba_y.as_ref().unwrap().slice(0..d_inner);
        device
            .dtoh_sync_copy_into(&y_v, y)
            .map_err(|e| format!("[cuda] mamba2 y dtoh failed: {e}"))?;
        mamba_scan_prof_add(0, 0, _t_tail.elapsed().as_nanos(), false);

        self.mamba2_mirror_h_if_enabled(state_key, hlen, d_inner, d_state, h_host)?;
        Ok(())
    }

    /// FUSED (MESH_GPU_SSM_FUSED=1) decode step: SSD scan → device gated-RMSNorm,
    /// leaving the NORMED y RESIDENT in `mamba2_y_normed` (NO dtoh of y). The raw
    /// scan output stays in `mamba_y`; the gated-norm kernel reads it plus `z`
    /// (uploaded to a pooled buffer this call) and the resident `norm_w`, writing
    /// the normed result to the DISTINCT `mamba2_y_normed` buffer. `out_proj` then
    /// reads x straight from there (see `q8_gemv_kernel_resident`). Semantics match
    /// the CPU gated-norm in `mamba2_ssd_step` (gate-first silu, mean(tmp²), ×gamma).
    /// Returns Ok(()) with the normed y resident; the caller does NOT touch host `y`.
    #[allow(clippy::too_many_arguments)]
    fn mamba2_ssd_scan_fused(
        &mut self,
        x_conv: &[f32],
        dt: &[f32],
        b_vec: &[f32],
        c_vec: &[f32],
        a_log: &[f32],
        d_skip: &[f32],
        z: &[f32],      // [d_inner] gate
        norm_w: &[f32], // [d_inner] gated-RMSNorm gamma
        rms_eps: f32,
        d_inner: usize,
        d_state: usize,
        num_heads: usize,
        n_groups: usize,
        layer_idx: usize,
        h_host: &mut [f32],
    ) -> Result<(), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_mamba2_gated_norm_module()?;

        // Scan → raw y resident in mamba_y (no dtoh).
        let state_key = self.mamba2_scan_into_mamba_y(
            x_conv, dt, b_vec, c_vec, a_log, d_skip, d_inner, d_state, num_heads, n_groups,
            layer_idx, h_host,
        )?;
        let hlen = state_key.1;

        // tail bucket: the device gated-norm (z upload + norm_w seed + launch) —
        // the fused path's replacement for the non-fused y dtoh.
        let _t_tail = std::time::Instant::now();
        let device = self.device.clone();

        // Resident norm_w (uploaded once, keyed by its own fingerprint like a_log).
        let nw_key = (weight_fingerprint(norm_w) as usize, norm_w.len());
        let nw_dev = match self.mamba2_normw.get(&nw_key) {
            Some(d) => d.clone(),
            None => {
                let d = Arc::new(
                    device
                        .htod_sync_copy(norm_w)
                        .map_err(|e| format!("[cuda] mamba2 norm_w htod failed: {e}"))?,
                );
                self.mamba2_normw.insert(nw_key, d.clone());
                d
            }
        };

        // Upload z into its pooled buffer (a fresh activation each token).
        {
            let need = d_inner;
            let grow = self.mamba2_z.as_ref().map(|b| b.len() < need).unwrap_or(true);
            if grow {
                let cap = need.next_power_of_two().max(4096);
                self.mamba2_z = Some(
                    device
                        .alloc_zeros::<f32>(cap)
                        .map_err(|e| format!("[cuda] mamba2 z pool alloc failed: {e}"))?,
                );
            }
            let zp = self.mamba2_z.as_mut().unwrap();
            device
                .htod_sync_copy_into(z, &mut zp.slice_mut(0..need))
                .map_err(|e| format!("[cuda] mamba2 z htod failed: {e}"))?;
        }

        // Ensure the DISTINCT resident normed-y output buffer.
        {
            let need = d_inner;
            let grow = self.mamba2_y_normed.as_ref().map(|b| b.len() < need).unwrap_or(true);
            if grow {
                let cap = need.next_power_of_two().max(4096);
                self.mamba2_y_normed = Some(
                    device
                        .alloc_zeros::<f32>(cap)
                        .map_err(|e| format!("[cuda] mamba2 y_normed pool alloc failed: {e}"))?,
                );
            }
        }

        let func = device
            .get_func("mamba2_gated_norm_mod", "mamba2_gated_norm")
            .ok_or_else(|| "[cuda] mamba2_gated_norm func missing after load_ptx".to_string())?;

        let cfg = LaunchConfig {
            // ONE block; strided sweep over d_inner. Shared = block_dim floats (reduction).
            grid_dim: (1, 1, 1),
            block_dim: (MAMBA2_GATED_NORM_BLOCK_DIM, 1, 1),
            shared_mem_bytes: (MAMBA2_GATED_NORM_BLOCK_DIM as usize * std::mem::size_of::<f32>())
                as u32,
        };

        // y_in = mamba_y (raw scan, read-only); z = mamba2_z; norm_w resident;
        // y_out = mamba2_y_normed (distinct → y_in is never clobbered).
        {
            let y_in = self.mamba_y.as_ref().unwrap().slice(0..d_inner);
            let z_v = self.mamba2_z.as_ref().unwrap().slice(0..d_inner);
            let mut y_out = self.mamba2_y_normed.as_mut().unwrap().slice_mut(0..d_inner);
            // SAFETY: single block, block_dim a power of two (tree reduce), shared sized
            // above; all pointers within resident/pooled allocations of ≥ d_inner floats.
            unsafe {
                func.launch(
                    cfg,
                    (&y_in, &z_v, nw_dev.as_ref(), &mut y_out, d_inner as i32, rms_eps),
                )
                .map_err(|e| format!("[cuda] mamba2_gated_norm launch failed: {e}"))?;
            }
        }
        mamba_scan_prof_add(0, 0, _t_tail.elapsed().as_nanos(), false);

        self.mamba2_mirror_h_if_enabled(state_key, hlen, d_inner, d_state, h_host)?;
        Ok(())
    }

    /// Load the mamba2_gated_norm cubin module into this device ONCE. Mirrors
    /// `ensure_mamba2_ssd_scan_module`. Err if the cubin is empty / load fails
    /// (callers map Err → the host gated-norm path).
    fn ensure_mamba2_gated_norm_module(&mut self) -> Result<(), String> {
        if self.mamba2_gated_norm_cubin_loaded {
            return Ok(());
        }
        if MAMBA2_GATED_NORM_CUBIN.is_empty() {
            return Err(
                "[cuda] mamba2_gated_norm cubin empty — kernel unavailable (nvcc absent at build)"
                    .to_string(),
            );
        }
        let cubin_path = std::env::temp_dir().join("mamba2_gated_norm.cubin");
        std::fs::write(&cubin_path, MAMBA2_GATED_NORM_CUBIN).map_err(|e| {
            format!("[cuda] mamba2_gated_norm cubin temp write failed ({}): {e}", cubin_path.display())
        })?;
        let cubin = cudarc::nvrtc::Ptx::from_file(&cubin_path);
        self.device
            .load_ptx(cubin, "mamba2_gated_norm_mod", &["mamba2_gated_norm"])
            .map_err(|e| format!("[cuda] load_ptx(mamba2_gated_norm cubin) failed: {e}"))?;
        self.mamba2_gated_norm_cubin_loaded = true;
        eprintln!("[cuda] mamba2_gated_norm CUBIN module loaded (cuModuleLoadData, sm_89)");
        Ok(())
    }

    /// Q8_0 GEMV that reads x from the RESIDENT `mamba2_y_normed` buffer (the fused
    /// gated-norm output) instead of `upload_xs(x)` from host — the out_proj half of
    /// the fused SSD layer. Identical to `q8_gemv_kernel` EXCEPT the x view; still
    /// dtoh's `out` (feeds the host residual + next layer's pre-norm — S1 scope).
    /// Caller MUST have just run `mamba2_ssd_scan_fused` (so `mamba2_y_normed` holds
    /// the normed y of THIS layer, ≥ d elems).
    fn q8_gemv_kernel_resident(
        &mut self,
        out: &mut [f32],
        w: &[u8],
        n: usize,
        d: usize,
    ) -> Result<(), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_q8k_module()?;
        // Resident normed-y must exist and be large enough (written by the fused
        // scan for this layer). Guard so a mis-order never reads a stale/short buffer.
        let have = self.mamba2_y_normed.as_ref().map(|b| b.len() >= d).unwrap_or(false);
        if !have {
            return Err("[cuda] q8_gemv_resident: mamba2_y_normed missing/short (fused scan not run?)".to_string());
        }
        let w_dev = self.resident_weight_q8_raw(w)?;
        self.ensure_out(n)?;
        static Q8K_F32: std::sync::OnceLock<bool> = std::sync::OnceLock::new();
        let fname = if *Q8K_F32.get_or_init(|| std::env::var("MESH_GPU_Q8K_F32").is_ok()) {
            "q8_gemv_f32"
        } else {
            "q8_gemv"
        };
        let func = self
            .device
            .get_func("q8_gemv_mod", fname)
            .ok_or_else(|| format!("[cuda] {fname} func missing after load_ptx"))?;
        let rows_per_block = Q8K_WARPS_PER_BLOCK * Q8K_ROWS_PER_WARP;
        let grid_x = (n as u32).div_ceil(rows_per_block);
        let shared_mem_bytes = if d <= Q8K_SHARED_X_MAX_K {
            (d * std::mem::size_of::<f32>()) as u32
        } else {
            0
        };
        let cfg = LaunchConfig {
            grid_dim: (grid_x, 1, 1),
            block_dim: (Q8K_BLOCK_DIM, 1, 1),
            shared_mem_bytes,
        };
        // x_view = the RESIDENT normed-y (no host upload); out_view = pooled out.
        let x_view = self.mamba2_y_normed.as_ref().unwrap().slice(0..d);
        let mut out_view = self.out_pool.as_mut().unwrap().slice_mut(0..n);
        // SAFETY: grid/block/shared match the kernel contract; x_view (≥ d) and
        // out_view (n) are within resident/pooled allocations; W has n*(d/32)*34 bytes.
        unsafe {
            func.launch(
                cfg,
                (w_dev.as_ref(), &x_view, &mut out_view, n as i32, d as i32),
            )
            .map_err(|e| format!("[cuda] q8_gemv_resident launch failed: {e}"))?;
        }
        self.device
            .dtoh_sync_copy_into(&out_view, out)
            .map_err(|e| format!("[cuda] q8_gemv_resident out dtoh failed: {e}"))?;
        Ok(())
    }

    // ---- MESH_GPU_PREFILL_ATTN=1: GPU batched prefill attention (QKᵀ→softmax→AV) ----

    /// Load the prefill_attn softmax cubin module into this device ONCE
    /// (idempotent guard via `prefill_attn_cubin_loaded`). EXACTLY mirrors
    /// `ensure_q8k_module`: materialize the embedded CUBIN to a temp file, load
    /// via `Ptx::from_file` -> cuModuleLoadData (native SASS, NO runtime NVRTC).
    /// Err if the cubin is empty / load fails; callers map Err -> false (CPU path).
    fn ensure_prefill_attn_module(&mut self) -> Result<(), String> {
        if self.prefill_attn_cubin_loaded {
            return Ok(());
        }
        if PREFILL_ATTN_CUBIN.is_empty() {
            return Err("[cuda] prefill_attn cubin empty — kernel unavailable (nvcc absent at build)".to_string());
        }
        let cubin_path = std::env::temp_dir().join("prefill_attn.cubin");
        std::fs::write(&cubin_path, PREFILL_ATTN_CUBIN).map_err(|e| {
            format!("[cuda] prefill_attn cubin temp write failed ({}): {e}", cubin_path.display())
        })?;
        let cubin = cudarc::nvrtc::Ptx::from_file(&cubin_path);
        self.device
            .load_ptx(cubin, "prefill_attn_mod", &["prefill_attn_softmax"])
            .map_err(|e| format!("[cuda] load_ptx(prefill_attn cubin) failed: {e}"))?;
        self.prefill_attn_cubin_loaded = true;
        eprintln!("[cuda] prefill_attn CUBIN module loaded (cuModuleLoadData)");
        Ok(())
    }

    /// GPU batched causal prefill attention for a whole chunk, writing the
    /// attention output into `batch_xb` (token i, head h → `i*qkv_dim+h*head_dim`).
    /// Bit-for-bit-equivalent (to f32 tol) to the CPU Phase-B loop: per query head
    /// h reading kv head `h/num_kv_groups`, causal range `0..=pos`, scores scaled
    /// by `1/sqrt(head_dim)` then softmaxed, then Σ_t softmax·V.
    ///
    /// Pipeline per query-tile (Tq rows, to bound the [heads×Tq×L] scores VRAM):
    ///   1. QKᵀ  — cuBLAS `sgemmStridedBatched`, batched over the num_kv_groups
    ///      query heads that share each kv head (K stride 0 within the group);
    ///      the `1/sqrt(head_dim)` scale is folded into `alpha`.
    ///   2. softmax+causal-mask — the `prefill_attn_softmax` kernel, one block per
    ///      (head,row); masked tail written 0 so the full-width AV reproduces the
    ///      CPU `0..=pos` sum.
    ///   3. AV   — cuBLAS `sgemmStridedBatched`, same group batching, K stride 0.
    /// cuBLAS is column-major: a row-major [p×q] buffer is read as col-major [q×p]
    /// (ld=q), which is why QKᵀ uses (OP_T, OP_N) and AV uses (OP_N, OP_N).
    #[allow(clippy::too_many_arguments)]
    fn prefill_attention(
        &mut self,
        batch_xb: &mut [f32],
        batch_q: &[f32],
        keys: &[f32],
        values: &[f32],
        seq_len: usize,
        start_pos: usize,
        layer_offset: usize,
        max_seq_len: usize,
        num_heads: usize,
        num_kv_heads: usize,
        head_dim: usize,
    ) -> Result<(), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_prefill_attn_module()?;

        let qkv_dim = num_heads * head_dim;
        let num_kv_groups = num_heads / num_kv_heads;
        let scale = 1.0f32 / (head_dim as f32).sqrt();
        let op_t = cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_T;
        let op_n = cudarc::cublas::sys::cublasOperation_t::CUBLAS_OP_N;

        let mut q_off = 0usize;
        while q_off < seq_len {
            let tq = (seq_len - q_off).min(PREFILL_ATTN_TILE_Q);
            // Keys this tile needs: the last query (abs pos start_pos+q_off+tq-1)
            // attends keys [0, that pos] → l = start_pos + q_off + tq keys.
            let l = start_pos + q_off + tq;

            // ── host gather: Q → [num_heads × tq × head_dim] contiguous per head
            let mut qg = vec![0f32; num_heads * tq * head_dim];
            for h in 0..num_heads {
                for t in 0..tq {
                    let src = (q_off + t) * qkv_dim + h * head_dim;
                    let dst = (h * tq + t) * head_dim;
                    qg[dst..dst + head_dim].copy_from_slice(&batch_q[src..src + head_dim]);
                }
            }
            // ── host gather: K, V → [num_kv_heads × l × head_dim] (drop max_seq_len gap)
            let mut kg = vec![0f32; num_kv_heads * l * head_dim];
            let mut vg = vec![0f32; num_kv_heads * l * head_dim];
            for kvh in 0..num_kv_heads {
                let base = layer_offset + kvh * max_seq_len * head_dim;
                let dstb = kvh * l * head_dim;
                kg[dstb..dstb + l * head_dim]
                    .copy_from_slice(&keys[base..base + l * head_dim]);
                vg[dstb..dstb + l * head_dim]
                    .copy_from_slice(&values[base..base + l * head_dim]);
            }

            // ── upload + scratch alloc (per-tile; pooling is a future optimization)
            let d_q = self
                .device
                .htod_sync_copy(&qg)
                .map_err(|e| format!("[cuda] prefill Q htod failed: {e}"))?;
            let d_k = self
                .device
                .htod_sync_copy(&kg)
                .map_err(|e| format!("[cuda] prefill K htod failed: {e}"))?;
            let d_v = self
                .device
                .htod_sync_copy(&vg)
                .map_err(|e| format!("[cuda] prefill V htod failed: {e}"))?;
            let mut d_s = self
                .device
                .alloc_zeros::<f32>(num_heads * tq * l)
                .map_err(|e| format!("[cuda] prefill scores alloc failed: {e}"))?;
            let mut d_o = self
                .device
                .alloc_zeros::<f32>(num_heads * tq * head_dim)
                .map_err(|e| format!("[cuda] prefill out alloc failed: {e}"))?;

            // ── Step 1: Scores[h][tq×l] = scale · Q[h]·K[kvh]ᵀ, batched per group.
            // Row-major Scores[tq×l] ≡ col-major Sc[l×tq]: Sc = op_T(K) · op_N(Q),
            // m=l, n=tq, k=head_dim; lda=ldb=head_dim, ldc=l. K shared (stride 0).
            for kvh in 0..num_kv_heads {
                let gemm = GemmConfig {
                    transa: op_t,
                    transb: op_n,
                    m: l as i32,
                    n: tq as i32,
                    k: head_dim as i32,
                    alpha: scale,
                    lda: head_dim as i32,
                    ldb: head_dim as i32,
                    beta: 0.0,
                    ldc: l as i32,
                };
                let cfg = StridedBatchedConfig {
                    gemm,
                    batch_size: num_kv_groups as i32,
                    stride_a: 0,
                    stride_b: (tq * head_dim) as i64,
                    stride_c: (tq * l) as i64,
                };
                let k_off = kvh * l * head_dim;
                let q_grp = kvh * num_kv_groups * tq * head_dim;
                let s_grp = kvh * num_kv_groups * tq * l;
                let a = d_k.slice(k_off..k_off + l * head_dim);
                let b = d_q.slice(q_grp..q_grp + num_kv_groups * tq * head_dim);
                let mut c = d_s.slice_mut(s_grp..s_grp + num_kv_groups * tq * l);
                unsafe { self.blas.gemm_strided_batched(cfg, &a, &b, &mut c) }
                    .map_err(|e| format!("[cuda] prefill QKᵀ sgemm_strided_batched failed: {e}"))?;
            }

            // ── Step 2: per-row causal mask + softmax (one block per (head,row)).
            let func = self
                .device
                .get_func("prefill_attn_mod", "prefill_attn_softmax")
                .ok_or_else(|| "[cuda] prefill_attn func missing after load_ptx".to_string())?;
            let lcfg = LaunchConfig {
                grid_dim: ((num_heads * tq) as u32, 1, 1),
                block_dim: (PREFILL_ATTN_BLOCK_DIM, 1, 1),
                shared_mem_bytes: PREFILL_ATTN_BLOCK_DIM * 4,
            };
            let mut s_view = d_s.slice_mut(0..num_heads * tq * l);
            unsafe {
                func.launch(
                    lcfg,
                    (&mut s_view, tq as i32, l as i32, start_pos as i32, q_off as i32),
                )
                .map_err(|e| format!("[cuda] prefill softmax launch failed: {e}"))?;
            }
            drop(s_view);

            // ── Step 3: Out[h][tq×head_dim] = P[h]·V[kvh], batched per group.
            // Row-major Out[tq×d] ≡ col-major Oc[d×tq]: Oc = op_N(V) · op_N(P),
            // m=head_dim, n=tq, k=l; lda=head_dim, ldb=l, ldc=head_dim. V stride 0.
            for kvh in 0..num_kv_heads {
                let gemm = GemmConfig {
                    transa: op_n,
                    transb: op_n,
                    m: head_dim as i32,
                    n: tq as i32,
                    k: l as i32,
                    alpha: 1.0,
                    lda: head_dim as i32,
                    ldb: l as i32,
                    beta: 0.0,
                    ldc: head_dim as i32,
                };
                let cfg = StridedBatchedConfig {
                    gemm,
                    batch_size: num_kv_groups as i32,
                    stride_a: 0,
                    stride_b: (tq * l) as i64,
                    stride_c: (tq * head_dim) as i64,
                };
                let v_off = kvh * l * head_dim;
                let s_grp = kvh * num_kv_groups * tq * l;
                let o_grp = kvh * num_kv_groups * tq * head_dim;
                let a = d_v.slice(v_off..v_off + l * head_dim);
                let b = d_s.slice(s_grp..s_grp + num_kv_groups * tq * l);
                let mut c = d_o.slice_mut(o_grp..o_grp + num_kv_groups * tq * head_dim);
                unsafe { self.blas.gemm_strided_batched(cfg, &a, &b, &mut c) }
                    .map_err(|e| format!("[cuda] prefill AV sgemm_strided_batched failed: {e}"))?;
            }

            // ── dtoh + scatter Out[h][t][:] → batch_xb[(q_off+t)*qkv_dim + h*head_dim]
            let mut og = vec![0f32; num_heads * tq * head_dim];
            self.device
                .dtoh_sync_copy_into(&d_o, &mut og)
                .map_err(|e| format!("[cuda] prefill out dtoh failed: {e}"))?;
            for h in 0..num_heads {
                for t in 0..tq {
                    let src = (h * tq + t) * head_dim;
                    let dst = (q_off + t) * qkv_dim + h * head_dim;
                    batch_xb[dst..dst + head_dim].copy_from_slice(&og[src..src + head_dim]);
                }
            }

            q_off += tq;
        }
        Ok(())
    }

    // ---- MESH_GPU_Q4K=1: custom in-kernel Q4_K / Q6_K dequant-GEMV (decode) ----

    /// Get (or upload + cache) the RAW K-quant (Q4_K or Q6_K) weight bytes
    /// resident in VRAM. EXACTLY mirrors `resident_weight_q8_raw` (NO host
    /// dequant, NO f16 conversion — the raw ~4.0 GB go up ONCE via htod_sync_copy
    /// and the kernel dequantizes in-flight). Q4_K and Q6_K share this one cache
    /// + budget (one weight content per fingerprint key). FIFO-evicted under
    /// `q4kraw_budget_bytes`.
    fn resident_weight_q4k_raw(&mut self, w: &[u8]) -> Result<Arc<CudaSlice<u8>>, String> {
        let key = (weight_fingerprint(w) as usize, w.len());
        if let Some(buf) = self.q4kraw_weights.get(&key) {
            return Ok(buf.clone());
        }
        let bytes = w.len() as u64;
        // Evict oldest (FIFO) until this upload fits the raw K-quant budget.
        while self.q4kraw_bytes + bytes > self.q4kraw_budget_bytes {
            let Some(old_key) = self.q4kraw_order.pop_front() else {
                break;
            };
            if let Some(old) = self.q4kraw_weights.remove(&old_key) {
                self.q4kraw_bytes = self.q4kraw_bytes.saturating_sub(old.len() as u64);
                drop(old); // last Arc -> device buffer freed -> VRAM reclaimed
            }
        }
        let t_up = Instant::now();
        let dev = self
            .device
            .htod_sync_copy(w)
            .map_err(|e| format!("[cuda] raw-Kquant weight htod_sync_copy failed ({:.0} MB, raw resident {:.2} GB / budget {:.1} GB): {e}",
                bytes as f64 / 1e6,
                self.q4kraw_bytes as f64 / 1e9,
                self.q4kraw_budget_bytes as f64 / 1e9))?;
        let up_ms = t_up.elapsed().as_secs_f64() * 1e3;
        let n_up = WEIGHT_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        let phase_up = PHASE_UPLOADS.fetch_add(1, Ordering::Relaxed) + 1;
        WEIGHT_BYTES_UP.fetch_add(bytes, Ordering::Relaxed);
        if should_log_phase(phase_up, cuda_upload_log_every()) {
            eprintln!(
                "[cuda] raw-Kquant weight upload #{n_up} (phase #{phase_up}) MISS {:.1} MB \
                 htod={up_ms:.1}ms (raw-Kquant resident {:.2} GB / budget {:.1} GB)",
                bytes as f64 / 1e6,
                (self.q4kraw_bytes + bytes) as f64 / 1e9,
                self.q4kraw_budget_bytes as f64 / 1e9,
            );
        }
        let arc = Arc::new(dev);
        self.q4kraw_weights.insert(key, arc.clone());
        self.q4kraw_order.push_back(key);
        self.q4kraw_bytes += bytes;
        Ok(arc)
    }

    /// Load the q4k_gemv cubin module into this device ONCE (idempotent guard via
    /// `q4k_cubin_loaded`). EXACTLY mirrors `ensure_q8k_module`: materialize the
    /// embedded sm_89 CUBIN to a temp file, load via `Ptx::from_file` ->
    /// cuModuleLoadData (native SASS, NO runtime NVRTC). Err if cubin empty / load
    /// fails; callers map Err -> false (existing path).
    fn ensure_q4k_module(&mut self) -> Result<(), String> {
        if self.q4k_cubin_loaded {
            return Ok(());
        }
        if Q4K_GEMV_CUBIN.is_empty() {
            return Err("[cuda] q4k_gemv cubin empty — kernel unavailable (nvcc absent at build)".to_string());
        }
        let cubin_path = std::env::temp_dir().join("q4k_gemv.cubin");
        std::fs::write(&cubin_path, Q4K_GEMV_CUBIN)
            .map_err(|e| format!("[cuda] q4k_gemv cubin temp write failed ({}): {e}", cubin_path.display()))?;
        let cubin = cudarc::nvrtc::Ptx::from_file(&cubin_path);
        self.device
            .load_ptx(cubin, "q4k_gemv_mod", &["q4k_gemv"])
            .map_err(|e| format!("[cuda] load_ptx(q4k_gemv cubin) failed: {e}"))?;
        // Opt the function into the sm_89 large-dynamic-shared limit so K up to
        // Q4K_SHARED_X_MAX_K (64 KB of staged x) is allowed (> the 48 KB classic
        // cap). Best-effort: if the attribute set fails (older driver), staging
        // for the big-K case simply won't launch and the global-x path runs.
        set_kquant_max_dynamic_shared(&self.device, "q4k_gemv_mod", "q4k_gemv");
        self.q4k_cubin_loaded = true;
        eprintln!("[cuda] q4k_gemv CUBIN module loaded (cuModuleLoadData, sm_89)");
        Ok(())
    }

    /// Load the q6k_gemv cubin module into this device ONCE. Mirrors
    /// `ensure_q4k_module`.
    fn ensure_q6k_module(&mut self) -> Result<(), String> {
        if self.q6k_cubin_loaded {
            return Ok(());
        }
        if Q6K_GEMV_CUBIN.is_empty() {
            return Err("[cuda] q6k_gemv cubin empty — kernel unavailable (nvcc absent at build)".to_string());
        }
        let cubin_path = std::env::temp_dir().join("q6k_gemv.cubin");
        std::fs::write(&cubin_path, Q6K_GEMV_CUBIN)
            .map_err(|e| format!("[cuda] q6k_gemv cubin temp write failed ({}): {e}", cubin_path.display()))?;
        let cubin = cudarc::nvrtc::Ptx::from_file(&cubin_path);
        self.device
            .load_ptx(cubin, "q6k_gemv_mod", &["q6k_gemv"])
            .map_err(|e| format!("[cuda] load_ptx(q6k_gemv cubin) failed: {e}"))?;
        // Same large-dynamic-shared opt-in as q4k (the down-proj K=15360 is Q6_K).
        set_kquant_max_dynamic_shared(&self.device, "q6k_gemv_mod", "q6k_gemv");
        self.q6k_cubin_loaded = true;
        eprintln!("[cuda] q6k_gemv CUBIN module loaded (cuModuleLoadData, sm_89)");
        Ok(())
    }

    /// Single-token (decode) Q4_K GEMV via the custom kernel. EXACTLY mirrors
    /// `q8_gemv_kernel` (warp-per-rows, shared-x staging, pooled buffers, dtoh,
    /// gpucheck) — only the cubin/func names + the dequant-row reference differ.
    /// `w` is the RAW Q4_K bytes [n rows × d], `x` length d, `out` length n.
    fn q4k_gemv_kernel(
        &mut self,
        out: &mut [f32],
        x: &[f32],
        w: &[u8],
        n: usize,
        d: usize,
    ) -> Result<(), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_q4k_module()?;
        let w_dev = self.resident_weight_q4k_raw(w)?;
        self.upload_xs(x)?;
        self.ensure_out(n)?;
        let func = self
            .device
            .get_func("q4k_gemv_mod", "q4k_gemv")
            .ok_or_else(|| "[cuda] q4k_gemv func missing after load_ptx".to_string())?;
        let rows_per_block = Q4K_WARPS_PER_BLOCK * Q4K_ROWS_PER_WARP;
        let grid_x = (n as u32).div_ceil(rows_per_block);
        let shared_mem_bytes = if d <= Q4K_SHARED_X_MAX_K {
            (d * std::mem::size_of::<f32>()) as u32
        } else {
            0
        };
        let cfg = LaunchConfig {
            grid_dim: (grid_x, 1, 1),
            block_dim: (Q4K_BLOCK_DIM, 1, 1),
            shared_mem_bytes,
        };
        let x_view = self.xs_pool.as_ref().unwrap().slice(0..d);
        let mut out_view = self.out_pool.as_mut().unwrap().slice_mut(0..n);
        // SAFETY: grid/block/shared match the kernel's launch contract; W has
        // n*(d/256)*144 bytes, x has d elems, out has n elems — all within the
        // resident/pooled allocations.
        unsafe {
            func.launch(
                cfg,
                (w_dev.as_ref(), &x_view, &mut out_view, n as i32, d as i32),
            )
            .map_err(|e| format!("[cuda] q4k_gemv launch failed: {e}"))?;
        }
        self.device
            .dtoh_sync_copy_into(&out_view, out)
            .map_err(|e| format!("[cuda] q4k_gemv out dtoh failed: {e}"))?;
        gpucheck_quant("q4k-kernel", out, x, w, n, d, 1, dequantize_q4k_row);
        Ok(())
    }

    /// Single-token (decode) Q6_K GEMV via the custom kernel. Mirrors
    /// `q4k_gemv_kernel`; `w` is the RAW Q6_K bytes [n rows × d] (d/256 × 210
    /// bytes/row).
    fn q6k_gemv_kernel(
        &mut self,
        out: &mut [f32],
        x: &[f32],
        w: &[u8],
        n: usize,
        d: usize,
    ) -> Result<(), String> {
        use cudarc::driver::{LaunchAsync, LaunchConfig};
        self.ensure_q6k_module()?;
        let w_dev = self.resident_weight_q4k_raw(w)?;
        self.upload_xs(x)?;
        self.ensure_out(n)?;
        let func = self
            .device
            .get_func("q6k_gemv_mod", "q6k_gemv")
            .ok_or_else(|| "[cuda] q6k_gemv func missing after load_ptx".to_string())?;
        let rows_per_block = Q4K_WARPS_PER_BLOCK * Q4K_ROWS_PER_WARP;
        let grid_x = (n as u32).div_ceil(rows_per_block);
        let shared_mem_bytes = if d <= Q4K_SHARED_X_MAX_K {
            (d * std::mem::size_of::<f32>()) as u32
        } else {
            0
        };
        let cfg = LaunchConfig {
            grid_dim: (grid_x, 1, 1),
            block_dim: (Q4K_BLOCK_DIM, 1, 1),
            shared_mem_bytes,
        };
        let x_view = self.xs_pool.as_ref().unwrap().slice(0..d);
        let mut out_view = self.out_pool.as_mut().unwrap().slice_mut(0..n);
        // SAFETY: grid/block/shared match the kernel's launch contract; W has
        // n*(d/256)*210 bytes, x has d elems, out has n elems.
        unsafe {
            func.launch(
                cfg,
                (w_dev.as_ref(), &x_view, &mut out_view, n as i32, d as i32),
            )
            .map_err(|e| format!("[cuda] q6k_gemv launch failed: {e}"))?;
        }
        self.device
            .dtoh_sync_copy_into(&out_view, out)
            .map_err(|e| format!("[cuda] q6k_gemv out dtoh failed: {e}"))?;
        gpucheck_quant("q6k-kernel", out, x, w, n, d, 1, dequantize_q6k_row);
        Ok(())
    }
}

/// GPU entry for the batched row-shared Q8 matmul. Returns `true` if the GPU
/// handled it; `false` (or on any GPU error) means the caller must run the CPU
/// kernel. The CPU path stays the source of truth for correctness + fallback.
/// MESH_GPU_PREFILL_ATTN=1 entry: route a chunk's causal prefill attention
/// (Phase B) through the batched GPU path. Same contract + fallback discipline
/// as the other `try_*` gates: `true` = the GPU handled it (output written into
/// `batch_xb`); `false` (flag off / GPU absent / kernel cubin empty / decode /
/// unsupported shape / any GPU error) = the caller MUST run the CPU Phase-B
/// `par_chunks_mut` loop. The CPU path stays the source of truth.
///
/// The caller MUST only take this path when the CPU-only attention features are
/// inactive (attention-score memo OFF, bowl q-filter NONE) — this GPU path
/// implements the plain causal attention, not those variants.
#[allow(clippy::too_many_arguments)]
pub fn try_prefill_attention(
    batch_xb: &mut [f32],
    batch_q: &[f32],
    keys: &[f32],
    values: &[f32],
    seq_len: usize,
    start_pos: usize,
    layer_offset: usize,
    max_seq_len: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) -> bool {
    // Gates: flag on, kernel compiled in, this is a prefill chunk (T>=2).
    if !gpu_prefill_attn_enabled() || !prefill_attn_kernel_available() {
        return false;
    }
    if seq_len < 2 {
        return false;
    }
    // Shape guards (GQA divisibility + buffer bounds) — any miss → CPU path.
    if num_heads == 0
        || num_kv_heads == 0
        || head_dim == 0
        || num_heads % num_kv_heads != 0
    {
        return false;
    }
    let qkv_dim = num_heads * head_dim;
    if batch_q.len() < seq_len * qkv_dim || batch_xb.len() < seq_len * qkv_dim {
        return false;
    }
    let l_max = start_pos + seq_len;
    for kvh in 0..num_kv_heads {
        let need = layer_offset + kvh * max_seq_len * head_dim + l_max * head_dim;
        if keys.len() < need || values.len() < need {
            return false;
        }
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.prefill_attention(
        batch_xb, batch_q, keys, values, seq_len, start_pos, layer_offset, max_seq_len,
        num_heads, num_kv_heads, head_dim,
    ) {
        Ok(()) => {
            // REAL-DATA correctness probe (FLUX_GPUCHECK=1): diff the whole GPU
            // attention output against an independent scalar f64 recompute.
            gpucheck_prefill_attn(
                batch_xb, batch_q, keys, values, seq_len, start_pos, layer_offset,
                max_seq_len, num_heads, num_kv_heads, head_dim,
            );
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if should_log_phase(phase, cuda_op_log_every()) {
                eprintln!(
                    "[cuda] PREFILL-ATTN #{nops} (phase #{phase}) T={seq_len} ctx={l_max} \
                     heads={num_heads}/{num_kv_heads}×{head_dim} {:.2}ms",
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            eprintln!("{e} — falling back to CPU prefill attention for this chunk");
            false
        }
    }
}

/// FLUX_GPUCHECK=1 probe for `try_prefill_attention`: recompute the FULL causal
/// attention output on the CPU in f64 (independent of the GPU code path) and log
/// the max |gpu − cpu| over all (token, head, dim). No-op unless the env is set
/// (the f64 recompute is O(seq²·heads·head_dim) — validation only). Like
/// `gpucheck_quant`, this only OBSERVES; the parity TEST is the gate.
#[allow(clippy::too_many_arguments)]
fn gpucheck_prefill_attn(
    out: &[f32],
    q: &[f32],
    keys: &[f32],
    values: &[f32],
    seq_len: usize,
    start_pos: usize,
    layer_offset: usize,
    max_seq_len: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
) {
    if !gpucheck_enabled() {
        return;
    }
    let qkv_dim = num_heads * head_dim;
    let num_kv_groups = num_heads / num_kv_heads;
    let scale = 1.0f64 / (head_dim as f64).sqrt();
    let mut max_abs = 0f64;
    let mut argmax = (0usize, 0usize, 0usize);
    for i in 0..seq_len {
        let pos = start_pos + i;
        for h in 0..num_heads {
            let kvh = h / num_kv_groups;
            let q_base = i * qkv_dim + h * head_dim;
            let kv_base = layer_offset + kvh * max_seq_len * head_dim;
            // scores (scaled) over the causal prefix 0..=pos
            let mut sc = vec![0f64; pos + 1];
            for (t, s) in sc.iter_mut().enumerate() {
                let kt = kv_base + t * head_dim;
                let mut acc = 0f64;
                for d in 0..head_dim {
                    acc += q[q_base + d] as f64 * keys[kt + d] as f64;
                }
                *s = acc * scale;
            }
            // softmax
            let m = sc.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
            let mut sum = 0f64;
            for s in sc.iter_mut() {
                *s = (*s - m).exp();
                sum += *s;
            }
            let inv = if sum > 0.0 { 1.0 / sum } else { 0.0 };
            // AV, compared element-wise to the GPU output
            for d in 0..head_dim {
                let mut acc = 0f64;
                for (t, s) in sc.iter().enumerate() {
                    acc += s * inv * values[kv_base + t * head_dim + d] as f64;
                }
                let got = out[i * qkv_dim + h * head_dim + d] as f64;
                let diff = (got - acc).abs();
                if diff > max_abs {
                    max_abs = diff;
                    argmax = (i, h, d);
                }
            }
        }
    }
    eprintln!(
        "[cuda] GPUCHECK prefill-attn: max|gpu-cpu|={max_abs:.3e} at (token={}, head={}, dim={}) \
         over {seq_len}×{num_heads}×{head_dim}",
        argmax.0, argmax.1, argmax.2
    );
}

pub fn try_mat_vec_q8_0_rows_shared(
    out: &mut [f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
) -> bool {
    let Some(ctx) = gpu() else {
        return false;
    };
    // Tiny single-/few-vector GEMVs are sync-overhead-bound; the SIMD CPU kernel
    // beats a host<->device round-trip. Let the caller run the CPU path.
    if tokens < gpu_min_tokens() {
        return false;
    }
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.gemm_rows_shared(out, xs, w, n, d, tokens) {
        Ok(()) => {
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if should_log_phase(phase, cuda_op_log_every()) {
                eprintln!(
                    "[cuda] Q8 gemm #{nops} (phase #{phase}) [{n}x{d}]·[{tokens}x{d}] -> [{tokens}x{n}] {:.2}ms",
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            if e == VRAM_SATURATED {
                // Expected steady state under the liquid-memory cpu policy — the
                // GPU is full, this op runs CPU. Throttle the log so the overflow
                // layers don't spam per token; a periodic count shows the split.
                let n = SATURATION_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                if n == 1 || n % 512 == 0 {
                    eprintln!(
                        "[cuda] liquid-memory: {n} overflow ops routed to CPU (GPU cache full)"
                    );
                }
            } else {
                eprintln!("{e} — falling back to CPU kernel for this op");
            }
            false
        }
    }
}

/// GPU entry for the single-vector Q8 matmul (tokens = 1): out[r] = Σ_c W[r,c]·x[c].
/// With the default `gpu_min_tokens >= 2` this always returns false (CPU wins on
/// a 1-row GEMV) — kept for completeness / explicit override.
pub fn try_mat_vec_q8_0(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) -> bool {
    try_mat_vec_q8_0_rows_shared(out, x, w, n, d, 1)
}

/// MESH_GPU_Q8K=1 single-token (decode) entry: route the Q8_0 GEMV through the
/// CUSTOM in-kernel dequant-GEMV (reads RAW Q8 bytes, dequantizes in-flight) so
/// VRAM-bandwidth-bound decode reads ~7.7 GB instead of the ~14.5 GB f16 working
/// set. Same contract + fallback discipline as `try_mat_vec_q8_0_rows_shared`:
/// `true` = the GPU kernel handled it; `false` (flag off / GPU absent / PTX
/// unavailable / wrong shape / any error) = the caller MUST run the existing
/// cuBLAS/CPU path. Decode-only (tokens=1). CPU stays the source of truth.
pub fn try_mat_vec_q8_0_kernel(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) -> bool {
    // All gates: flag on, GPU engaged, decode token clears the min gate, kernel
    // PTX compiled in. Any miss → false → existing path.
    if !gpu_q8k_enabled() || !q8_kernel_available() {
        return false;
    }
    if !gpu_wants(1) {
        return false;
    }
    // Q8_0 requires K (=d) to be a multiple of 32; the kernel assumes K/32 whole
    // blocks. Guard so a ragged shape never reaches the kernel.
    if d == 0 || d % 32 != 0 {
        return false;
    }
    let blocks_per_row = d / 32;
    if w.len() < n * blocks_per_row * 34 {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.q8_gemv_kernel(out, x, w, n, d) {
        Ok(()) => {
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if should_log_phase(phase, cuda_op_log_every()) {
                eprintln!(
                    "[cuda] Q8-KERNEL gemv #{nops} (phase #{phase}) [{n}x{d}]·[1x{d}] -> [1x{n}] {:.2}ms",
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            eprintln!("{e} — falling back to existing path for this op");
            false
        }
    }
}

/// MESH_GPU_SCAN=1 single-token (decode) entry for the Mamba-1 (S6) selective
/// scan: run the per-channel recurrence on the GPU with the state resident in
/// VRAM. `h_host` is this layer's CPU state; it SEEDS the resident VRAM state on
/// the first step for the layer (so reset/resume just work) and, on every
/// successful step, is MIRRORED back from the advanced resident state (a cheap
/// D2H) so the host stays coherent for a CPU-scan fallback or `/ssm-state/save`.
/// SAME contract + fallback discipline as `try_mat_vec_q8_0_kernel`:
/// `true` = the GPU kernel handled it (write `y`, resident state advanced);
/// `false` (flag off / GPU absent / cubin unavailable / any error) = the caller
/// MUST run the existing CPU S6 scan. The CPU scan stays the source of truth.
#[allow(clippy::too_many_arguments)]
pub fn try_mamba1_s6_scan(
    y: &mut [f32],
    x_conv: &[f32],
    dt: &[f32],
    b_vec: &[f32],
    c_vec: &[f32],
    a_log: &[f32],
    d_skip: &[f32],
    d_inner: usize,
    d_state: usize,
    layer_idx: usize,
    h_host: &mut [f32],
) -> bool {
    if !gpu_scan_enabled() || !mamba_scan_kernel_available() {
        return false;
    }
    // Shape sanity — the kernel indexes a_log[ch*d_state + s] and h likewise.
    if d_inner == 0
        || d_state == 0
        || y.len() != d_inner
        || x_conv.len() != d_inner
        || dt.len() != d_inner
        || d_skip.len() != d_inner
        || b_vec.len() != d_state
        || c_vec.len() != d_state
        || a_log.len() != d_inner * d_state
        || h_host.len() != d_inner * d_state
    {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    match guard.mamba1_s6_scan(
        y, x_conv, dt, b_vec, c_vec, a_log, d_skip, d_inner, d_state, layer_idx, h_host,
    ) {
        Ok(()) => true,
        Err(e) => {
            eprintln!("{e} — falling back to the CPU S6 scan for this step");
            false
        }
    }
}

/// Clear all RESIDENT Mamba recurrent states (call at a sequence boundary, from
/// `MambaPipeline::reset_states`). The next GPU scan step for each layer then
/// re-seeds its resident state from the (freshly-zeroed / freshly-loaded) host
/// state. No-op without a GPU / when the scan path was never engaged. The
/// resident a_log / d_skip caches are intentionally KEPT (weights don't change
/// across sequences).
pub fn mamba_scan_reset_all() {
    let Some(ctx) = gpu() else {
        return;
    };
    if let Ok(mut guard) = ctx.lock() {
        guard.mamba_h.clear();
        // Also clear the parallel Mamba-2 SSD resident states (same sequence
        // boundary; the resident a_log / d_skip caches are intentionally KEPT).
        guard.mamba2_h.clear();
    }
}

/// UNCONDITIONALLY mirror ONE layer's resident Mamba-2 (SSD) recurrent state back
/// into the host `h_host` (CHANNEL-MAJOR), regardless of MESH_GPU_SCAN_MIRROR_HOST.
///
/// The Mamba-2 hot decode path leaves the resident VRAM state authoritative and
/// gates the per-token 256 MB D2H mirror OFF for cost (see `mamba2_mirror_h_if_enabled`).
/// Any HOST-side reader of `state.ssm_h` — the SSM PREFIX-STATE cache capture and
/// `/ssm-state/save` — therefore serializes a STALE (first-use seed = zero) state
/// unless it mirrors first. A checkpoint/prefix blob saved without this mirror
/// restores a ZEROED SSD state → the continuation resumes from no long-range memory
/// and decodes garbage (a degenerate non-terminating tail), exactly the failure the
/// S6 path fixed by mirroring every step. This is the LOW-FREQUENCY equivalent: run
/// it only at a capture/save boundary (a handful of times), not per token.
///
/// Returns `true` iff a resident state existed for this layer and was mirrored;
/// `false` (no GPU / scan never engaged / this layer not resident / size mismatch)
/// leaves `h_host` untouched — already the source of truth on the CPU-scan path.
#[cfg(all(feature = "cuda", not(target_arch = "wasm32")))]
pub fn mamba2_sync_h_to_host(
    layer_idx: usize,
    d_inner: usize,
    d_state: usize,
    h_host: &mut [f32],
) -> bool {
    let hlen = d_inner * d_state;
    if hlen == 0 || h_host.len() != hlen {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let Ok(guard) = ctx.lock() else {
        return false;
    };
    let state_key = (layer_idx, hlen);
    let Some(resident) = guard.mamba2_h.get(&state_key) else {
        return false;
    };
    let h_resident = resident.slice(0..hlen);
    let mut h_gpu = vec![0.0f32; hlen];
    if guard
        .device
        .dtoh_sync_copy_into(&h_resident, &mut h_gpu)
        .is_err()
    {
        return false;
    }
    // Resident is STATE-MAJOR (h_gpu[n*d_inner + c]); host is CHANNEL-MAJOR
    // (h_host[c*d_state + n]) — the exact inverse of the seed transpose.
    for ch in 0..d_inner {
        let dst = ch * d_state;
        for n in 0..d_state {
            h_host[dst + n] = h_gpu[n * d_inner + ch];
        }
    }
    true
}

/// Non-cuda / wasm no-op: the host `state.ssm_h` is always the source of truth
/// (no resident GPU state exists), so nothing to mirror.
#[cfg(not(all(feature = "cuda", not(target_arch = "wasm32"))))]
pub fn mamba2_sync_h_to_host(
    _layer_idx: usize,
    _d_inner: usize,
    _d_state: usize,
    _h_host: &mut [f32],
) -> bool {
    false
}

/// MESH_GPU_SCAN=1 single-token (decode) entry for the Mamba-2 (SSD) selective
/// scan: run the grouped multi-head recurrence on the GPU with the state resident
/// in VRAM. Mirrors `try_mamba1_s6_scan` exactly (seed-on-first-use, mirror-back
/// on success, CPU stays the source of truth). The caller precomputes `dt =
/// softplus(dt_in + dt_bias)` and applies the gated RMSNorm AFTER this returns.
/// `true` = the GPU kernel handled it (write `y`, resident state advanced);
/// `false` (flag off / GPU absent / cubin unavailable / shape guard / any error)
/// = the caller MUST run the existing CPU SSD scan.
#[allow(clippy::too_many_arguments)]
pub fn try_mamba2_ssd_scan(
    y: &mut [f32],
    x_conv: &[f32],
    dt: &[f32],
    b_vec: &[f32],
    c_vec: &[f32],
    a_log: &[f32],
    d_skip: &[f32],
    d_inner: usize,
    d_state: usize,
    num_heads: usize,
    head_dim: usize,
    n_groups: usize,
    layer_idx: usize,
    h_host: &mut [f32],
) -> bool {
    if !gpu_scan_enabled() || !mamba2_ssd_scan_kernel_available() {
        return false;
    }
    // Shape sanity — the kernel maps ONE THREAD PER CHANNEL (d_inner = num_heads *
    // head_dim), indexes a_log/d_skip/dt per head, B/C per group. The resident h is
    // GPU-internal STATE-MAJOR (h[n*d_inner + c], coalesced) — seeded/mirrored by
    // transpose; the host state stays channel-major (h_host[c*d_state + n]).
    let bc_len = n_groups.saturating_mul(d_state);
    if d_inner == 0
        || d_state == 0
        || num_heads == 0
        || head_dim == 0
        || n_groups == 0
        || d_inner != num_heads * head_dim
        || y.len() != d_inner
        || x_conv.len() != d_inner
        || dt.len() != num_heads
        || a_log.len() != num_heads
        || d_skip.len() != num_heads
        || b_vec.len() != bc_len
        || c_vec.len() != bc_len
        || h_host.len() != d_inner * d_state
    {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    match guard.mamba2_ssd_scan(
        y, x_conv, dt, b_vec, c_vec, a_log, d_skip, d_inner, d_state, num_heads, head_dim,
        n_groups, layer_idx, h_host,
    ) {
        Ok(()) => true,
        Err(e) => {
            eprintln!("{e} — falling back to the CPU SSD scan for this step");
            false
        }
    }
}

/// True when the FUSED SSD path is fully wired: MESH_GPU_SSM_FUSED=1 AND all three
/// kernels the fused layer needs are compiled in (SSD scan + gated norm + the Q8
/// resident out_proj GEMV). `mamba2_ssd_step` gates `use_fused` on this so that
/// whenever the fused scan runs, the resident out_proj is guaranteed available —
/// no path can leave a normed y resident with no way to consume it. Any miss →
/// false → the existing scan + host-norm + host out_proj path (parity reference).
pub fn ssm_fused_ready() -> bool {
    gpu_ssm_fused_enabled()
        && mamba2_ssd_scan_kernel_available()
        && mamba2_gated_norm_kernel_available()
        && q8_kernel_available()
}

/// MESH_GPU_SSM_FUSED=1 FUSED decode step: SSD scan → device gated-RMSNorm, leaving
/// the NORMED y RESIDENT (no dtoh). Same seed/mirror discipline as
/// `try_mamba2_ssd_scan`; additionally takes `z` + `norm_w` + `rms_eps` for the
/// device gated-norm. `true` = the normed y is resident (the caller must consume it
/// via the resident out_proj, e.g. `try_out_proj_resident_q8`; host `y` is left
/// untouched/stale). `false` (flag off / kernels absent / shape guard / any error)
/// = the caller MUST run the non-fused scan + host gated-norm path.
#[allow(clippy::too_many_arguments)]
pub fn try_mamba2_ssd_scan_fused(
    x_conv: &[f32],
    dt: &[f32],
    b_vec: &[f32],
    c_vec: &[f32],
    a_log: &[f32],
    d_skip: &[f32],
    z: &[f32],
    norm_w: &[f32],
    rms_eps: f32,
    d_inner: usize,
    d_state: usize,
    num_heads: usize,
    head_dim: usize,
    n_groups: usize,
    layer_idx: usize,
    h_host: &mut [f32],
) -> bool {
    if !gpu_ssm_fused_enabled()
        || !mamba2_ssd_scan_kernel_available()
        || !mamba2_gated_norm_kernel_available()
    {
        return false;
    }
    // Same shape sanity as `try_mamba2_ssd_scan`, plus the gate/gamma over d_inner.
    let bc_len = n_groups.saturating_mul(d_state);
    if d_inner == 0
        || d_state == 0
        || num_heads == 0
        || head_dim == 0
        || n_groups == 0
        || d_inner != num_heads * head_dim
        || x_conv.len() != d_inner
        || dt.len() != num_heads
        || a_log.len() != num_heads
        || d_skip.len() != num_heads
        || b_vec.len() != bc_len
        || c_vec.len() != bc_len
        || z.len() != d_inner
        || norm_w.len() != d_inner
        || h_host.len() != d_inner * d_state
    {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    match guard.mamba2_ssd_scan_fused(
        x_conv, dt, b_vec, c_vec, a_log, d_skip, z, norm_w, rms_eps, d_inner, d_state, num_heads,
        n_groups, layer_idx, h_host,
    ) {
        Ok(()) => true,
        Err(e) => {
            eprintln!("{e} — falling back to the non-fused scan + host gated-norm for this step");
            false
        }
    }
}

/// out_proj GEMV for the fused SSD layer: run the Q8_0 kernel reading x from the
/// RESIDENT `mamba2_y_normed` (the fused gated-norm output) — NO host upload. Only
/// valid immediately after a successful `try_mamba2_ssd_scan_fused` for the SAME
/// layer. `true` = the resident GEMV ran (`out` filled). `false` (flag off / kernel
/// absent / wrong shape / resident buffer missing / error) = the caller must recover
/// host y (`fused_y_to_host`) and run the normal out_proj.
pub fn try_out_proj_resident_q8(out: &mut [f32], w: &[u8], n: usize, d: usize) -> bool {
    if !gpu_ssm_fused_enabled() || !q8_kernel_available() {
        return false;
    }
    if !gpu_wants(1) {
        return false;
    }
    if d == 0 || d % 32 != 0 {
        return false;
    }
    let blocks_per_row = d / 32;
    if w.len() < n * blocks_per_row * 34 {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    match guard.q8_gemv_kernel_resident(out, w, n, d) {
        Ok(()) => true,
        Err(e) => {
            eprintln!("{e} — recovering host y for the normal out_proj path");
            false
        }
    }
}

/// Copy the RESIDENT fused normed-y (`mamba2_y_normed[0..y.len()]`) back to host —
/// the recovery path when `try_out_proj_resident_q8` cannot run but the fused scan
/// already produced a resident normed y (so host `y` is stale). `false` = no GPU /
/// no resident buffer / dtoh error (caller then has whatever host y it held).
pub fn fused_y_to_host(y: &mut [f32]) -> bool {
    let Some(ctx) = gpu() else {
        return false;
    };
    let guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    match &guard.mamba2_y_normed {
        Some(buf) if buf.len() >= y.len() => {
            let v = buf.slice(0..y.len());
            guard.device.dtoh_sync_copy_into(&v, y).is_ok()
        }
        _ => false,
    }
}

/// MESH_GPU_Q4K=1 single-token (decode) entry for Q4_K: route the Q4_K GEMV
/// through the CUSTOM in-kernel dequant-GEMV (reads RAW Q4_K bytes, dequantizes
/// in-flight) so VRAM-bandwidth-bound decode reads ~4.0 GB instead of the f16
/// working set. SAME contract + fallback discipline as `try_mat_vec_q8_0_kernel`:
/// `true` = the GPU kernel handled it; `false` (flag off / GPU absent / cubin
/// unavailable / wrong shape / any error) = the caller MUST run the existing
/// cuBLAS/CPU path. Decode-only (tokens=1). CPU stays the source of truth.
pub fn try_mat_vec_q4k_kernel(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) -> bool {
    if !gpu_q4k_enabled() || !q4k_kernel_available() {
        return false;
    }
    if !gpu_wants(1) {
        return false;
    }
    // Q4_K requires K (=d) to be a multiple of 256 (whole superblocks).
    if d == 0 || d % 256 != 0 {
        return false;
    }
    let sblk_per_row = d / 256;
    if w.len() < n * sblk_per_row * 144 {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.q4k_gemv_kernel(out, x, w, n, d) {
        Ok(()) => {
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if should_log_phase(phase, cuda_op_log_every()) {
                eprintln!(
                    "[cuda] Q4K-KERNEL gemv #{nops} (phase #{phase}) [{n}x{d}]·[1x{d}] -> [1x{n}] {:.2}ms",
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            eprintln!("{e} — falling back to existing path for this op");
            false
        }
    }
}

/// MESH_GPU_Q4K=1 single-token (decode) entry for Q6_K (the same flag enables
/// both K-quant kernels — Q4_K_M's ffn_down/attn_v tensors are Q6_K). Mirrors
/// `try_mat_vec_q4k_kernel`; the Q6_K superblock is 210 bytes/256 elems.
pub fn try_mat_vec_q6k_kernel(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) -> bool {
    if !gpu_q4k_enabled() || !q6k_kernel_available() {
        return false;
    }
    if !gpu_wants(1) {
        return false;
    }
    // Q6_K requires K (=d) to be a multiple of 256 (whole superblocks).
    if d == 0 || d % 256 != 0 {
        return false;
    }
    let sblk_per_row = d / 256;
    if w.len() < n * sblk_per_row * 210 {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.q6k_gemv_kernel(out, x, w, n, d) {
        Ok(()) => {
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if should_log_phase(phase, cuda_op_log_every()) {
                eprintln!(
                    "[cuda] Q6K-KERNEL gemv #{nops} (phase #{phase}) [{n}x{d}]·[1x{d}] -> [1x{n}] {:.2}ms",
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            eprintln!("{e} — falling back to existing path for this op");
            false
        }
    }
}

// ── MESH_GPU_CPU_RACE readiness gates ──────────────────────────────────────
//
// The heterogeneous GPU‖CPU split (driven from `math.rs::mat_vec_q8_0` /
// `mat_vec_q4k` / `mat_vec_q6k`) sends the GPU half through the EXISTING
// `try_*_kernel` entries (so the GPU half uses the custom in-kernel dequant-GEMV,
// the only resident-weight GPU path for decode). These predicates report whether
// that kernel WOULD run for the FULL `(n, d)` shape — same gates the kernel entry
// itself checks (per-kernel enable flag, kernel compiled in, GPU present, decode
// min-token gate, shape, weight length) — so the race only engages when the GPU
// half is actually viable. The split then calls the kernel on a sub-range
// `[0..k)` (whose shape is a valid sub-shape: same `d`, `k` whole rows, weight
// prefix `w[0 .. k*bytes_per_row]`), and the kernel re-checks the same gates for
// that sub-range. If the sub-range call returns false anyway, the caller computes
// that range on the CPU, so the result is always complete and exact.

/// Q8_0 readiness for the GPU‖CPU race: the Q8 kernel would run for `(n, d)`.
pub fn q8k_race_ready(n: usize, d: usize, w_len: usize) -> bool {
    if !gpu_q8k_enabled() || !q8_kernel_available() || !gpu_wants(1) {
        return false;
    }
    if d == 0 || d % 32 != 0 {
        return false;
    }
    w_len >= n * (d / 32) * 34
}

/// Q4_K readiness for the GPU‖CPU race: the Q4_K kernel would run for `(n, d)`.
pub fn q4k_race_ready(n: usize, d: usize, w_len: usize) -> bool {
    if !gpu_q4k_enabled() || !q4k_kernel_available() || !gpu_wants(1) {
        return false;
    }
    if d == 0 || d % 256 != 0 {
        return false;
    }
    w_len >= n * (d / 256) * 144
}

/// Q6_K readiness for the GPU‖CPU race: the Q6_K kernel would run for `(n, d)`.
pub fn q6k_race_ready(n: usize, d: usize, w_len: usize) -> bool {
    if !gpu_q4k_enabled() || !q6k_kernel_available() || !gpu_wants(1) {
        return false;
    }
    if d == 0 || d % 256 != 0 {
        return false;
    }
    w_len >= n * (d / 256) * 210
}

/// True when the fused-projection lever is fully engaged: `MESH_GPU_FUSE=1` AND
/// the contiguous slab (`MESH_GPU_SLAB=1`) AND f16 weight dtype. The fused path
/// reuses the slab's raw-pointer GEMM body, so all three must hold; otherwise
/// the caller runs the per-projection path. Public so model.rs can pre-check
/// before paying the cost of building the fused member list.
pub fn gpu_fuse_active() -> bool {
    // FLUX_GPU_F32_ACT=1 overrides fusion: the fused path is f16-slab-only and
    // would round activations to f16, defeating the precision fix. Disable it so
    // every projection takes the per-projection f32-activation routing (which is
    // d-gated). Fusion is a perf-only lever (default off), so this is safe.
    !gpu_f32_act_enabled() && gpu_fuse_enabled() && gpu_slab_enabled() && weight_dtype_is_f16()
}

/// MESH_GPU_FUSE=1 fused GPU entry: ONE cublas GEMM over a CONTIGUOUS group of
/// projections sharing `xs` and inner dim `d` (e.g. FFN gate+up, or q+k+v).
/// `out_concat` is [tokens * Σ member_rows], laid out member-block by
/// member-block in member order — the caller splits it into the per-projection
/// buffers. `members` is `[(weight_bytes, rows, cols)]`; all `cols` must equal
/// `d`. Returns `true` iff the GPU handled it; `false` (flag off / not slab+f16
/// / too-few-tokens / any GPU error) means the caller MUST run the existing
/// per-projection path. Same contract + fallback discipline as
/// `try_mat_vec_q8_0_rows_shared`. CPU stays the source of truth.
pub fn try_mat_vec_q8_0_fused(
    out_concat: &mut [f32],
    xs: &[f32],
    members: &[(&[u8], usize, usize)],
    d: usize,
    dequant_row: fn(&mut [f32], &[u8], usize, usize),
    label: &str,
) -> bool {
    // All three flags must hold; the fused path lives only on the slab+f16 body.
    if !gpu_fuse_active() {
        return false;
    }
    let Some(ctx) = gpu() else {
        return false;
    };
    // Decode is tokens=1; the fused win is cutting per-token syncs. Honor the
    // same min-token gate as the per-projection entries (LLM decode deploys set
    // FLUX_GPU_MIN_TOKENS=1).
    let tokens = 1usize;
    if !gpu_wants(tokens) {
        return false;
    }
    if members.is_empty() {
        return false;
    }
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.gemm_rows_shared_fused(out_concat, xs, members, d, tokens, dequant_row, label) {
        Ok(()) => {
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if should_log_phase(phase, cuda_op_log_every()) {
                let total_rows: usize = members.iter().map(|&(_, r, _)| r).sum();
                eprintln!(
                    "[cuda] {label}-FUSED gemm #{nops} (phase #{phase}) [{total_rows}x{d}]·[{tokens}x{d}] -> [{tokens}x{total_rows}] ({} members) {:.2}ms",
                    members.len(),
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            if e == VRAM_SATURATED {
                let n = SATURATION_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                if n == 1 || n % 512 == 0 {
                    eprintln!("[cuda] liquid-memory: {n} overflow ops routed to CPU (GPU cache full)");
                }
            } else {
                eprintln!("{e} — falling back to CPU per-projection path for this fused op");
            }
            false
        }
    }
}

/// True when the GPU is engaged AND `tokens` clears the min-token gate — the
/// cheap pre-check callers use before paying any packing/flattening cost to
/// build the flat `rows_shared` buffers. Decode is tokens=1, so LLM services
/// must set `FLUX_GPU_MIN_TOKENS=1` per-deploy to engage the GPU token loop —
/// only do that where the dequantized f32 weights fit resident in the VRAM
/// budget (≲4–5B params on a 24 GB L4); past that the FIFO cache re-dequants +
/// re-uploads per token and loses to the CPU kernel.
pub fn gpu_wants(tokens: usize) -> bool {
    tokens >= gpu_min_tokens() && gpu_available()
}

/// Shared driver for the quantized-LLM GPU entries (Q4K/Q6K — the formats the
/// gnosis-openai text-model .knots actually ship). Same contract as
/// `try_mat_vec_q8_0_rows_shared`: `true` = the GPU handled it; `false` (or
/// any GPU error) = the caller must run the CPU kernel.
fn try_mat_vec_quant_rows_shared(
    out: &mut [f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
    dequant_row: fn(&mut [f32], &[u8], usize, usize),
    label: &str,
) -> bool {
    let Some(ctx) = gpu() else {
        return false;
    };
    if tokens < gpu_min_tokens() {
        return false;
    }
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.gemm_rows_shared_quant(out, xs, w, n, d, tokens, dequant_row, label) {
        Ok(()) => {
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            let phase = PHASE_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if should_log_phase(phase, cuda_op_log_every()) {
                eprintln!(
                    "[cuda] {label} gemm #{nops} (phase #{phase}) [{n}x{d}]·[{tokens}x{d}] -> [{tokens}x{n}] {:.2}ms",
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            if e == VRAM_SATURATED {
                // Expected steady state under the liquid-memory cpu policy — the
                // GPU is full, this op runs CPU. Throttle the log so the overflow
                // layers don't spam per token; a periodic count shows the split.
                let n = SATURATION_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                if n == 1 || n % 512 == 0 {
                    eprintln!(
                        "[cuda] liquid-memory: {n} overflow ops routed to CPU (GPU cache full)"
                    );
                }
            } else {
                eprintln!("{e} — falling back to CPU kernel for this op");
            }
            false
        }
    }
}

/// GPU entry for the batched row-shared Q4K matmul (LLM attention/FFN/lm-head
/// projections on q4_K knots). Contract mirrors `try_mat_vec_q8_0_rows_shared`.
pub fn try_mat_vec_q4k_rows_shared(
    out: &mut [f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
) -> bool {
    try_mat_vec_quant_rows_shared(out, xs, w, n, d, tokens, dequantize_q4k_row, "Q4K")
}

/// Single-vector Q4K GEMV (the LLM decode hot path, tokens = 1). Engages only
/// under `FLUX_GPU_MIN_TOKENS=1` — see `gpu_wants` for the VRAM-fit caveat.
pub fn try_mat_vec_q4k(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) -> bool {
    try_mat_vec_quant_rows_shared(out, x, w, n, d, 1, dequantize_q4k_row, "Q4K")
}

/// GPU entry for the batched row-shared Q6K matmul (q6_K knot tensors — often
/// the lm-head / down-proj tensors of otherwise-q4 knots).
pub fn try_mat_vec_q6k_rows_shared(
    out: &mut [f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
) -> bool {
    try_mat_vec_quant_rows_shared(out, xs, w, n, d, tokens, dequantize_q6k_row, "Q6K")
}

/// Single-vector Q6K GEMV (decode). Same gating as `try_mat_vec_q4k`.
pub fn try_mat_vec_q6k(out: &mut [f32], x: &[f32], w: &[u8], n: usize, d: usize) -> bool {
    try_mat_vec_quant_rows_shared(out, x, w, n, d, 1, dequantize_q6k_row, "Q6K")
}

/// GPU entry for the batched row-shared **f32-weight** matmul (the T5-XXL path,
/// whose Q8 blocks are pre-dequantized to f32 host buffers). `w` is row-major
/// [n x d], `xs` is [tokens x d], `out` is [tokens x n]:
///   out[t*n + r] = Σ_c w[r*d + c] · xs[t*d + c].
/// Returns `true` if the GPU handled it; `false` (or on any GPU error / too-few
/// tokens) means the caller must run the CPU kernel. This is what turns the T5
/// encoder — previously ~19-27 min of per-token CPU f32 matmul that produced NO
/// progress logs (the "dead silence" after GPU init) — into a handful of large
/// resident-weight GPU GEMMs per block.
pub fn try_matmul_f32_rows_shared(
    out: &mut [f32],
    xs: &[f32],
    w: &[f32],
    n: usize,
    d: usize,
    tokens: usize,
) -> bool {
    let Some(ctx) = gpu() else {
        return false;
    };
    if tokens < gpu_min_tokens() {
        return false;
    }
    if w.len() != n * d {
        return false;
    }
    let mut guard = match ctx.lock() {
        Ok(g) => g,
        Err(_) => return false,
    };
    let t0 = Instant::now();
    match guard.gemm_rows_shared_f32(out, xs, w, n, d, tokens) {
        Ok(()) => {
            let nops = GPU_OPS.fetch_add(1, Ordering::Relaxed) + 1;
            if nops <= 8 || nops % 256 == 0 {
                eprintln!(
                    "[cuda] f32 gemm #{nops} [{n}x{d}]·[{tokens}x{d}] -> [{tokens}x{n}] {:.2}ms",
                    t0.elapsed().as_secs_f64() * 1e3
                );
            }
            true
        }
        Err(e) => {
            if e == VRAM_SATURATED {
                // Expected steady state under the liquid-memory cpu policy — the
                // GPU is full, this op runs CPU. Throttle the log so the overflow
                // layers don't spam per token; a periodic count shows the split.
                let n = SATURATION_OPS.fetch_add(1, Ordering::Relaxed) + 1;
                if n == 1 || n % 512 == 0 {
                    eprintln!(
                        "[cuda] liquid-memory: {n} overflow ops routed to CPU (GPU cache full)"
                    );
                }
            } else {
                eprintln!("{e} — falling back to CPU kernel for this op");
            }
            false
        }
    }
}

/// How many GPUCHECK reference diffs to emit per process (across all shapes).
/// Bounded so the (expensive) CPU recompute does not dominate a real render.
static GPUCHECK_EMITTED: AtomicU64 = AtomicU64::new(0);

fn gpucheck_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPUCHECK")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false)
    })
}

/// `FLUX_GPUFIX=1` BISECT: after a GPU GEMM, overwrite `out` with the EXACT CPU
/// recompute (f64 accumulate from the quantized weight). Keeps the rest of the
/// forward on the GPU binary. If the forward then serves "Paris", the GPU GEMM
/// OUTPUT was the cause (cos=1.0 but precision-tipping); if still garbage, a
/// non-GEMM GPU op is. Slow (CPU per op) — read top3 from logs, not HTTP.
fn gpufix_enabled() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPUFIX")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false)
    })
}

/// `FLUX_GPUFIX_MIN_D=N`: only force the exact-CPU GEMM for ops whose contraction
/// dim `d >= N`. The FLUX_GPUCHECK diff localized the corruptor to the FFN
/// down-projection `[3840x15360]` (d=15360, the huge contraction): its f16-input
/// rounding accumulates ~10x more abs-err (up to 6.2e-2, flagged WRONG) than any
/// other GEMM (all <1e-2, OK) and tips gemma4's hypersensitive readout. Forcing
/// JUST the large-d GEMMs to exact CPU keeps every small GEMM on fast GPU-f16.
/// Default 0 = force all (original FLUX_GPUFIX=1 behavior).
fn gpufix_min_d() -> usize {
    static V: OnceLock<usize> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPUFIX_MIN_D")
            .ok()
            .and_then(|v| v.trim().parse::<usize>().ok())
            .unwrap_or(0)
    })
}

/// Whether to run the exact-CPU override for a GEMM of contraction dim `d`.
fn gpufix_applies(d: usize) -> bool {
    gpufix_enabled() && d >= gpufix_min_d()
}

/// `FLUX_GPU_NO_CACHE=1`: never cache device weights — every GEMM re-dequantizes
/// and re-uploads from the CURRENT host bytes. Decisive test for "is the residual
/// gemma4 divergence a stale/collided cached weight?": this path cannot serve a
/// stale weight (no map, no eviction, fresh upload each call), so if it serves
/// correctly the cache is the culprit. Slower (htod per op) but correctness-safe.
fn no_weight_cache() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPU_NO_CACHE")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false)
    })
}

/// Max number of `[gpucheck]` diff lines to emit (default 24). Raise via
/// `FLUX_GPUCHECK_MAX` to verify GEMMs PAST the first few layers — the 24 default
/// only covered layers 0-3, hiding a possible later-layer GEMM divergence.
fn gpucheck_max() -> u64 {
    static V: OnceLock<u64> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPUCHECK_MAX")
            .ok()
            .and_then(|v| v.trim().parse::<u64>().ok())
            .unwrap_or(24)
    })
}

/// Content fingerprint of a weight buffer, used as the GPU weight-cache key
/// INSTEAD of the host pointer. The streaming `HttpBackend` serves weights from
/// an LRU of REUSED host buffers, so a `(w.as_ptr(), w.len())` key collided once
/// buffers cycled — the cache then returned a STALE device weight uploaded from
/// a different tensor that had transiently lived at the same address. gemma4
/// garbled from exactly the first such collision (bit-identical to CPU through
/// layers 0-3, then divergent at layer 4), while CPU + FLUX_GPUFIX were immune
/// because they always dequantize from the CURRENT bytes. Keying by content
/// makes a hit mean "same weight" regardless of which buffer holds it: a reused
/// address with new bytes hashes differently → miss → fresh upload; the same
/// tensor re-streamed into a new buffer hashes the same → correct reuse.
/// fnv1a-64 over up to ~4096 evenly-strided bytes + the byte length; cheap
/// (~microseconds) and collision-negligible for the few hundred distinct model
/// tensors. Generic over element type so the f32 (T5) cache shares it.
fn weight_fingerprint<T>(w: &[T]) -> u64 {
    let bytes =
        unsafe { std::slice::from_raw_parts(w.as_ptr() as *const u8, std::mem::size_of_val(w)) };
    let n = bytes.len();
    let mut h: u64 = 0xcbf2_9ce4_8422_2325;
    h ^= n as u64;
    h = h.wrapping_mul(0x0000_0100_0000_01b3);
    // Sample FULL 8-byte WORDS (not single bytes) at ~4096 evenly-spaced offsets.
    //
    // WHY (root cause of the mamba dt_proj [5120×160] intermittent GROSS GEMM
    // corruption): the old code folded ONE byte per stride, `bytes[i]` with
    // `stride = n/4096`. For these weights `n = elems*4` and `elems` is a multiple
    // of 4096 (dt_proj 819200 = 4096·200, x_proj 983040 = 4096·240, lm_head too),
    // so `stride = elems/1024` is a MULTIPLE OF 4 → every sampled offset is ≡0 mod
    // 4 → it hashed ONLY byte-0, the least-significant mantissa byte, of every
    // ~200th float. That byte is the least discriminative, so the 64 same-length
    // dt_proj weights COLLIDED in the `(fingerprint, len)` resident-weight-cache
    // key: a colliding layer got handed a DIFFERENT layer's resident device weight
    // → cos flipped negative on those layers (looks "intermittent" across the
    // same shape), garbling dt → the S6 scan diverged → wrong token.
    //
    // Hashing a full u64 word per sample captures the exponent + high-mantissa
    // bytes (high entropy) and is 8× the coverage, so distinct trained weights no
    // longer collide. This is still content-addressed (same bytes → same key
    // regardless of which reused host buffer holds them), so it preserves the
    // streaming-backend dedup + the fix for the original pointer-collision bug —
    // it only strengthens discrimination. Cost is unchanged (~4096 samples).
    if n >= 8 {
        let words = n / 8;
        let stride_w = (words / 4096).max(1);
        let mut wi = 0usize;
        while wi < words {
            let off = wi * 8;
            let word = u64::from_le_bytes(bytes[off..off + 8].try_into().unwrap());
            h ^= word;
            h = h.wrapping_mul(0x0000_0100_0000_01b3);
            wi += stride_w;
        }
        // Always fold the final 8-byte word so tail-only differences register.
        let last = u64::from_le_bytes(bytes[n - 8..n].try_into().unwrap());
        h ^= last;
        h = h.wrapping_mul(0x0000_0100_0000_01b3);
    } else if n > 0 {
        // Tiny buffers (<8 B): fold every byte — exhaustive, no collision risk.
        for &b in bytes {
            h ^= b as u64;
            h = h.wrapping_mul(0x0000_0100_0000_01b3);
        }
    }
    h
}

/// Overwrite `out` with the exact CPU GEMM (f64 accumulate) of the quantized
/// weight. Used by the FLUX_GPUFIX bisect and as a per-op exact-GEMM override.
fn force_cpu_gemm(
    out: &mut [f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
    dequant_row: fn(&mut [f32], &[u8], usize, usize),
) {
    use gnosis_frf::prelude::*;
    let out_ptr = out.as_mut_ptr() as usize;
    (0..n).into_par_iter().for_each(|r| {
        let mut row = vec![0.0f32; d];
        dequant_row(&mut row, w, r, d);
        for t in 0..tokens {
            let mut acc = 0.0f64;
            for c in 0..d {
                acc += row[c] as f64 * xs[t * d + c] as f64;
            }
            unsafe {
                *((out_ptr as *mut f32).add(t * n + r)) = acc as f32;
            }
        }
    });
}

/// Overwrite `out` with the exact CPU GEMM (f64 accumulate) of a PURE-f32 weight
/// (the `gemm_rows_shared_f32` path: mamba x_proj/dt_proj/lm_head, transformer
/// f32 lm_head). Mirrors `force_cpu_gemm` but reads the f32 weight rows directly
/// (no dequant), so its numerics are byte-identical to `gpucheck_f32`'s CPU
/// reference and to the scalar CPU kernel that serves "Paris" today. Used by the
/// FLUX_GPUFIX / FLUX_GPUFIX_F32 bisect + as a per-op exact-GEMM override.
///
/// WHY this exists: the pure-f32 GEMM path had a `gpucheck_f32` OBSERVER but NO
/// `force_cpu_gemm` OVERRIDE, so `FLUX_GPUFIX=1` — the "known-correct oracle" —
/// silently no-op'd on it (it only overrode the quant/f16 paths). That made it
/// impossible to answer "is the f32 GEMM the mamba corruptor?" on the L4, because
/// FLUX_GPU_MIN_TOKENS gates the f32 GEMM, the Q8 in-kernel GEMV, AND the S6 scan
/// TOGETHER (all check the SAME `gpu_min_tokens`), so toggling it flips all three
/// at once. This override (and FLUX_GPUFIX_F32, which forces ONLY this path while
/// leaving Q8+scan on GPU) is the decisive per-path bisect.
fn force_cpu_gemm_f32(out: &mut [f32], xs: &[f32], w: &[f32], n: usize, d: usize, tokens: usize) {
    use gnosis_frf::prelude::*;
    let out_ptr = out.as_mut_ptr() as usize;
    (0..n).into_par_iter().for_each(|r| {
        let row = &w[r * d..r * d + d];
        for t in 0..tokens {
            let mut acc = 0.0f64;
            for c in 0..d {
                acc += row[c] as f64 * xs[t * d + c] as f64;
            }
            unsafe {
                *((out_ptr as *mut f32).add(t * n + r)) = acc as f32;
            }
        }
    });
}

/// `FLUX_GPUFIX_F32=1`: force ONLY the pure-f32 GEMM (`gemm_rows_shared_f32`) to
/// the exact CPU recompute, leaving the Q8 in-kernel GEMV and the S6 scan on the
/// GPU. Decisive mamba bisect: run decode (FLUX_GPU_MIN_TOKENS=1, all GPU) with
/// this set — if the output becomes COHERENT the f32 GEMM was the corruptor; if
/// it stays GARBAGE the corruptor is the Q8 kernel or the scan, NOT the f32 GEMM.
fn gpufix_f32_only() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPUFIX_F32")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false)
    })
}

/// `FLUX_GPUFIX_Q8K=1`: force ONLY the Q8 in-kernel dequant-GEMV
/// (`q8_gemv_kernel`) to the exact CPU recompute, leaving the pure-f32 GEMM and
/// the S6 scan on the GPU. The complementary half of `gpufix_f32_only`'s bisect.
fn gpufix_q8k_only() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("FLUX_GPUFIX_Q8K")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false)
    })
}

/// `MESH_GPU_F32_FP64=1` (additive, DEFAULT OFF): run the pure-f32 GEMM
/// (`gemm_rows_shared_f32`) in DOUBLE precision — widen the f32 weight + xs to
/// f64, `cublasDgemm` (f64 accumulate), narrow the result back to f32. cuBLAS
/// sgemm is already PEDANTIC (no TF32), but it still accumulates in f32 with a
/// blocked summation ORDER that differs from the CPU's naive sequential f32 sum;
/// for hypersensitive decoders (mamba-2.8b's chaotic S6 scan) that order-only
/// difference tips the next-token argmax. f64 accumulation is order-independent
/// to ~1e-13, converging the GPU result to the exact-arithmetic token the CPU
/// serves — while staying on the GPU (Dgemm is slower per-FLOP than sgemm but the
/// mamba f32 tensors are small: x_proj/dt_proj tiny, lm_head [50280×2560] one
/// GEMM/token). FLUX/T5 and transformer decode leave this OFF and keep sgemm.
/// OnceLock-cached.
fn gpu_f32_fp64() -> bool {
    static V: OnceLock<bool> = OnceLock::new();
    *V.get_or_init(|| {
        std::env::var("MESH_GPU_F32_FP64")
            .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
            .unwrap_or(false)
    })
}

/// Compare cos-sim + max-abs-err of `gpu_out` against a fresh CPU recompute of
/// the SAME [n x d]·[tokens x d] -> [tokens x n] GEMM. Returns and logs one line.
fn report_diff(tag: &str, gpu_out: &[f32], cpu_out: &[f32], n: usize, d: usize, tokens: usize) {
    let mut dot = 0.0f64;
    let mut na = 0.0f64;
    let mut nb = 0.0f64;
    let mut max_abs = 0.0f64;
    for (g, c) in gpu_out.iter().zip(cpu_out.iter()) {
        let (g, c) = (*g as f64, *c as f64);
        dot += g * c;
        na += g * g;
        nb += c * c;
        let e = (g - c).abs();
        if e > max_abs {
            max_abs = e;
        }
    }
    let cos = if na > 0.0 && nb > 0.0 {
        dot / (na.sqrt() * nb.sqrt())
    } else {
        // both all-zero => trivially identical; one zero => undefined (flag).
        if na == 0.0 && nb == 0.0 { 1.0 } else { 0.0 }
    };
    let verdict = if cos > 0.9999 && max_abs < 1e-2 { "OK" } else { "WRONG" };
    eprintln!(
        "[gpucheck] {tag} [{n}x{d}]·[{tokens}x{d}] cos={cos:.6} max_abs_err={max_abs:.3e} {verdict}"
    );
    use std::io::Write;
    let _ = std::io::stderr().flush();
}

fn gpucheck_q8(gpu_out: &[f32], xs: &[f32], w: &[u8], n: usize, d: usize, tokens: usize) {
    if !gpucheck_enabled() {
        return;
    }
    if GPUCHECK_EMITTED.fetch_add(1, Ordering::Relaxed) >= gpucheck_max() {
        return;
    }
    // CPU reference: out[t*n + r] = Σ_c dequant(W)[r,c] · xs[t*d + c].
    use gnosis_frf::prelude::*;
    let mut cpu = vec![0.0f32; tokens * n];
    let cpu_ptr = cpu.as_mut_ptr() as usize;
    (0..n).into_par_iter().for_each(|r| {
        let mut row = vec![0.0f32; d];
        dequantize_q8_0_row(&mut row, w, r, d);
        for t in 0..tokens {
            let mut acc = 0.0f64;
            for c in 0..d {
                acc += row[c] as f64 * xs[t * d + c] as f64;
            }
            unsafe {
                *((cpu_ptr as *mut f32).add(t * n + r)) = acc as f32;
            }
        }
    });
    report_diff("Q8", gpu_out, &cpu, n, d, tokens);
}

/// GPU-vs-CPU diff for the f16/bf16 quantized GEMM path. Recomputes the GEMM on
/// CPU from the SAME quantized weight (f64 accumulate) and reports cos-sim +
/// max-abs-err. `tag` distinguishes f16/bf16. Localizes the gemma4 GPU
/// 16-bit-GEMM correctness bug: a "WRONG" verdict on a specific [n×d] shape
/// pins the failing op. FLUX_GPUCHECK=1 to enable.
fn gpucheck_quant(
    tag: &str,
    gpu_out: &[f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
    dequant_row: fn(&mut [f32], &[u8], usize, usize),
) {
    if !gpucheck_enabled() {
        return;
    }
    if GPUCHECK_EMITTED.fetch_add(1, Ordering::Relaxed) >= gpucheck_max() {
        return;
    }
    use gnosis_frf::prelude::*;
    let mut cpu = vec![0.0f32; tokens * n];
    let cpu_ptr = cpu.as_mut_ptr() as usize;
    (0..n).into_par_iter().for_each(|r| {
        let mut row = vec![0.0f32; d];
        dequant_row(&mut row, w, r, d);
        for t in 0..tokens {
            let mut acc = 0.0f64;
            for c in 0..d {
                acc += row[c] as f64 * xs[t * d + c] as f64;
            }
            unsafe {
                *((cpu_ptr as *mut f32).add(t * n + r)) = acc as f32;
            }
        }
    });
    report_diff(tag, gpu_out, &cpu, n, d, tokens);
}

fn gpucheck_f32(gpu_out: &[f32], xs: &[f32], w: &[f32], n: usize, d: usize, tokens: usize) {
    if !gpucheck_enabled() {
        return;
    }
    if GPUCHECK_EMITTED.fetch_add(1, Ordering::Relaxed) >= gpucheck_max() {
        return;
    }
    use gnosis_frf::prelude::*;
    let mut cpu = vec![0.0f32; tokens * n];
    let cpu_ptr = cpu.as_mut_ptr() as usize;
    (0..n).into_par_iter().for_each(|r| {
        for t in 0..tokens {
            let mut acc = 0.0f64;
            for c in 0..d {
                acc += w[r * d + c] as f64 * xs[t * d + c] as f64;
            }
            unsafe {
                *((cpu_ptr as *mut f32).add(t * n + r)) = acc as f32;
            }
        }
    });
    report_diff("f32", gpu_out, &cpu, n, d, tokens);
}

/// Standalone GPU Mamba-1 S6 selective-scan self-test (the qspec correctness
/// gate). Builds random S6 inputs for a couple of representative shapes
/// (falcon-mamba-7b 8192×16, mamba-2.8b 5120×16), runs several DECODE steps on
/// BOTH the GPU kernel and an inline CPU reference (byte-identical to
/// `mamba1_s6_step`'s scan loop), and asserts `max_rel_err(y) <= 1e-4` at every
/// step — which also exercises the resident-state carry across tokens. Returns a
/// human-readable report or Err if the kernel is unavailable / the tolerance is
/// exceeded. Mirrors `gpu_selftest`; invoked via `paris-probe-rknot
/// --gpu-selftest scan`.
pub fn scan_selftest() -> Result<String, String> {
    if !mamba_scan_kernel_available() {
        return Err(
            "[scancheck] mamba_scan kernel unavailable (build with --features cuda and nvcc \
             present so build.rs emits the cubin)"
                .to_string(),
        );
    }
    if gpu().is_none() {
        return Err("[scancheck] no CUDA device / GPU backend not engaged".to_string());
    }
    let mut log = String::new();
    log.push_str("[scancheck] Mamba-1 S6 selective-scan GPU-vs-CPU self-test on device 0\n");

    // Deterministic LCG so the test is reproducible without an rng dependency.
    let mut seed: u64 = 0x9e3779b97f4a7c15;
    let mut next = || {
        seed = seed.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
        // Map to [-1, 1).
        ((seed >> 33) as f32 / (1u64 << 31) as f32) - 1.0
    };

    // (d_inner, d_state, steps). d_inner deliberately NOT a multiple of the block
    // dim in one case to exercise the tail-guard (5120 = 20 blocks is exact; use
    // 8200 to force a ragged last block).
    let cases: &[(usize, usize, usize)] = &[(8192, 16, 3), (8200, 16, 3), (5120, 16, 4)];
    for &(d_inner, d_state, steps) in cases {
        // Fresh resident state for this case.
        mamba_scan_reset_all();

        let a_log: Vec<f32> = (0..d_inner * d_state).map(|_| next() * 2.0).collect();
        let d_skip: Vec<f32> = (0..d_inner).map(|_| next()).collect();

        // CPU state carried across steps; GPU state carried in VRAM (seeded from
        // this same zeroed h0 on the first step for this a_log fingerprint).
        let mut h_cpu = vec![0.0f32; d_inner * d_state];
        let h0 = vec![0.0f32; d_inner * d_state];
        let mut first_step = true;

        let mut worst = 0.0f64;
        let t0 = Instant::now();
        for step in 0..steps {
            // softplus(raw) so dt is positive, like the real dt after softplus.
            let x_conv: Vec<f32> = (0..d_inner).map(|_| next()).collect();
            let dt: Vec<f32> = (0..d_inner)
                .map(|_| {
                    let r = next() * 2.0;
                    if r > 20.0 { r } else { (1.0 + r.exp()).ln() }
                })
                .collect();
            let b_vec: Vec<f32> = (0..d_state).map(|_| next()).collect();
            let c_vec: Vec<f32> = (0..d_state).map(|_| next()).collect();

            // CPU reference — byte-identical to mamba1_s6_step's scan loop.
            let mut y_cpu = vec![0.0f32; d_inner];
            for ch in 0..d_inner {
                let mut yi = d_skip[ch] * x_conv[ch];
                for s in 0..d_state {
                    let idx = ch * d_state + s;
                    let a = (-dt[ch] * a_log[idx].exp()).exp();
                    h_cpu[idx] = h_cpu[idx] * a + dt[ch] * b_vec[s] * x_conv[ch];
                    yi += c_vec[s] * h_cpu[idx];
                }
                y_cpu[ch] = yi;
            }

            // GPU — seeds resident h from h0 (zeros) on the first step, carries after.
            // try_mamba1_s6_scan mirrors advanced state back into h_host (&mut), so the
            // selftest seed must be a mutable buffer (a copy of the current state).
            let mut seed_h: Vec<f32> = if first_step { h0.clone() } else { h_cpu.clone() };
            first_step = false;
            let mut y_gpu = vec![0.0f32; d_inner];
            if !try_mamba1_s6_scan(
                &mut y_gpu, &x_conv, &dt, &b_vec, &c_vec, &a_log, &d_skip, d_inner, d_state, 0,
                &mut seed_h,
            ) {
                return Err(format!(
                    "[scancheck] GPU scan declined the [{d_inner}x{d_state}] step {step} \
                     (flag off? shape? MESH_GPU_SCAN=1 required + a device)"
                ));
            }

            // Vector-relative error: max|gpu-cpu| normalized by the signal scale
            // max|cpu|. Robust to an individual near-zero y[ch] (a per-element
            // ratio would spike there) while faithfully measuring "how big is the
            // GPU-vs-CPU discrepancy relative to the output magnitude".
            let mut max_abs_err = 0.0f64;
            let mut max_ref = 1e-30f64;
            for ch in 0..d_inner {
                let err = (y_gpu[ch] as f64 - y_cpu[ch] as f64).abs();
                if err > max_abs_err {
                    max_abs_err = err;
                }
                let a = (y_cpu[ch] as f64).abs();
                if a > max_ref {
                    max_ref = a;
                }
            }
            let rel = max_abs_err / max_ref;
            if rel > worst {
                worst = rel;
            }
        }
        let ms = t0.elapsed().as_secs_f64() * 1e3;
        let ok = worst <= 1e-4;
        log.push_str(&format!(
            "  [{d_inner}x{d_state}] {steps} steps {ms:.2}ms  max_rel_err={worst:.2e} {}\n",
            if ok { "OK" } else { "WRONG" }
        ));
        if !ok {
            return Err(format!(
                "[scancheck] WRONG result for [{d_inner}x{d_state}]: max_rel_err={worst:.2e} > 1e-4"
            ));
        }
    }
    // Leave no resident state behind for a subsequent real run.
    mamba_scan_reset_all();
    log.push_str("[scancheck] all cases PASS — GPU S6 scan matches the CPU reference (<=1e-4)\n");
    Ok(log)
}

/// Standalone GPU sanity + timing self-test. Runs a couple of canonical GEMMs
/// (a small single-vector GEMV like the T5 path, and a batched matmul like the
/// DiT path), checks the result against a host reference, and prints timings.
/// Returns Ok with a human-readable report, or Err if cuBLAS is unavailable or
/// produced a wrong result. This isolates "cuBLAS works on this L4" from "the
/// render integration works".
pub fn gpu_selftest() -> Result<String, String> {
    let Some(ctx) = gpu() else {
        return Err("[gpucheck] no CUDA device / GPU backend not engaged".to_string());
    };
    let mut log = String::new();
    log.push_str("[gpucheck] cuBLAS self-test on device 0\n");

    // Build a synthetic Q8_0 weight [n x d] and an activation [tokens x d], then
    // compare the GPU GEMM to a pure-host reference. Q8_0 block = 34 bytes
    // (f16 scale + 32 i8). We craft simple deterministic values.
    let cases: &[(usize, usize, usize)] = &[
        (4096, 4096, 1),   // T5-like single-vector GEMV
        (4096, 4096, 256), // DiT-like batched matmul
        (12288, 3072, 512),
    ];
    let mut guard = ctx.lock().map_err(|_| "ctx lock poisoned".to_string())?;
    for &(n, d, tokens) in cases {
        let blocks_per_row = d.div_ceil(32);
        let mut w = vec![0u8; n * blocks_per_row * 34];
        // Deterministic Q8: scale=f16(0.01), qs = (row+col) mod 7 - 3.
        let scale_bits = f32_to_f16_bits(0.01);
        for r in 0..n {
            for b in 0..blocks_per_row {
                let off = (r * blocks_per_row + b) * 34;
                w[off] = (scale_bits & 0xff) as u8;
                w[off + 1] = (scale_bits >> 8) as u8;
                for j in 0..32 {
                    let c = b * 32 + j;
                    let q = (((r + c) % 7) as i32 - 3) as i8;
                    w[off + 2 + j] = q as u8;
                }
            }
        }
        let mut xs = vec![0.0f32; tokens * d];
        for (i, v) in xs.iter_mut().enumerate() {
            *v = ((i % 13) as f32 - 6.0) * 0.1;
        }
        let mut out_gpu = vec![0.0f32; tokens * n];
        let t0 = Instant::now();
        guard.gemm_rows_shared(&mut out_gpu, &xs, &w, n, d, tokens)?;
        let gpu_ms = t0.elapsed().as_secs_f64() * 1e3;

        // Host reference: dequantize + dot, for a few sampled outputs.
        let mut max_rel = 0.0f64;
        let sample_rows = [0usize, n / 3, n - 1];
        let sample_tok = [0usize, tokens / 2, tokens - 1];
        let mut row = vec![0.0f32; d];
        for &r in &sample_rows {
            dequantize_q8_0_row(&mut row, &w, r, d);
            for &t in &sample_tok {
                let mut acc = 0.0f64;
                for c in 0..d {
                    acc += row[c] as f64 * xs[t * d + c] as f64;
                }
                let got = out_gpu[t * n + r] as f64;
                let denom = acc.abs().max(1e-6);
                let rel = (got - acc).abs() / denom;
                if rel > max_rel {
                    max_rel = rel;
                }
            }
        }
        let ok = max_rel < 1e-3;
        log.push_str(&format!(
            "  [{n}x{d}]·[{tokens}x{d}] gpu={gpu_ms:.2}ms max_rel_err={max_rel:.2e} {}\n",
            if ok { "OK" } else { "WRONG" }
        ));
        if !ok {
            return Err(format!(
                "[gpucheck] WRONG result for [{n}x{d}]·[{tokens}x{d}]: max_rel_err={max_rel:.2e}"
            ));
        }
    }
    log.push_str("[gpucheck] all cases PASS — cuBLAS gemm is correct + fast on this L4\n");
    Ok(log)
}

/// Minimal f32 -> f16 bit conversion for the self-test weight scale (round to
/// nearest, no subnormal/inf finesse needed for 0.01).
fn f32_to_f16_bits(x: f32) -> u16 {
    let bits = x.to_bits();
    let sign = ((bits >> 16) & 0x8000) as u16;
    let exp = ((bits >> 23) & 0xff) as i32 - 127 + 15;
    let mant = (bits >> 13) & 0x3ff;
    if exp <= 0 {
        return sign;
    }
    if exp >= 0x1f {
        return sign | 0x7c00;
    }
    sign | ((exp as u16) << 10) | mant as u16
}
